// 来源：周易原文及传统解读，无版权问题

const gua64List = [
  {
    id: 1,
    name: "乾为天",
    shortName: "乾卦",
    upper: "乾",
    lower: "乾",
    symbol: "☰\n☰",
    text: "乾。元，亨，利，贞。",
    xiangZhuan: "天行健，君子以自强不息。",
    baihua: "大吉大利，吉利的贞卜。\n\n《象辞》说：天道刚健，运行不已。君子观此卦象，从而以天为法，自强不息。",
    duanyi: "乾象征天，六阳爻构成乾卦，为《易经》六十四卦之首。纯阳刚建，其性刚强，其行劲健，大通而至正，兆示大通而有利，但须行正道，方可永远亨通。",
    shaoyong: "刚健旺盛，发育之功；完事顺利，谨防太强。\n\n得此卦者，天行刚健，自强不息，名利双收之象，宜把握机会，争取成果。女人得此卦则有过于刚直之嫌。",
    chuantong: "这个卦是同卦（下乾上乾）相叠。象征天，喻龙（德才的君子），又象征纯粹的阳和健，表明兴盛强健。乾卦是根据万物变通的道理，以“元、亨、利、贞”为卦辞，表示吉祥如意，教导人遵守天道的德行。",
    yaoci: [{"position": "初九", "text": "潜龙勿用。", "xiang": "潜龙勿用，阳在下也。", "baihua": "潜藏的龙，无法施展。\n\n《象辞》说：潜藏的龙，无法施展，因为初九阳爻处在一卦的下位，所以压抑难伸。", "shaoyong": "平： 得此爻者，宜沉稳待机，若一动作即生灾疾，谋事不利，谨防小人。做官的会有阻力。经商的会有阻滞。女命则兴家业，孕生子。"}, {"position": "九二", "text": "见龙在田，利见大人。", "xiang": "见龙在田，德施普也。", "baihua": "龙出现在大地上，有利于会见贵族王公。\n\n《象辞》说：龙出现在大地上，喻指君子走出了压抑的低谷，正开始谋取能够广泛施予德泽的社会地位。", "shaoyong": "吉： 得此爻者，会得到贵人的提拔。做官的会遇到明主，身居要职。读书人考试能获得佳绩。经商者获利。女命逢之，则又富又贵。"}, {"position": "九三", "text": "君子终日乾乾，夕惕若；厉，无咎。", "xiang": "终日乾乾，反复道也。", "baihua": "有才德的君子始终是白天勤奋努力，夜晚戒惧反省，虽然处境艰难，但终究没有灾难。\n\n《象辞》说：君子整日里勤奋努力，意思是反复行道，坚持不舍。", "shaoyong": "平： 得此爻者，会往来不停，财利难获，凡事不认真计划，躁动者会有损失。做官的会身兼重职，且事多繁冗，如果能保持忧虑和谨慎的态度则没有过失。女命逢之，性躁，难成为贤内助。"}, {"position": "九四", "text": "或跃在渊，无咎。", "xiang": "或跃在渊，进无咎也。", "baihua": "龙也许跳进深潭，没有灾难。\n\n《象辞》说：龙也许跳进深潭，表示可以有所作为而没有灾难。", "shaoyong": "平： 得此爻者，百为艰难。做官的会停缺待职，等待机会。女命逢之，则安乐富贵也。"}, {"position": "九五", "text": "飞龙在天，利见大人。", "xiang": "飞龙在天，大人造也。", "baihua": "龙飞腾在空中，有利于会见贵族王公。\n\n《象辞》说：龙飞腾在空中，意味着君子大有所为。", "shaoyong": "吉： 得此爻者，会遇到贵人，谋遂志得。做官的会飞黄腾达。女命则兼男权，难免孤独。"}, {"position": "上九", "text": "亢龙有悔。", "xiang": "亢龙有悔，盈不可久也。", "baihua": "升腾到极限的龙会有灾祸之困。\n\n《象辞》说：升腾到极限的龙会有灾祸之困，这是警戒人们崇高、盈满是不可能长久保持的。", "shaoyong": "凶： 得此爻者，有过刚取凶之祸，五十以后者不寿。做官的会退职，或遭贬。女命逢之，其性必悍，难成为贤内助。"}]
  },
  {
    id: 2,
    name: "坤为地",
    shortName: "坤卦",
    upper: "坤",
    lower: "坤",
    symbol: "☷\n☷",
    text: "坤。元，亨，利牝马之贞。君子有攸往，先迷后得主。利西南得朋，东北丧朋。安贞，吉。",
    xiangZhuan: "地势坤，君子以厚德载物。",
    baihua: "大吉大利。占问雌马得到吉兆。君子前去旅行，先迷失路途，后来找到主人，吉利。西南行获得财物，东北行丧失财物。占问定居，得到吉兆。\n\n《象辞》说：大地的形势平铺舒展，顺承天道。君子观此卦象，取法于地，以深厚的德行来承担重大的责任。",
    duanyi: "坤卦坤上坤下，为坤宫本位卦。坤卦为柔顺，为地气舒展之象，具有纯阴之性，先失道而后得主，宜往西南，西南可得到朋友。",
    shaoyong: "柔顺和静，厚载之功；静守安顺，妄动招损。\n\n得此卦者，宜顺从运势，以静制动，不宜独立谋事，顺从他人，一起合作，可成大事。",
    chuantong: "这个卦是同卦（下坤上坤）相叠，阴性。象征地（与乾卦相反），顺从天，承载万物，伸展无穷无尽。坤卦以雌马为象征，表明地道生育抚养万物，而又依天顺时，性情温顺。它以“先迷后得”证明“坤”顺从“乾”，依随“乾”，才能把握正确方向，遵循正道，获取吉利。",
    yaoci: [{"position": "初六", "text": "履霜，坚冰至。", "xiang": "履霜坚冰，阴始凝也。", "baihua": "践踏着薄霜，可以推断坚厚的冰层快要冻结成了。\n\n《象辞》说：践踏着薄霜，可以推断坚厚的冰层快要冻结成了。这表明阴冷之气开始凝聚了，遵循自然规律的推进，坚厚的冰层快要冻结而成了。", "shaoyong": "平： 得此爻者，宜谨防仇怨引起的纠纷。阴气盛的人则会大兴家业。做官的要谨防小人的谗言而生祸。"}, {"position": "六二", "text": "直，方，大，不习无不利。", "xiang": "六二之动，直以方也；不习无不利，地道光也。", "baihua": "平直、方正、辽阔是大地的特点。即使前往陌生的地方，也没有什么不利的。\n\n《象辞》说：六二的爻象是平直而且方正，即使前往陌生的地方，也没有什么不利的，因为地道是广大无边的。", "shaoyong": "吉： 得此爻者，会不愁吃喝，衣食无忧。做官的会升迁，身居高位。女命则为贤良起家。"}, {"position": "六三", "text": "含章可贞。或从王事，无成有终。", "xiang": "含章可贞，以时发也；或从王事，知光大也。", "baihua": "战胜殷商。称心的占卜。有人服役于战争，没有取得战绩，但结局还是好的。\n\n《象辞》说：战胜殷商，称心的占卜，说明能抓住时机采取行动。有人服役于战争（没有取得战绩而有好的结局），因为他才智广大。", "shaoyong": "平： 得此爻者，谋望可成，认真经营会有收获。做官的会有升迁的希望。女命则为德妇。"}, {"position": "六四", "text": "括囊，无咎，无誉。", "xiang": "括囊无咎，慎不害也。", "baihua": "扎紧了口袋，如缄口不言，没有指责，也没有赞誉。\n\n《象辞》说：扎紧了口袋，如缄口不言，是说谨慎才没有祸害。", "shaoyong": "平： 得此爻者，经营受阻，大凡谨慎收敛者，则无横来之祸。做官的要谨守常职，可望升迁。女命则贤而起家。"}, {"position": "六五", "text": "黄裳，元吉。", "xiang": "黄裳元吉，文在中也。", "baihua": "黄色的裙裤，大吉大利。\n\n《象辞》说：黄色的裙裤大吉大利，因为“黄裳”象征着人内在的美德。", "shaoyong": "吉： 得此爻者，将会获得财利，事事安稳，没有灾难。做官的将会升迁，飞黄腾达。女命则为德妇，贤惠之人。"}, {"position": "上六", "text": "龙战于野，其血玄黄。", "xiang": "龙战于野，其道穷也。", "baihua": "龙在大地上争斗，血流遍野。\n\n《象辞》说：龙在大地上争斗，比喻人走到了穷困的绝境。", "shaoyong": "凶： 得此爻者，有竞争的困扰，会有大的损失。做官的会有被贬之祸。"}]
  },
  {
    id: 3,
    name: "水雷屯",
    shortName: "屯卦",
    upper: "坎",
    lower: "震",
    symbol: "☳\n☵",
    text: "屯。元，亨，利，贞。勿用，有攸往，利建侯。",
    xiangZhuan: "云，雷，屯；君子以经纶。",
    baihua: "大吉大利，吉利的占卜。不利于出门。有利于建国封侯。\n\n《象辞》说：屯的上卦为坎，坎为云，下卦为震，震为雷。云行于上，雷动于下，是屯卦的卦象。君子观此卦象，取法于云雷，用云的恩泽，雷的威严来治理国事。",
    duanyi: "屯卦坎上震下，为坎宫二世卦。屯说明有困难，又象征动而逢险境，需刚毅果敢方为吉。",
    shaoyong: "万物始生，开始困难；先劳后逸，苦尽甘来。\n\n得此卦者，身处困境，宜守不宜进，须多加辛苦努力，排除困难，方可通达，有初难后解之象。",
    chuantong: "这个卦是异卦（下震上坎）相叠，震为雷，喻动；坎为雨，喻险。雷雨交加，险象丛生，环境恶劣。“屯”原指植物萌生大地，万物始生，充满艰难险阻，然而顺时应运，必欣欣向荣。",
    yaoci: [{"position": "初九", "text": "盘桓，利居贞，利建侯。", "xiang": "虽盘桓，志行正也；以贵下贱，大得民也。", "baihua": "徘徊难进。这是有利于居住的卜问。巫遇此爻，有利于建国封侯。\n\n《象辞》说：虽然徘徊难进，但志行贞正。初九居六二阴爻之下，象征以尊贵而俯顺于低贱，因而大得民心。", "shaoyong": "平： 得此爻者，安分守己者则无忧，躁动者不利。做官的暂时未受到重用，坚守正道，好运可期。女命则为良妇而兴家。"}, {"position": "六二", "text": "屯如邅如，乘马班如。匪寇婚媾，女子贞不字，十年乃字。", "xiang": "六二之难，乘刚也；十年乃字，反常也。", "baihua": "逡巡不前。行路踌躇，驾着马车原地回旋，不是前来抢劫，而是迎娶新娘。占得这个女子不能孕育，十年才能怀孕。\n\n《象辞》说：六二之爻预示艰难，因为处在初九阳爻之上。十年才能怀孕，这是反常现象。", "shaoyong": "平： 得此爻者，有婚嫁之喜事。做官的权柄日盛。"}, {"position": "六三", "text": "即鹿无虞，惟入于林中。君子几不如舍。往吝。", "xiang": "即鹿无虞，以纵禽也。", "baihua": "追捕野鹿，没有充当向导的官员。思忖着鹿逃入山林。君子机灵，认为不如放弃。深入山林，认为会有危险。\n\n《象辞》说：追捕野鹿，没有充当向导的官员，意在追逐走兽。君子放弃那野鹿，知道深入山林会有危险，因而除此别无他法。", "shaoyong": "凶： 得此爻者，须安分守己，否则会有灾难。做官的有贪污之嫌，有被停职降职之忧。"}, {"position": "六四", "text": "乘马班如，求婚媾，往吉，无不利。", "xiang": "求而往，明也。", "baihua": "驾着马车原地回旋，这是寻求婿姻。放胆前进，必定吉利。\n\n《象辞》说：敢于追求，勇于深入，因为其人深明形势。", "shaoyong": "吉： 得此爻者，谋事可成，百事和合，会得到朋友的帮助，大吉大利。做官的将会名声显赫，有升迁之机。"}, {"position": "九五", "text": "屯其膏，小贞吉，大贞凶。", "xiang": "屯其膏，施未光也。", "baihua": "屯积肥肉。筮遇此爻，问小事则吉，问大事则凶。\n\n《象辞》说：“屯积肥肉”，意思是施舍不广。", "shaoyong": "平： 得此爻者，谋事者切勿急躁，小事可成，大事无望，甚至会招来凶祸。"}, {"position": "上六", "text": "乘马班如，泣血涟如。", "xiang": "泣血涟如，何可长也。", "baihua": "驾着马车原地回旋，哭泣无声，滴泪涟涟。\n\n《象辞》说：哭泣无声，滴泪涟涟，这种情景怎能长久下去。", "shaoyong": "凶： 得此爻者，家道中落，须防损失。做官的须谨防小人的谗言。"}]
  },
  {
    id: 4,
    name: "山水蒙",
    shortName: "蒙卦",
    upper: "艮",
    lower: "坎",
    symbol: "☵\n☶",
    text: "蒙。亨。匪我求童蒙，童蒙求我。初筮告，再三渎，渎则不告。利贞。",
    xiangZhuan: "山下出泉，蒙。",
    baihua: "通泰。不是我有求于幼稚愚昧的人，而是幼稚愚昧的人有求于我。第一次占筮，神灵告诉了他。轻慢不敬的再三占筮，轻慢不敬的占筮，神灵就不会告诉他。但还是吉利的卜问。\n\n《象辞》说：上卦为艮，象征山；下卦为坎，象征泉。山下有泉，泉水喷涌而出，这是蒙卦的卦象。君子观此卦象，取法于一往无前的山泉，从而以果敢坚毅的行动来培养自身的品德。",
    duanyi: "蒙卦艮上坎下，为离宫四世卦。蒙即蒙昧，主回还往复，疑惑不前，多忧愁过失，乃是凶卦。",
    shaoyong: "智慧未开，蒙昧闭塞；犹豫不决，缺乏果断。\n\n得此卦者，智慧犹如童蒙，不辨是非，迷失方向；若能顺贤师良友之教，启其聪明则亨通。",
    chuantong: "这个卦是异卦（下坎上艮）相叠，艮是山的形象，喻止；坎是水的形象，喻险。卦形为山下有险，仍不停止前进，是为蒙昧，故称蒙卦。但因把握时机，行动切合时宜，因此，具有启蒙和通达的卦象。",
    yaoci: [{"position": "初六", "text": "发蒙，利用刑人，用说桎梏。以往，吝。", "xiang": "利用刑人，以正法也。", "baihua": "启蒙教育，教育学生开发生产，教师用受刑之人作榜样，给犯人脱去手铐脚镣。往前走有困难。\n\n《象辞》说：以刑罚惩治罪人是有利的，可以以此来整肃法纪。", "shaoyong": "凶： 得此爻者，多有官诉，亲朋不和，多争斗，终能脱解。做官的为教育之职，或为司法系统之职。"}, {"position": "九二", "text": "包蒙吉。纳妇吉。子克家。", "xiang": "子克家，刚柔接也。", "baihua": "教育包容，这是吉兆。筮遇此爻，娶迎妻子，吉利。男女能相配成家。\n\n《象辞》说：男女相配成家，因为九二、六三两爻相近，表示阴阳刚柔相交会。", "shaoyong": "吉： 得此爻者，人情和合，百事有成，或结婚，或生子孙，有财有福。做官的会守住官职。"}, {"position": "六三", "text": "勿用娶女，见金夫，不有躬。无攸利。", "xiang": "勿用娶女，行不顺也。", "baihua": "不要抢劫女子为婚，会遭到武装者的抵抗，丢掉性命，没有什么好处。\n\n《象辞》说：不能聘娶女子，六三之爻居于九二之上，这是以柔乘刚之象，象征着以女虐男，这是悖逆不顺的。", "shaoyong": "凶： 得此爻者，会生是非，小则破财，大则伤身。做官的会因为贪婪而自取其辱。"}, {"position": "六四", "text": "困蒙，吝。", "xiang": "困蒙之吝，独远实也。", "baihua": "教育脱困，太可惜。\n\n《象辞》说：为蒙昧无知所困扰，因为离群索居，远离生活。", "shaoyong": "凶： 得此爻者，人情淡薄，经营受阻。静无灾，动有损。做官的因为无人赏识而难以晋升。"}, {"position": "六五", "text": "童蒙，吉。", "xiang": "童蒙之吉，顺以巽也。", "baihua": "教育少年儿童，吉利。\n\n《象辞》说：幼稚蒙昧的人之所以吉利，是因为柔顺服从。", "shaoyong": "吉： 得此爻者，依附贵人、良师者百事顺遂，谋望可成。"}, {"position": "上九", "text": "击蒙。不利为寇，利御寇。", "xiang": "利用御寇，上下顺也。", "baihua": "教育击打，不应当作匪寇，而要抵御匪寇。\n\n《象辞》说：有利于防御盗寇，因为上九阳爻居于一卦之首，说明臣下顺从拥戴。防御盗寇之举，获得众人支持，必能胜利。", "shaoyong": "平： 得此爻者，宜守旧，须谨防争讼，寇盗之扰。做官的会有司寇之名职。"}]
  },
  {
    id: 5,
    name: "水天需",
    shortName: "需卦",
    upper: "坎",
    lower: "乾",
    symbol: "☰\n☵",
    text: "需。有孚，光亨，贞吉。利涉大川。",
    xiangZhuan: "云上于天，需；君子以饮食宴乐。",
    baihua: "抓到俘虏。大吉大利，吉利的卜问。有利于涉水渡河。\n\n《象辞》说：需的上卦为坎，表示云；下卦为乾，表示天。云浮聚于天上，待时降雨是需卦的卦象。君子观此卦象，可以宴饮安乐，待时而动。",
    duanyi: "需卦坎上乾下，为坤宫游魂卦。需为踌躇、期待，虽然刚强，但前面有险阻，应当等待，涉大川则利。",
    shaoyong: "坎陷当前，遇阻不进；大器晚成，收成在后。\n\n得此卦者，时机尚未成熟，需要耐心等待，急进反会见凶。",
    chuantong: "这个卦是异卦（下乾上坎）相叠，下卦是乾，刚健之意；上卦是坎，险陷之意。以刚逢险，宜稳健之妥，不可冒失行动，观时待变，所往一定成功。",
    yaoci: [{"position": "初九", "text": "需于郊，利用恒，无咎。", "xiang": "需于郊，不犯难行也；利用恒，无咎，未失常也。", "baihua": "在郊外等侯，应该照旧等待下去，没有危险。\n\n《象辞》说：在郊外等候，是说不能冒险前进。照旧等待下去，没有危险，这是因为待机而动没有违反正常的原则。", "shaoyong": "平： 得此爻者，宜守旧，则无灾祸。做官的须守常职，耐心等待机会。"}, {"position": "九二", "text": "需于沙，小有言，终吉。", "xiang": "需于沙，衍在中也；虽小有言，以终吉也。", "baihua": "在沙地上等待，稍微有过错，最后还是吉利的。\n\n《象辞》说：在沙地上等待，沙地软柔难通行，将有延误事机之失，这过失在自身。虽然稍微有过错，最后的结果还是好的。", "shaoyong": "吉： 得此爻者，会受到争诉之扰，若能以宽厚待人，则不辩自明。做官的会受到流言的困扰，但最后吉祥。"}, {"position": "九三", "text": "需于泥，致寇至。", "xiang": "需于泥，灾在外也。", "baihua": "在泥淖中等待，把强盗招引过来。\n\n《象辞》说：在泥淖中等待，泥淖污秽，环境险恶，灾难就在附近。由自己招致了强盗，但郑重谨慎，随机应变，就可不受损伤。", "shaoyong": "凶： 得此爻者，须防止窃盗之患，亦要预防水险。做官的会被贬职。"}, {"position": "六四", "text": "需于血，出自穴。", "xiang": "需于血，顺以听也。", "baihua": "起初在血泊中滞留，后来从凶险的陷阱中逃脱出来。\n\n《象辞》说：在血泊中滞留，坐等不测的命运降临，六四之爻处在九五之爻的威逼之下，只得顺从强者，听从摆布。", "shaoyong": "平： 得此爻者，坏运逐渐远离，恢复平静。做官的能全身而退。从事国学者可出身成名。"}, {"position": "九五", "text": "需于酒食，贞吉。", "xiang": "酒食贞吉，以中正也。", "baihua": "在酒宴上等待，这是吉利的占兆。\n\n《象辞》说：有酒有肉，吉利之兆，因为九五之爻处于上卦中位，象征其人有中正的品德，自能择善而居，处优容之境。", "shaoyong": "吉： 得此爻者，会物产丰富，衣食不缺，也会有婚嫁之喜。做官的食禄会丰厚。"}, {"position": "上六", "text": "入于穴，有不速之客三人来，敬之终吉。", "xiang": "不速之客，敬之终吉；虽不当位，未大失也。", "baihua": "进入地穴式的房屋，有三位不速之客来到，恭敬地接待他们，结果是吉利的。\n\n《象辞》说：不速之客来了，恭敬地接待他们，结果是吉利的。因为全卦阳刚过甚，逼压阴柔，但是上六处阴位，位置合适，所以有惊无险，没有大的损失。", "shaoyong": "平： 得此爻者，宜谨慎，则忧愁自散。做官的会有升迁之机会，但须防谗邪之流。"}]
  },
  {
    id: 6,
    name: "天水讼",
    shortName: "讼卦",
    upper: "乾",
    lower: "坎",
    symbol: "☵\n☰",
    text: "讼。有孚，窒惕，中吉，终凶。利见大人，不利涉大川。",
    xiangZhuan: "天与水违行，讼。",
    baihua: "虽有利可图(获得俘虏)，但要警惕戒惧。其事中间吉利，后来凶险。占筮得此爻，有利于会见贵族王公，不利于涉水渡河。\n\n《象辞》说：上卦为乾，乾为天；下卦为坎，坎为水，天水隔绝，流向相背，事理乖舛，这是讼卦的卦象。君子观此卦象，以杜绝争讼为意，从而在谋事之初必须慎之又慎。",
    duanyi: "讼卦乾上坎下，为离宫游魂卦。上乾为刚，下坎为险，一方刚强，一方阴险，必然产生争论，因此多有不吉。",
    shaoyong: "天高水深，达远不亲；慎谋退守，敬畏无凶。\n\n得此卦者，身心不安，事多不顺，与他人多争诉之事，宜修身养性，谨慎处事。",
    chuantong: "这个卦是异卦（下坎上乾）相叠。同需卦相反，互为“综卦”。乾为刚健，坎为险陷。刚与险，健与险，彼此反对，定生争讼。争讼非善事，务必慎重戒惧。",
    yaoci: [{"position": "初六", "text": "不永所事，小有言，终吉。", "xiang": "不永所事，讼不可长也；虽小有言，其辩明也。", "baihua": "做事不能持之以恒，稍有过错，最后还是吉利的。\n\n《象辞》说：做事不能持之以恒，说明官司不可能长久打下去。虽然稍有过错，但争讼双方的是非曲直终将辨别清楚。", "shaoyong": "吉： 得此爻者，会生起是非，但终吉。有病者，不药而愈。做官的会遭诽谤，但会不辩自明。"}, {"position": "九二", "text": "不克讼，归而逋，其邑人三百户无眚。", "xiang": "不克讼，归而逋也；自下讼上，患至掇也。", "baihua": "讼事失败，归到采邑，三百户奴隶逃亡。没有大的灾祸。\n\n《象辞》说：讼事失败，逃窜回家，这是躲避反讼。小官与大官争讼，败讼而归，势在必然。幸好灾难没有进一步扩大。", "shaoyong": "平： 得此爻者，平安无事。做官的会有食邑之荣。"}, {"position": "六三", "text": "食旧德，贞厉，终吉。或从王事，无成。", "xiang": "食旧德，从上吉也。", "baihua": "依赖先人遗业过活。卜问得险兆，但最后是吉利的。但是，如果服务于王事，谋取利禄，却不会成功。\n\n《象辞》说：依赖先人遗业过活，因为六三爻象表明，居于九四之下，只有凭借祖上余荫才获吉利。", "shaoyong": "平： 得此爻者，宜保持常态，则无灾难。做官的宜谨守常职，晋升无望。"}, {"position": "九四", "text": "不克讼，复即命，渝安贞，吉。", "xiang": "复即命，渝安贞，吉，不失也。", "baihua": "讼事失败，败讼回家，服从判决。卜问平安，得吉利之兆。\n\n《象辞》说：败讼回家，服从判决，安守本分，不失正道。", "shaoyong": "吉： 得此爻者，会转危为安。做官的会闲中复职。"}, {"position": "九五", "text": "讼，元吉。", "xiang": "讼，元吉，以中正也。", "baihua": "争讼，筮遇此爻，大吉大利。\n\n《象辞》说：争讼而大吉大利，因为九五之爻居上卦的中位，像人守中正之道。", "shaoyong": "吉： 得此爻者，经营、谋事、求财皆大吉。做官的会受到重用。读书人会获得佳绩。"}, {"position": "上九", "text": "或锡之鞶带，终朝三褫之。", "xiang": "以讼受服，亦不足敬也。", "baihua": "王侯赐予人以绅带，但不满一天，三次赐予三次革夺。\n\n《象辞》说：某人因为讼事而得到赐予绅带的殊荣，这不是值得尊敬的事。", "shaoyong": "平： 得此爻者，会有争诉之忧，宜修德养身，化大为小。做官的会有成有败，患得患失。读书人认真学习，必可获佳绩。"}]
  },
  {
    id: 7,
    name: "地水师",
    shortName: "师卦",
    upper: "坤",
    lower: "坎",
    symbol: "☵\n☷",
    text: "师。贞，丈人吉，无咎。",
    xiangZhuan: "地中有水，师。",
    baihua: "占问总指挥的军情，没有灾祸。\n\n《象辞》说：下卦为坎，坎为水；上卦为坤，坤为地，像“地中有水”，这是师卦的卦象。君子观此卦象，取法于容纳江河的大地，收容和畜养大众。",
    duanyi: "师卦坤上坎下，为坎宫归魂卦。师即兵众，只有选择德高望重的长者来统率军队，才能吉祥无咎。",
    shaoyong: "忧劳动众，变化无穷；公正无私，排除万难。\n\n得此卦者，困难重重，忧心劳众，宜包容别人，艰苦努力，摒除一切困难。",
    chuantong: "这个卦是异卦（下坎上坤）相叠。“师”指军队。坎为水、为险；坤为地、为顺，喻寓兵于农。兵凶战危，用兵乃圣人不得已而为之，但它可以顺利无阻碍地解决矛盾，因为顺乎形势，师出有名，故能化凶为吉。",
    yaoci: [{"position": "初六", "text": "师出以律，否臧凶。", "xiang": "师出以律，失律凶也。", "baihua": "整军出战全凭纪律，不遵守纪律就会有凶险。\n\n《象辞》说：整军出战全凭纪律，失去纪律的约束就会带来凶险。", "shaoyong": "凶： 得此爻者，经营得当，则财货日增。但妄动者，成少败多。不良者，多险难刑伤。做官的宜谨守正道，则会得到上级的欣赏。"}, {"position": "九二", "text": "在师中，吉无咎，王三锡命。", "xiang": "在师中吉，承天宠也，王三锡命，怀万邦也。", "baihua": "主帅身在军中指挥，吉利，没有灾难。君王三次颁命嘉奖。\n\n《象辞》说：主帅身在军中指挥，吉利，因为得到上天的宠爱。君王三次颁命嘉奖，因为主帅能怀徕万国。", "shaoyong": "吉： 得此爻者，会遇到贵人，谋事可成。做官的会受到上级的赏识，有升迁之机会。读书人会取得佳绩。"}, {"position": "六三", "text": "师或舆尸，凶。", "xiang": "师或舆尸，大无功也。", "baihua": "军队出征，有人载尸而归，这是凶险之兆。\n\n《象辞》说：军队出征，有人载尸而归，这是前方吃了败仗。", "shaoyong": "凶： 得此爻者，多有悲优，或家中亲人病故。做官的会受职待缺。"}, {"position": "六四", "text": "师左次，无咎。", "xiang": "左次无咎，未失常也。", "baihua": "军队在左边扎营，没有危险。\n\n《象辞》说：军队在左边扎营，没有危险，因为军队驻扎或左或右，唯视地理环境、敌我形势而定，并没有违背行军常道。", "shaoyong": "平： 得此爻者，安居乐业，无妄动之灾。做官的官运不济，不宜妄想。"}, {"position": "六五", "text": "田有禽，利执言，无咎。长子帅师，弟子舆尸，贞凶。", "xiang": "长子帅师，以中行也；弟子舆尸，使不当也。", "baihua": "打猎时获得猎物，作战中捕获俘虏，没有灾祸。长子指挥军队，次子战败阵亡，这是凶险的贞兆。\n\n《象辞》说：以长子指挥军队，这是依正道行事。次子战败阵亡，这是因为差遣不当。", "shaoyong": "平： 得此爻者，财富日增，若用人得当，则谋望可成，但须谨防小人之危。做官的或有实权，或因为谏言而地位高显。读书人会取得佳绩。"}, {"position": "上六", "text": "大君有命，开国承家，小人勿用。", "xiang": "大君有命，以正功也；小人勿用，必乱邦也。", "baihua": "国君颁发命令，有人被封为诸侯，享有封国，有人被封为大夫，享有采邑。但是不要重用无才无德的小人。\n\n《象辞》说：国君颁发封赏功臣的命令，这是论功行赏。不要重用无才无德的小人，因为小人必定覆国乱邦。", "shaoyong": "平： 得此爻者，可立家计，或继承家业，但谨防小人从中作梗。做官的会当权立功。专业人才则会技艺成名。"}]
  },
  {
    id: 8,
    name: "水地比",
    shortName: "比卦",
    upper: "坎",
    lower: "坤",
    symbol: "☷\n☵",
    text: "比。吉。原筮，元永贞，无咎。不宁方来，后夫凶。",
    xiangZhuan: "地上有水，比。",
    baihua: "吉利。同时再卜筮，仍然大吉大利。卜问长时期的吉凶，也没有灾祸。不愿臣服的邦国来朝，迟迟不来者有难。\n\n《象辞》说：下卦为坤，上卦为坎，坤为地，坎为水，像地上有水，这是比卦的卦象。先王观此卦象，取法于水附大地，地纳江河之象，封建万国，亲近诸侯。",
    duanyi: "比卦坎上坤下，为坤宫归魂卦。比为相亲相依附之意，长期如此，就会无咎，所以吉祥。",
    shaoyong: "水行地上，亲比欢乐；人情亲顺，百事无忧。\n\n得此卦者，可获朋友之助，众人之力，谋事有成，荣显之极。",
    chuantong: "这个卦是异卦（下坤上坎）相叠，坤为地，坎为水。水附大地，地纳河海，相互依赖，亲密无间。此卦与师卦完全相反，互为综卦。它阐述的是相亲相辅，宽宏无私，精诚团结的道理。",
    yaoci: [{"position": "初六", "text": "有孚比之，无咎。有孚盈缶，终来有它吉。", "xiang": "比之初六，有它吉也。", "baihua": "捕获俘虏，安抚他们，没有灾难。捕获俘虏，满盆满罐的酒饭招待他们。虽然可能有意外之患，但最后是吉利的。\n\n《象辞》说：筮遇初六之爻，虽有意外之患，但最后是吉利的。", "shaoyong": "吉： 得此爻者，会遇到知己，谋事称心如意。做官的会有意外之喜。\n\n台湾国学大儒傅佩荣解\n\n时运： 诚信交往，声名日隆。\n\n财运： 信用卓著，利益自来。\n\n家宅： 社区和睦；亲事亦谐。\n\n身体： 平安无事。\n\n初六变卦\n\n\n\n初六爻动变得 周易第3卦：水雷屯 。这个卦是异卦（下震上坎）相叠，震为雷，喻动；坎为雨，喻险。雷雨交加，险象丛生，环境恶劣。“屯”原指植物萌生大地，万物始生，充满艰难险阻，然而顺时应运，必欣欣向荣。"}, {"position": "六二", "text": "比之自内，贞吉。", "xiang": "比之自内，不自失也。", "baihua": "内部和睦团结，卜问得吉兆。\n\n《象辞》说：内部和睦团结，就不会失掉民心。", "shaoyong": "吉： 得此爻者，得贵人之助，营谋遂意。做官的会无过失，安然而吉亨。读书人或能成名。女命则会得贤夫。"}, {"position": "六三", "text": "比之匪人。", "xiang": "比之匪人，不亦伤乎。", "baihua": "跟败类狼狈为奸。\n\n《象辞》说：跟败类狼狈为奸，不是很可悲吗？", "shaoyong": "凶： 得此爻者，交友不慎，或有争诉，破财刑伤。做官的要谨防同僚不睦而造成不顺。女子则所嫁并非良人，破家丧身之象，不然则会争诉破财。"}, {"position": "六四", "text": "外比之，贞吉。", "xiang": "外比于贤，以从上也。", "baihua": "跟外邦联盟亲善，卜问得吉兆。\n\n《象辞》说：外部亲附于贤明的国君，像臣下服从君上。", "shaoyong": "吉： 得此爻者，出外有利，多得知己之力，事事顺利。做官的会有升迁之喜。"}, {"position": "九五", "text": "显比，王用三驱，失前禽。邑人不诫，吉。", "xiang": "显比之吉，位正中也。", "baihua": "普遍的和洽。君王采用三面包围的方法狩猎，网开一面，有意放走逃奔的野兽。老百姓对君王狩猎毫不惊惧。筮遇此爻吉利。\n\n《象辞》说：普遍的和洽是吉利的，因为九五之爻处于上卦中位，像人守中正之道。放走向前奔逃的，猎取迎面奔窜的，这就是“失前禽”的缘故。老百姓对君王狩猎毫不惊惧，因为君王平时行事端正。", "shaoyong": "吉： 得此爻者，会先逆后顺，谋事有成，无往不利。做官的会有大的荣耀。读书人会考的佳绩。"}, {"position": "上六", "text": "比之无首，凶。", "xiang": "比之无首，无所终也。", "baihua": "小人朋比为奸，勾心斗角，无法形成一个团结的中心，这是非常危险的事。\n\n《象辞》说：小人朋比为奸，勾心斗角，无法形成一个团结的中心，当然没有好下场。", "shaoyong": "凶： 得此爻者，刑克有灾，人情淡薄，甚者恐有性命之忧。做官的会失去下属的支持，处境危难。"}]
  },
  {
    id: 9,
    name: "风天小畜",
    shortName: "小畜卦",
    upper: "巽",
    lower: "乾",
    symbol: "☰\n☴",
    text: "小畜。亨。密云不雨，自我西郊。",
    xiangZhuan: "风行天上，小畜。",
    baihua: "吉利。在西郊一带浓云密布，但雨没有下来。\n\n《象辞》说：上卦为巽，巽为风；下卦为乾，乾为天，和风拂地，草木低昂，勃勃滋生，这是小畜的卦象。君子观此卦象，取法催发万物的和风，自励风范，推行德教。",
    duanyi: "小畜卦巽上乾下，为巽宫初世卦。小畜为小的蓄积、小的阻碍，阳盛而阴不足，以致不得不暂时停顿，但终究还能亨通。",
    shaoyong: "力量寡弱，阻止前进；藏器待时，耐心推进。\n\n得此卦者，力量薄弱，运势反覆，宜蓄养实力，静待时机，急进则有险，凡事须耐心推进。",
    chuantong: "这个卦是异卦（下乾上巽）相叠，乾为天，巽为风。喻风调雨顺，谷物滋长，故卦名小畜（蓄）。力量有限，须待发展到一定程度，才可大有作为。",
    yaoci: [{"position": "初九", "text": "复自道，何其咎？吉。", "xiang": "复自道，其义吉也。", "baihua": "由原路返回，有什么灾祸？吉利。\n\n《象辞》说：由原路返回，其含义是吉利。", "shaoyong": "平： 得此爻者，宜守旧业，不宜创新。谋事者，须防猜忌疑惑之祸。做官的会闲位复职。"}, {"position": "九二", "text": "牵复，吉。", "xiang": "牵复在中，亦不自失也。", "baihua": "牵引着返回，吉利。\n\n《象辞》说：牵引着返回，吉利，因为九二之爻处于下卦中位，像人操行中正，自然不会有错失。", "shaoyong": "吉： 得此爻者，有人相助，营谋遂意。做官的有升迁之机会。"}, {"position": "九三", "text": "舆说辐，夫妻反目。", "xiang": "夫妻反目，不能正室也。", "baihua": "车子坏了一个轮子。夫妻互相口角。\n\n《象辞》说：夫妻口角，说明不能治理家庭。", "shaoyong": "凶： 得此爻者，荣而见辱，进而见退，或有足目之疾，或夫妻反目，或君臣疏远，或朋友是非，血气损伤。"}, {"position": "六四", "text": "有孚，血去惕出，无咎。", "xiang": "有孚惕出，上合志也。", "baihua": "捕获了俘虏，战争危险暂时消除了，但仍须保持警惕，才能没有灾难。\n\n《象辞》说：捕获了俘虏，保持着警惕，说明尚能统一意志。", "shaoyong": "平： 得此爻者，心诚者，人情和合，营谋颇遂。做官的会得到上司的提拔，久任者，能转运。"}, {"position": "九五", "text": "有孚挛如，富以其邻。", "xiang": "有孚挛如，不独富也。", "baihua": "捕获俘虏，串连搁缚，这些财物与邻邑同享。\n\n《象辞》说：捕获俘虏，串连捆缚，财物与邻邑同享，并非一人独享。", "shaoyong": "吉： 得此爻者，能得到他人的帮助，百谋称心。做官的会得到上级的赏识，下属的拥戴，德高望重。"}, {"position": "上九", "text": "既雨既处，尚德载。妇贞厉。月几望，君子征凶。", "xiang": "既雨既处，德积载也。", "baihua": "久雨新停，还赶得上栽种作物。妇女占得此爻则凶险。夏历某月十四日君子离家出行也有危险。\n\n《象辞》说：久雨新停，未误农时，当能丰登满载。君子离家出行有凶险，因为对充满危险的旅途缺乏了解。", "shaoyong": "平： 得此爻者，会受到小人的骚扰，宜修德养身，不妄进者，则可免灾。妇女占得此爻则凶，君子离家出行有凶险。"}]
  },
  {
    id: 10,
    name: "天泽履",
    shortName: "履卦",
    upper: "乾",
    lower: "兑",
    symbol: "☱\n☰",
    text: "履。履虎尾，不咥人，亨。",
    xiangZhuan: "上天下泽，履。",
    baihua: "踩着虎尾巴，老虎不咬人，吉利。\n\n《象辞》说：本卦上卦为乾，为天，下卦为兑，为泽，上天下泽，尊卑显别，这是履卦的卦象。君子观此卦象，从而分别上下尊卑，使人民循规蹈矩，安份守纪。",
    duanyi: "履卦乾上兑下，为艮宫五世卦。履为履行之意，又寓意礼，提示占筮者要兢兢戒惧，遵守礼节，这样才有惊无险。",
    shaoyong: "步履不安，困难危险；谦虚自重，敬慎事主。\n\n得此卦者，困难时期，多坎坷不顺，万事不宜急进，须循序渐进，谨慎行事。",
    chuantong: "这个卦是异卦（下兑上乾）相叠，乾为天，兑为泽，以天喻君，以泽喻民，原文：“履（踩）虎尾，不咥（咬）人”。因此，结果吉利。君上民下，各得其位。兑柔遇乾刚，所履危。履意为实践，卦义是脚踏实地的向前进取的意思。",
    yaoci: [{"position": "初九", "text": "素履，往无咎。", "xiang": "素履之往，独行愿也。", "baihua": "以朴素坦白的态度处世，没有灾害。\n\n《象辞》说：以朴素坦白的态度处世，是说能独行其志愿。", "shaoyong": "平： 得此爻者，营谋有计，则财利日增。做官的若修德养身，则有升迁之机。"}, {"position": "九二", "text": "履道坦坦，幽人贞吉。", "xiang": "幽人贞吉，中不自乱也。", "baihua": "行道之人，胸怀坦荡；隐居之人，长逢吉兆。\n\n《象辞》说：隐居之人洁身守正，因为他们秉性中正，不被世俗所惑。", "shaoyong": "平： 得此爻者，安然自乐，修身养性。做官的会有全身而退之兆。"}, {"position": "六三", "text": "眇能视，跛能履。履虎尾，咥人，凶。武人为于大君。", "xiang": "眇能视，不足以有明也。", "baihua": "瞎了眼睛却要看物，跛了脚却要行走，这是勉为其难，犹如踩着虎尾巴，终将为虎所伤。这是凶险之事。武人纂夺国政，同样是凶险之事。\n\n《象辞》说：瞎了眼睛却要看物，其视力不足以辨物。跛了脚却要行走，其脚力不足以行路。老虎之所以伤人，因为六三阴爻而居于阳位，所处不当。武人纂夺国政，这是僭越犯上，以六三之位而行九五之志，必遭祸殃。", "shaoyong": "凶： 得此爻者，会有争诉，囚狱之扰，甚者家破人亡。做官的则会有被贬职之祸。"}, {"position": "九四", "text": "履虎尾，愬愬，终吉。", "xiang": "愬愬终吉，志行也。", "baihua": "踩着虎尾巴，但能遇险知惧，最后仍吉利。\n\n《象辞》说：恐惧警惕，终归于吉，说明虽历磨难，但志愿得行。", "shaoyong": "平： 得此爻者，会有危险，宜温和自持，可免灾祸。做官的会有虎符将帅之兆。读书人将会取得不错的佳绩。"}, {"position": "九五", "text": "夬履，贞厉。", "xiang": "夬履贞厉。", "baihua": "行为急躁莽撞；卜其行事有危险之象。\n\n《象辞》说：行为急躁莽撞，卜其行事有危险之象，但九五阳爻居上卦中位，正当其位。因而虽险不凶。", "shaoyong": "凶： 得此爻者，躁动妄行者，则祸患将至，甚者有性命之忧。做官的会功高盖主，而不赏。"}, {"position": "上九", "text": "视履考祥，其旋元吉。", "xiang": "元吉在上，大有庆也。", "baihua": "行为审慎，遇事周密反复地考虑，大吉。\n\n《象辞》说：大吉大利，因为上九之爻居全卦之首。预兆其人将有重大喜庆之事。", "shaoyong": "吉： 得此爻者，财利可获。做官的宜退而以享安静和平之福。读书人努力者可获佳绩。"}]
  },
  {
    id: 11,
    name: "地天泰",
    shortName: "泰卦",
    upper: "坤",
    lower: "乾",
    symbol: "☰\n☷",
    text: "泰。小往大来，吉亨。",
    xiangZhuan: "天地交，泰。",
    baihua: "由小而大，由微而盛，吉利，亨通。\n\n《象辞》说：天地交感，是泰卦的卦象。君子观此卦象，裁度天地运行的规律，辅助天地的造化，从而支配天下万民。",
    duanyi: "泰卦坤上乾下，为坤宫三世卦。此卦所失者小，所得者大，若是占得此卦，将会失小而得大。",
    shaoyong: "小往大来，通泰吉祥；泰极转否，事宜固守。\n\n得此卦者，否极泰来，鸿运当头，诸事皆顺，但须防乐极生悲。",
    chuantong: "这个卦是异卦（下乾上坤）相叠，乾为天，为阳；坤为地，为阴，阴阳交感，上下互通，天地相交，万物纷纭。反之则凶，万事万物，皆对立，转化，盛极必衰，衰而转盛，故应时而变者泰（通）。",
    yaoci: [{"position": "初九", "text": "拔茅茹，以其汇，征吉。", "xiang": "拔茅征吉，志在外也。", "baihua": "连根拨掉茅草，及其同类。征伐敌人，吉利。\n\n《象辞》说：连根拔掉茅草，彻底征服敌人，吉利，说明志在讨伐敌国。", "shaoyong": "吉： 得此爻者，志同合谋，财利日增。做官的会逐步升迁。"}, {"position": "九二", "text": "包荒，用冯河，不遐遗，朋亡，得尚于中行。", "xiang": "包荒，得尚于中行，以光大也。", "baihua": "用挖空的瓠瓜绑在身上渡河，不至于沉没。钱币丢失了，在半路上得到别人的帮助。\n\n《象辞》说：其人度量弘大，深得同路人的赏识，这是由于他光明正大呀。", "shaoyong": "吉： 得此爻者，会有好运，必遇尊贵，但要防长上有损，言语有伤。做官的会身居高位，功名显达。"}, {"position": "九三", "text": "无平不陂，无往不复。艰贞无咎。勿恤其孚，于食有福。", "xiang": "无往不复，天地际也。", "baihua": "平地终将变成坡地，离去必定复返。卜问艰难之事，爻象显示必能渡过难关，不要担心被人虏去，而且在饮食上尚有口福。\n\n《象辞》说：离去必定复返，这是天地间的法则。", "shaoyong": "平： 得此爻者，须谨慎自持，宜保守，则安，不然会犯小人，事事遇阻。做官的会比较艰难，须防小人和别人的妒忌。"}, {"position": "六四", "text": "翩翩不富，以其邻，不戒以孚。", "xiang": "翩翩不富，皆失实也；不戒以孚，中心愿也。", "baihua": "巧言欺人，将给邻邑带来灾难；不加警戒，即将遇难被虏。\n\n《象辞》说：巧言欺人，祸及邻人，是说同受损失。不加警戒，遇难被虏，这是因为心地太忠厚了。", "shaoyong": "平： 得此爻者，营谋失利，退守可平安。做官的进取难成，宜退守。"}, {"position": "六五", "text": "帝乙归妹，以祉元吉。", "xiang": "以祉元吉，中以行愿也。", "baihua": "殷帝乙嫁女于周文王，因而得福，大吉大利。\n\n《象辞》说：得福大吉，因为六五之爻居上卦中位，像人行事得中正之道，所行必遂。", "shaoyong": "吉： 得此爻者，会得到别人的赏识和抬举，或结婚生子，幸福安乐。做官的或能升迁，或有喜事。"}, {"position": "上六", "text": "城复于隍，勿用师。自邑告命，贞吝。", "xiang": "城复于隍，其命乱也。", "baihua": "城墙攻破倒塌在护城濠里。“停止进攻”，从邑中传来命令。卜问得不祥之兆。\n\n《象辞》说：城墙攻破倒塌在护城濠里（本应乘势攻击，反命停止进攻），这是邑中传来的命令错乱了。", "shaoyong": "凶： 得此爻者，会有破损，有疾病，谨慎厚道者可免祸。做官的会被贬职。"}]
  },
  {
    id: 12,
    name: "天地否",
    shortName: "否卦",
    upper: "乾",
    lower: "坤",
    symbol: "☷\n☰",
    text: "否。否之匪人。不利君子贞。大往小来。",
    xiangZhuan: "天地不交，否。",
    baihua: "为小人所隔阂，这是不利于君子的占卜，事业也将由盛转衰。\n\n《象辞》说：天地隔阂不能交感，万物咽窒不能畅釜，这是否卦的卦象。君子观此卦象，从而在国家政治否塞之时，应思隐居不仕，以崇尚俭约来躲避灾难，不要以利禄为荣。",
    duanyi: "否卦乾上坤下，为乾宫三世卦。否象征闭塞不通，是不吉之兆。否卦中，阴阳不交，是一切都不和谐之象。",
    shaoyong: "大往小来，闭塞不通；否极泰来，修德避难。\n\n得此卦者，万物闭塞之象，上下不合，诸事不顺，凡事宜忍，须待时运好转而有为。",
    chuantong: "这个卦是异卦（下坤上乾）相叠，其结构同泰卦相反，系阳气上升，阴气下降，天地不交，万物不通。它们彼此为“综卦”，表明泰极而否，否极泰来，互为因果。",
    yaoci: [{"position": "初六", "text": "拔茅茹，以其汇，贞吉，亨。", "xiang": "拔茅贞吉，志在君也。", "baihua": "连根拔掉茅草，及其同类，占得此爻则吉利，亨通。\n\n《象辞》说：连根拔掉茅草，占得此爻吉利，比喻其志在清理君侧，为国尽忠。", "shaoyong": "平： 得此爻者，宜守旧，小人得势之时，爻辞虽好，但须谨防小人牵连之事。做官的受职者待缺，当权者防扰。"}, {"position": "六二", "text": "包承，小人吉；大人否，亨。", "xiang": "大人否，享，不乱群也。", "baihua": "厨中有肉，这对老百姓来说是吉利，对贵族来说并不是通泰的表现。\n\n《象辞》说：贵族身处窘境，则能心怀惩戒，使其安守本分。", "shaoyong": "平： 得此爻者，宜忍耐，宽容待人，不然会生是非。做官的宜低调行事。"}, {"position": "六三", "text": "包羞。", "xiang": "包羞，位不当也。", "baihua": "厨中有美味。\n\n《象辞》说：心怀羞愧，因为才德不称其位。", "shaoyong": "凶： 得此爻者，须防是非争诉之扰。做官的会退休离职。"}, {"position": "九四", "text": "有命无咎，畴离祉。", "xiang": "有命无咎，志行也。", "baihua": "君王有赏赐之命，没有灾害，谁能得到赏赐呢?\n\n《象辞》说：君王有赏赐之命，没有灾害，说明君王论功行赏，臣下尽职效力，各行其志。", "shaoyong": "吉： 得此爻者，家产日增，吉庆安乐。做官的会得到朋友和同僚之助，或升迁，或进财。"}, {"position": "九五", "text": "休否，大人吉；其亡其亡，系于苞桑。", "xiang": "大人之吉，位正当也。", "baihua": "警戒覆亡，贵族王公如此存心则吉利。危险呵，危险，国家命运好像系在柔弱的苞草、桑枝上一样。\n\n《象辞》说：九五爻辞讲贵族王公安不忘危，则吉利。因为九五之爻居上卦中位，像其人忧国忧君，才德正当其位。", "shaoyong": "吉： 得此爻者，旧祸已去，好运将至，诸事皆吉。做官的会身居重位。"}, {"position": "上九", "text": "倾否，先否后喜。", "xiang": "否终则倾，何可长也。", "baihua": "短暂的恶运，先遇恶运后交好运。\n\n《象辞》说：恶运快终了，好运岂迢遥。命运交变之际，什么力量可以制止呢？", "shaoyong": "平： 得此爻者，将会转好运，久困者利可期，久讼者讼事解。做官的失职者复职，闲缺者会走马上任。"}]
  },
  {
    id: 13,
    name: "天火同人",
    shortName: "同人卦",
    upper: "乾",
    lower: "离",
    symbol: "☲\n☰",
    text: "同人。同人于野，亨。利涉大川，利君子贞。",
    xiangZhuan: "天与火，同人；君子以类族辨物。",
    baihua: "聚众于郊外，将行大事，吉利。有利于涉水渡河，有利于君子的卜问。\n\n《象辞》说：同人之卦，上卦为乾为天为君王，下卦为离为火为臣民，上乾下离象征君王上情下达，臣民下情上达，君臣意志和同，这是同人的卦象。君子观此卦象，取法于火，明烛天地，照亮幽隐，从而去分析物类，辨明情状。",
    duanyi: "同人卦乾上离下，为离宫归魂卦。同人卦象征交结情深，两人契义，同心断金。主所求皆得，事事称心。",
    shaoyong: "人类相亲，与人和同；所求皆得，无不称心。\n\n得此卦者，吉祥如意，与人合作共事更佳，上下同心，谋事有成。",
    chuantong: "这个卦是异卦（下离上乾）相叠，乾为天，为君；离为火，为臣民百姓，上天下火，火性上升，同于天，上下和同，同舟共济，人际关系和谐，天下大同。",
    yaoci: [{"position": "初九", "text": "同人于门，无咎。", "xiang": "出门同人，又谁咎也。", "baihua": "聚集大众于王门，将行大事，没有灾祸。\n\n《象辞》说：君王走出王门与国人打成一片，谁又会遭受灾祸呢？", "shaoyong": "平： 得此爻者，能与人合伙经营获利，或出家远行，或修造门户，或在他处学习。做官的或会受到重用，或有升迁之机。"}, {"position": "六二", "text": "同人于宗，吝。", "xiang": "同人于宗，吝道也。", "baihua": "聚同族于宗庙，卜祷凶吉，因为面临艰难。\n\n《象辞》说：仅仅聚同族于宗庙，这是狭隘的宗法原则。", "shaoyong": "凶： 得此爻者，事多不定，与宗人朋友多不和，相互多猜忌，面和心不合，容易起是非。做官的没有升迁之机，需耐心等待。"}, {"position": "九三", "text": "伏戎于莽，升其高陵，三岁不兴。", "xiang": "伏戎于莽，敌刚也，三岁不兴，安行也。", "baihua": "将军队隐蔽在深山密林，并且占领了制高点，但长时期不能取胜。\n\n《象辞》说：将军队隐蔽在深山密林，因为敌人太强大。长时期不能取胜，怎能有所作为呢？", "shaoyong": "凶： 得此爻者，或有丧亲，或有诉讼打官司之患。做官的须防被免职之忧。"}, {"position": "九四", "text": "乘其墉，弗克攻，吉。", "xiang": "乘其墉，义弗克也，其吉，则困而反则也。", "baihua": "爬上了敌人的城墙，城还没有攻下来，继续攻打才能获胜。\n\n《象辞》说：爬上了敌人的城墙，从道义上讲应该停士攻城。之所以继续攻打为吉利，因为困守之敌可能逞其狡诈。", "shaoyong": "平： 得此爻者，亲友之间会互相猜忌，荣中有辱，结果会好些，凡事须多加提防则可吉祥。做官的若能兢兢业业，则有提拔之机遇，或会受到表彰。"}, {"position": "九五", "text": "同人，先号啕而后笑，大师克相遇。", "xiang": "同人之先，以中直也。", "baihua": "聚集起来的大众先哭嚎后欢笑，因为大军及时增援，大获胜仗。\n\n《象辞》说：聚集起来的大众之所以先哭后笑（战斗转败为胜），因为筮遇此爻，九五居上卦之中位，像人得贞正之道，势必化凶为吉。大军会师，是说我军压倒了敌人。", "shaoyong": "平： 得此爻者，先难后易，是非不一。做官的会先贬后升。"}, {"position": "上九", "text": "同人于郊，无悔。", "xiang": "同人于郊，志未得也。", "baihua": "聚众于郊外，致祭于神灵祝贺胜利，自然没有悔咎。\n\n《象辞》说：聚众于郊外，援助不广，尚不得行其志。", "shaoyong": "平： 得此爻者，宜守常，不宜激进。做官的则多有出差的机会。"}]
  },
  {
    id: 14,
    name: "火天大有",
    shortName: "大有卦",
    upper: "离",
    lower: "乾",
    symbol: "☰\n☲",
    text: "大有。元亨。",
    xiangZhuan: "火在天上，大有。",
    baihua: "昌隆通泰。\n\n《象辞》说：本卦下卦为乾为天，上卦为离为火，火在天上，明烛四方，这是大有的卦象。君子观此卦象，取法于火，洞察善恶，抑恶扬善，从而顺应天命，祈获好运。",
    duanyi: "大有卦离上乾下，为乾宫归魂卦。大有卦为柔得尊位，抑恶扬善，丰财利义，象征天命所归，得人心，因此主吉。",
    shaoyong: "日丽中天，遍照万物；盛大富有，持盈保泰。\n\n得此卦者，正当好运，事事吉祥，大有收获，但需防物极必反，盛极转衰。",
    chuantong: "这个卦是异卦（下乾上离）相叠。上卦为离，为火；下卦为乾，为天。火在天上，普照万物，万民归顺，顺天依时，大有所成。",
    yaoci: [{"position": "初九", "text": "无交害，匪咎；艰则无咎。", "xiang": "大有初九，无交害也。", "baihua": "不要彼此侵害，即没有灾祸，既使处于艰难之中，也没有灾祸。\n\n《象辞》说：大有初九爻辞说，不要彼此侵害。", "shaoyong": "平： 得此爻者，心绪不定，小人欺凌，很是艰辛，长辈或有灾难。做官的须急流勇退，不可贪婪荣华富贵。"}, {"position": "九二", "text": "大车以载，有攸往，无咎。", "xiang": "大车以载，积中不败也。", "baihua": "用大车装物载人，有明确的目的地，没有灾祸。\n\n《象辞》说：用大车装物载人，物积于车中不会散失。", "shaoyong": "吉： 得此爻者，营谋得利，财利丰厚，但不利于老人的健康。做官的闲职者会受到重用。"}, {"position": "九三", "text": "公用亨于天子，小人弗克。", "xiang": "公用亨于天子，小人害也。", "baihua": "天子宴请公侯。小人则不能参与。\n\n《象辞》说：天子宴请公侯，（小人不能参与）因为小人参与国政，将是国家的祸害。", "shaoyong": "平： 得此爻者，有灾难，举步维艰，勿近小人。做官的会受到重任，读书人会取得很好的成绩。"}, {"position": "九四", "text": "匪其彭，无咎。", "xiang": "匪其彭，无咎，明辩晰也。", "baihua": "用曝晒男巫来求雨，旱情严重，但没有灾祸。\n\n《象辞》说：反对坏人坏事没有灾祸，因为明于考察辨析。", "shaoyong": "平： 得此爻者，宜守常，则可避免伤害，眼睛方面或会出现病症。做官的须安于现状，不可激进，则可免祸。"}, {"position": "六五", "text": "厥孚交如，威如，吉。", "xiang": "厥孚交如，信以发志也；威如之吉，易而无备也。", "baihua": "来犯之敌被紧紧捆绑，严厉惩罚，吉利。\n\n《象辞》说：其人诚信坦白，因为他以诚信来表现自己的志向。威服众人之所以吉利，因为众人敬畏，则能平安而不困惫。", "shaoyong": "吉： 得此爻者，须相时而动，切不可骄傲自负，以免自取其祸。做官的宜退不宜进。"}, {"position": "上九", "text": "自天祐之，吉无不利。", "xiang": "大有上吉，自天祐也。", "baihua": "上天保祐，吉利，无所不顺利。\n\n《象辞》说：大有是大吉大利之卦，因为得到上天的保祐。", "shaoyong": "吉： 得此爻者，得到祖上之庇佑，一路好运。做官的以及读书人会进职成名。"}]
  },
  {
    id: 15,
    name: "地山谦",
    shortName: "谦卦",
    upper: "坤",
    lower: "艮",
    symbol: "☶\n☷",
    text: "谦。亨，君子有终。",
    xiangZhuan: "地中有山，谦。",
    baihua: "通泰。筮遇此卦，君子将有所成就。\n\n《象辞》说：本卦外卦为坤为地，内卦为艮为山，地中有山，内高外卑，居高不傲，这是谦卦的卦象。君子观此卦象，以谦让为怀，裁取多余昀，增益缺乏的，衡量财物的多寡而公平施予。",
    duanyi: "谦卦坤上艮下，为兑宫五世卦。谦为谦逊，内卦艮和外卦坤都是谦虚之象，所以为吉利之卦。",
    shaoyong: "谦和忍让，尊人自卑；利用谦虚，万事可达。\n\n得此卦者，吉利平安，步步高升。谦虚忍让者前途大好，骄横者必招败。谦受益，满招损。",
    chuantong: "这个卦是异卦（下艮上坤）相叠，艮为山，坤为地。地面有山，地卑（低）而山高，是为内高外低，比喻功高不自居，名高不自誉，位高不自傲。这就是谦。",
    yaoci: [{"position": "初六", "text": "谦谦君子，用涉大川，吉。", "xiang": "谦谦君子，卑以自牧也。", "baihua": "谦让，再谦让，这才是君子的风度。具有这种品德，即使冒险涉水过河，也是吉利的。\n\n《象辞》说：十分谦让的君子，就是从谦让入手进行自我修养。", "shaoyong": "平： 得此爻者，宜远行或出游，出外做生意会发财。做官的须退守，不宜与人争利，出差的机会会多。"}, {"position": "六二", "text": "鸣谦，贞吉。", "xiang": "鸣谦贞吉，中心得也。", "baihua": "明智而谦让，卜问得吉兆。\n\n《象辞》说：明智而谦让，心正而吉利，因为六二之爻居下卦中位，像人守中正之道。", "shaoyong": "吉： 得此爻者，不宜轻举妄动，宜退守。做官的会升迁，读书人会进取成名。"}, {"position": "九三", "text": "劳谦君子，有终吉。", "xiang": "劳谦君子，万民服也。", "baihua": "勤劳而谦让，这样的人将有好结果，凡事吉利。\n\n《象辞》说：勤劳而谦让的君子，万民敬服。", "shaoyong": "吉： 得此爻者，营谋得利，但会劳心劳力。做官的会高升。"}, {"position": "六四", "text": "无不利，撝谦。", "xiang": "无不利，撝谦，不违则也。", "baihua": "无所不利，只要奋勇直前而又谦虚谨慎。\n\n《象辞》说：无所不利，只要奋勇直前而又谦虚谨慎，因为这样才不会违犯法则。", "shaoyong": "吉： 得此爻者，无所不通，但做官的、读书人及商人宜固守退让，太盛则有过。"}, {"position": "六五", "text": "不富以其邻，利用侵伐，无不利。", "xiang": "利用侵伐，征不服也。", "baihua": "贫穷是由于敌国的侵掠，应该对之讨伐，无所不利。\n\n《象辞》说：筮遇此爻有利于征战讨伐，因为是征讨不服从王命的人。", "shaoyong": "平： 得此爻者，会得到贵人的帮助而成事，会获得利益，但须谨防生出祸端，与人争诉。当官的会文武兼用，利于进取。读书人会有金榜题名之机会。"}, {"position": "上六", "text": "鸣谦，利用行师，征邑国。", "xiang": "鸣谦，志未得也；可用行师，征邑国也。", "baihua": "明智而谦让，出兵征伐邑国自然获胜。\n\n《象辞》说：明智而谦让，尚不能感化邑国得行其志，就可以出兵征讨邑国。", "shaoyong": "平： 得此爻者，有争诉之扰，但会不辨自明。做官的须修德养身，进取有望。"}]
  },
  {
    id: 16,
    name: "雷地豫",
    shortName: "豫卦",
    upper: "震",
    lower: "坤",
    symbol: "☷\n☳",
    text: "豫。利建侯行师。",
    xiangZhuan: "雷出地奋，豫。",
    baihua: "有利于封侯建国，出兵打仗。\n\n《象辞》说：本卦上卦为震，震为雷，下卦为坤，坤为地。春雷轰鸣，大地震动，催发万物，这是豫卦的卦象。先王观此卦象，取法于声满大地的雷鸣，制作音乐，歌功颂德，光荣归于上帝，光荣归于祖考。",
    duanyi: "豫卦震上坤下，为震宫初世卦。雷出地奋，象征春雷使万物苏醒，君王之威行于子民，因此有利于建候、行师。",
    shaoyong: "雷出地上，悦服快乐；安乐之中，预防忧患。\n\n得此卦者，顺天应时，事事吉祥，可得长辈之助，但须防色难，切不可沉迷于声色欢场之中。",
    chuantong: "这个卦是异卦（下坤上震）相叠，坤为地，为顺；震为雷，为动。雷依时出，预示大地回春。因顺而动，和乐之源。此卦与谦卦互为综卦，交互作用。",
    yaoci: [{"position": "初六", "text": "鸣豫，凶。", "xiang": "初六鸣豫，志穷凶也。", "baihua": "津津乐道于荒淫享乐，凶险。\n\n《象辞》说：初六爻辞讲，津津乐道于荒淫享乐，其人意志必消退，身名必败裂。", "shaoyong": "凶： 得此爻者，不顺，有口舌之争，前进有阻力。做官的不要得意忘形，须谨慎，以免生祸。读书人则可能会一鸣惊人。"}, {"position": "六二", "text": "介于石，不终日，贞吉。", "xiang": "不终日，贞吉，以中正也。", "baihua": "夹在石缝中，幸而不到一天就被人救出。卜问得吉兆。\n\n《象辞》说：磨难不足一日即解除，卜问得吉兆，因为六二之爻居下卦中位，像人得中正之道。", "shaoyong": "吉： 得此爻者，会获利。做官的宜急流勇退，读书人有成名之机。"}, {"position": "六三", "text": "盱豫，悔。 迟有悔。", "xiang": "盱豫有悔，位不当也。", "baihua": "懒散游乐，将招致后悔；再加上懈怠大意，那就后悔莫及。\n\n《象辞》说：懒散游乐，将招致后悔，因为六三之爻居于阳位，是处置不当，像人之行事与所处地位不相称。", "shaoyong": "凶： 得此爻者，投机取巧，是非不一。"}, {"position": "九四", "text": "由豫，大有得，勿疑，朋盍簪。", "xiang": "由豫大有得。", "baihua": "田猎取乐，大获鸟兽。筮遇此爻，勿疑友人多嘴而谗己。\n\n《象辞》说：田猎取乐，大获鸟兽，说明猎获甚多，如愿以偿。", "shaoyong": "吉： 得此爻者，进取成名，经营获利。做官的会得到知己，进取有望。"}, {"position": "六五", "text": "贞疾，恒不死。", "xiang": "六五贞疾，乘刚也。", "baihua": "卜问疾病，长时间内不会死去。\n\n《象辞》说：六五爻辞讲患病，因为六五阴爻居于九四阳爻之上，犯了柔乘刚之象。“长时间不会死去”，因为六五之爻居于上卦中位，正当不死之象。", "shaoyong": "凶： 得此爻者，多心事，有灾难，或有腹疾。做官的多洋洋得意，持恩固宠，难免有失。"}, {"position": "上六", "text": "冥豫，成有渝，无咎。", "xiang": "冥豫在上，何可长也。", "baihua": "末日将至尚且享乐，已成之事也将毁败。\n\n《象辞》说：末日将至尚且享乐，以此居上位，怎能长久。", "shaoyong": "平： 得此爻者，因为心气太高，会有诉争之扰，但若能改过自新，心态平和，则不会有过失。做官的会有贪污之嫌，须明哲保身。"}]
  },
  {
    id: 17,
    name: "泽雷随",
    shortName: "随卦",
    upper: "兑",
    lower: "震",
    symbol: "☳\n☱",
    text: "",
    xiangZhuan: "泽中有雷，随。",
    baihua: "大吉大利，卜得吉兆，没有灾害。\n\n《象辞》说：本卦下卦为震，震为雷，上卦为兑，兑为泽;雷入泽中，大地寒凝，万物蛰伏，是随卦的卦象。君子观此卦象，取法于随天时而沉寂的雷声，随时作息，向晚则入室休息。",
    duanyi: "随卦兑上震下，为震宫归魂卦。随即顺从、随时之意，占得此卦，凡事顺心，吉无不利。\n\n邵雍河洛理数解卦\n\n随顺和同，贞固自持;随从机运，不能专横。\n\n小吉 ：得此卦者，宜随大势，其事可成。凡事与他人多沟通交流，可名利双收。切不可坚持己见，专横者事不成。\n\n傅佩荣解卦手册\n\n时运：明年运行，五年方展。\n\n财运：堆积存货，明春有利。\n\n家宅：防止惊惧。\n\n身体：休养为宜;牢狱之灾。\n\n传统解卦\n\n这个卦是异卦(下震上兑)相叠，震为雷，为动;兑为悦，动而悦就是“随”。随指相互顺从，己有随物，物能随己，彼此沟通。随必依时顺势，有原则和条件，以坚贞为前提。\n\n大象 ：震木在兑泽之下，木必随水漂荡，随者，顺也。\n\n运势 ：有去旧迎新之吉象，宜与人合作，可获厚利，忌三心两意，或独断独行。\n\n事业 ：对社会和人生有正确的估价，重视人际关系，善于同他人合作，事业会很顺利。为了保证取得更进一步的成功，不得贪图小利，向比自己优秀的人学习，择善而从，心存诚信、努力开拓事业。\n\n经商 ：顺利。在与他人的真诚合作下，能够达到预期的目的。在竞争中应保持清醒头脑，从大处、长远考虑，遵守商业道德，保持至诚的态度对待顾客和同行，会保持竞争优势。\n\n求名 ：在自己刻苦钻研的基础上，虚心向有德有才的师长学习，借助外界的力量，促使自己更快的进步，实现个人的理想。\n\n婚恋 ：双方情投意合可以成功，家庭和睦，但若迷恋于情爱，会影响双方的事业，务必注意。\n\n决策 ：个人成长道路并不十分顺利，但由于谦虚、随和，人际关系好，尤其能够得到长辈的器重，各种事都能在他人的帮助和关心下成功。但务必注意追随他人应有的立场和原则，不可趋炎附势，招致祸凶。\n\n台湾张铭仁解卦\n\n随：表示随遇而安，一切随缘、随和。主吉象。事事均可依随着自己的心思计划来执行，会顺利地达成。事业、投资、理财、感情，均会有令人满意的发展和收获。\n\n解释 ：跟随上司主意行事。\n\n特性 ：交际佳，贵人运多，善谋略，为辅佐良才，保守，被动。\n\n运势 ：物事均有去旧迎新之吉象，凡事与他人互相通达、协商，可名利双收。倘若三心二意，或独立单行，不听人言劝，有自招灾祸之虞。\n\n家运 ：本身有相当不错的收入，富有之象。但不可过于放纵，守操节为宜。\n\n疾病 ：病重，须长期治疗，注意口腔、肝、足患等症。\n\n胎孕 ：无碍，无惊险。\n\n子女 ：亲情融洽，与六亲和睦，幸福之象。\n\n周转 ：和气相商有利，意气用事则难成。\n\n买卖 ：勿顽强固执，则交易有利。否则失之，有阻。\n\n等人 ：会迟到。\n\n寻人 ：不必去找了，过些时日会自己回来，勿急。\n\n失物 ：即将疏忽之时，会突然察觉。\n\n外出 ：吉利。可以改变处境。\n\n考试 ：成绩理想。\n\n诉讼 ：宜决意和解，目前无忧，但不久须防有祸。\n\n求事 ：虽吉，然若能谦逊待人，多接受别人意见，会得人提拔。\n\n改行 ：有充份计划者可行。\n\n开业 ：吉利。",
    shaoyong: "",
    chuantong: "这个卦是异卦(下震上兑)相叠，震为雷，为动;兑为悦，动而悦就是“随”。随指相互顺从，己有随物，物能随己，彼此沟通。随必依时顺势，有原则和条件，以坚贞为前提。",
    yaoci: [{"position": "初九", "text": "", "xiang": "", "baihua": "馆舍时里发生事故，筮遇此爻则吉，出门同行都得好处。\n\n《象辞》说：官吏把事情办坏了，归从正道则吉利。出门同行都得好处，这是不失正道的缘故。\n\n邵雍河洛理数爻辞解释\n\n吉 ：得此爻者，多获利。做官的正当好运，有升迁之机。\n\n傅佩荣解卦手册\n\n时运：交运之时，利于变动。\n\n财运：货物外售，可以得利。\n\n家宅：装修迁居。\n\n身体：改变用药，远方求医。\n\n初九变卦\n\n\n\n初九爻动变得 周易第45卦：泽地萃 。这个卦是异卦相叠(下坤上兑)。坤为地、为顺;兑为泽、为水。泽泛滥淹没大地，人众多相互斗争，危机必四伏，务必顺天任贤，未雨绸缪，柔顺而又和悦，彼此相得益彰，安居乐业。萃，聚集、团结。", "shaoyong": ""}, {"position": "六二", "text": "", "xiang": "系小子，弗兼与也。", "baihua": "抓住了未成年的奴隶，跑了成年的奴隶。\n\n《象辞》说：抓住了小的，跑了大的，意思是两者不能兼得。\n\n邵雍河洛理数爻辞解释\n\n凶 ：得此爻者，不安宁，或受小人的暗算，是非不断。当官的宜退守，进取者要有自知之明。\n\n傅佩荣解卦手册\n\n时运：形势颠倒，最好谨慎。\n\n财运：贪小失大，显然不利。\n\n家宅：家主受累;婚嫁不妥。\n\n身体：顾此失彼。\n\n六二变卦\n\n\n\n六二爻动变得 周易第58卦：兑为泽 。这个卦是同卦(下泽上泽)相叠。泽为水。两泽相连，两水交流，上下相和，团结一致，朋友相助，欢欣喜悦。兑为悦也。同秉刚健之德，外抱柔和之姿，坚行正道，导民向上。", "shaoyong": ""}, {"position": "六三", "text": "", "xiang": "系丈夫，志舍下也。", "baihua": "抓住了成年奴隶，跑了未成年奴隶。希望无失不如现得。筮遇此爻，卜问居处则吉利。\n\n《象辞》说：抓了大的，跑了小的，其志在于追逐大的，舍弃小的。\n\n邵雍河洛理数爻辞解释\n\n平 ：得此爻者，营谋遂意，但宜走正道，才能得利。做官的会得到保举而升迁有望。\n\n傅佩荣解卦手册\n\n时运：求财求名，皆为正运。\n\n财运：小往大来，利益可期。\n\n家宅：积蓄有成，关心子女。\n\n身体：大人无妨，小孩不利。\n\n六三变卦\n\n\n\n六三爻动变得 周易第49卦：泽火革 。这个卦是异卦(下离上兑)相叠。离为火、兑为泽，泽内有水。水在上而下浇，火在下而上升。火旺水干;水大火熄。二者相生亦相克，必然出现变革。变革是宇宙的基本规律。", "shaoyong": ""}, {"position": "九四", "text": "", "xiang": "随有获，其义凶也。", "baihua": "追名逐利，贪多务获，卜问得凶兆。押送俘虏上路，明于约束，没有灾难。\n\n《象辞》说：追名逐利，贪多务获，这种人遭遇凶险是应该的。谨守信用，严守正道，这是明察事功的结果。\n\n邵雍河洛理数爻辞解释\n\n平 ：得此爻者，会得到好人的抬举，化凶为吉。做官的会身居要职，努力进取者可成事，可获得名利。\n\n傅佩荣解卦手册\n\n时运：吉凶互见，明年吉祥。\n\n财运：虽有获利，小心意外。\n\n家宅：置屋不宜。\n\n身体：先凶后吉。\n\n九四变卦\n\n\n\n九四爻动变得 周易第3卦：水雷屯 。这个卦是异卦(下震上坎)相叠，震为雷，喻动;坎为雨，喻险。雷雨交加，险象丛生，环境恶劣。“屯”原指植物萌生大地。万物始生，充满艰难险阻，然而顺时应运，必欣欣向荣。", "shaoyong": ""}, {"position": "九五", "text": "", "xiang": "孚于嘉吉，位正中也。", "baihua": "俘虏了不少嘉人，吉利。\n\n《象辞》说：信守中正之道，诸事吉利，因为九五之爻居上卦中位，像人守中正之道。\n\n邵雍河洛理数爻辞解释\n\n吉 ：得此爻者，营谋遂意，多喜庆之事，做官的会升职，或多喜事。\n\n傅佩荣解卦手册\n\n时运：正当好运，诸事皆吉。\n\n财运：货物上品，得利不少。\n\n家宅：积善之家;婚嫁可喜。\n\n身体：无须担心。\n\n九五变卦\n\n\n\n九五爻动变得 周易第51卦：震为雷 。这个卦是同卦(下震上震)相叠。震为雷，两震相叠，反响巨大，可消除沉闷之气，亨通畅达。平日应居安思危，怀恐惧心理，不敢有所怠慢，遇到突发事变，也能安然自若，谈笑如常。", "shaoyong": ""}, {"position": "上六", "text": "", "xiang": "拘系之，上穷也。", "baihua": "将俘虏拘禁起来，紧紧捆绑，周文王将他们作为人牲在西山祭祀神灵。\n\n《象辞》说：被捆绑拘禁，因为上六居一卦之尽头，像人处于穷困之境地。\n\n邵雍河洛理数爻辞解释\n\n凶 ：得此爻者，苦难多多，不很如意，重病者会有生命之忧。做官的须防止小人的谗言。\n\n傅佩荣解卦手册\n\n时运：困难重重，难以如意。\n\n财运：稳扎稳打，未能伸展。\n\n家宅：家人抱怨;嫁娶有缘。\n\n身体：诚心祷告;可能归魂。\n\n上六变卦\n\n\n\n上六爻动变得 周易第25卦：天雷无妄 。这个卦是异卦(下震上乾)相叠。乾为天为刚为健;震为雷为刚为动。动而健，刚阳盛，人心振奋，必有所得，但唯循纯正，不可妄行。无妄必有获，必可致福。\n\n未经允许不得转载： 易学界 » 周易第17卦\\_随卦(泽雷随)\\_兑上震下\\_上兑下震\\_周易六十四卦详解", "shaoyong": ""}]
  },
  {
    id: 18,
    name: "山风蛊",
    shortName: "蛊卦",
    upper: "艮",
    lower: "巽",
    symbol: "☴\n☶",
    text: "",
    xiangZhuan: "山下有风，蛊。",
    baihua: "大吉大利。利于涉水渡河，但须在甲前三日之辛日与甲后三日之丁日启程。\n\n《象辞》说：本卦上卦为艮为山，下卦为巽为风，贤人如山居于上，宣布德教施于下，所谓山下有风，这是巽卦盼卦象。君子观此卦象，取法于吹拂万物的风，从而振救万民，施行德教。",
    duanyi: "蛊卦艮上巽下，为巽宫归魂卦。蛊是指皿中食物因腐败而生虫，筮遇此卦，半凶半吉。\n\n邵雍河洛理数解卦\n\n三蛊在器，事物败坏;辛勤丁宁，转危为安。\n\n凶 ：得此卦者，艰难迷惑之时，事事不如意;宜大胆革新，奋发图强，艰苦努力，可转危为安。\n\n傅佩荣解卦手册\n\n时运：力图振作，可改旧观。\n\n财运：不宜堆积，应即贩卖。\n\n家宅：整顿家风;恐有私情;生育不顺。\n\n身体：蛊毒之症，小心咒诅。\n\n传统解卦\n\n这个卦是异卦(下巽上艮)相叠，与随卦互为综卦。蛊本意为事，引申为多事、混乱。器皿久不用而生虫称“蛊”，喻天下久安而因循、腐败，必须革新创造，治理整顿，挽救危机，重振事业。\n\n大象：风入山下，闭而不出，即物腐生虫，意气不通，因循败事。\n\n运势：诸事不如意，艰难迷惑，宜大胆革新，否则引来内忧外患。\n\n事业：运气处于不佳状态，或因外界条件，或因个人因素所致。唯有谨慎分析原因，找出弊端，坚决，大胆，不惜冒险，战胜阻力。这时一要头脑冷静，二要向高明的人请教，必能创造业绩。\n\n经商：诸多不利困扰着自己，不宜继续走老路。应全面分析市场动向，当机立断，另外找寻出路。\n\n求名：会遇到许多困难和不利，应看作是对自己的考验，要以百倍的勇气，继续奋斗。同时，虚心寻找自己的不足，加以补救。\n\n婚恋：不顺利。双方如情投意合，则应全力以赴促成此事，夫妇应共同努力维系家庭。\n\n决策：生不逢时，家道或事业有中落现象，个人陷入多事之秋。唯有正视现实，勤奋勉励，不屈不挠，有所作为，甚至不惜冒险，挽救败落状况。必要时还需耐心等待时机。\n\n台湾张铭仁解卦\n\n蛊 ：表示受到蛊惑、毒害。主大凶象。蛊毒是因内在腐朽而生虫化毒，显示问题的根因存在已久，却未诚实面对处理而导致愈来愈严重。易做出错误的决策，慨大都被人所迷惑、而一时心神错乱引致祸事。\n\n解释 ：中蛊毒，无可救药。\n\n特性 ：内心犹豫，猜疑心重，多事之秋，宜大胆革新。\n\n运势 ：诸事不如意、积弊已深，未能进展，气运杂乱。逢此宜鼓起勇气，大胆加以革新，有内忧外患之象。\n\n家运 ：家庭易生烦心之事，不彻底改革有破家、损财之象。\n\n疾病 ：宜把握治疗时机，冬季占得险象，为内脏恶性疾病。\n\n胎孕 ：胎有惊。\n\n子女 ：双亲不堪其忧之苦象耳。\n\n周转 ：信用不好，周转无望。\n\n买卖 ：交易不成，另谋生计为要。\n\n等人 ：中途有变，不会来。\n\n寻人 ：因家庭感情失和而出走，或与人私奔，于东南或东北。\n\n失物 ：找不回来，遗失似是木制工艺品，在门口或旅馆遗失，或者是寄失了。\n\n外出 ：宜推迟或提前。否则会出现危险，务必小心谨慎。\n\n考试 ：落榜。\n\n诉讼 ：慎防桃色纠纷，会拖一段时间，不易解决。\n\n求事 ：不利。\n\n改行 ：弃旧迎新，或革新内部人事。\n\n开业 ：开业者不宜，有损财或官符之灾。",
    shaoyong: "",
    chuantong: "这个卦是异卦(下巽上艮)相叠，与随卦互为综卦。蛊本意为事，引申为多事、混乱。器皿久不用而生虫称“蛊”，喻天下久安而因循、腐败，必须革新创造，治理整顿，挽救危机，重振事业。\n\n大象：风入山下，闭而不出，即物腐生虫，意气不通，因循败事。\n\n运势：诸事不如意，艰难迷惑，宜大胆革新，否则引来内忧外患。\n\n事业：运气处于不佳状态，或因外界条件，或因个人因素所致。唯有谨慎分析原因，找出弊端，坚决，大胆，不惜冒险，战胜阻力。这时一要头脑冷静，二要向高明的人请教，必能创造业绩。\n\n经商：诸多不利困扰着自己，不宜继续走老路。应全面分析市场动向，当机立断，另外找寻出路。\n\n求名：会遇到许多困难和不利，应看作是对自己的考验，要以百倍的勇气，继续奋斗。同时，虚心寻找自己的不足，加以补救。\n\n婚恋：不顺利。双方如情投意合，则应全力以赴促成此事，夫妇应共同努力维系家庭。\n\n决策：生不逢时，家道或事业有中落现象，个人陷入多事之秋。唯有正视现实，勤奋勉励，不屈不挠，有所作为，甚至不惜冒险，挽救败落状况。必要时还需耐心等待时机。",
    yaoci: [{"position": "初六", "text": "", "xiang": "干父之蛊，意承考也。", "baihua": "继承父业，有一个孝顺的儿子，固然没有灾害，即使遇到危险，最后乃吉利。\n\n《象辞》说：继承父业，意思是继承其父遗志。\n\n邵雍河洛理数爻辞解释\n\n吉：得此爻者，会得到祖先的庇佑，营谋遂意。做官的会受到重任，改革创新。\n\n傅佩荣解卦手册\n\n时运：克勤克俭，前途光明。\n\n财运：重整旧业，可以得利。\n\n家宅：改造旧宅;婚嫁可喜。\n\n身体：初无大碍，无子不利。\n\n初六变卦\n\n\n\n初六爻动变得 周易第26卦：山天大畜 。这个卦是异卦(下乾上艮)相叠。乾为天，刚健;艮为山，笃实。畜者积聚，大畜意为大积蓄。为此不畏严重的艰难险阻，努力修身养性以丰富德业。", "shaoyong": ""}, {"position": "九二", "text": "", "xiang": "干母之蛊，得中道也。", "baihua": "继承母业，则吉凶不可卜问。\n\n《象辞》说：继承母业，九二处下卦中位，爻象显示其人得中正之道。\n\n邵雍河洛理数爻辞解释\n\n平 ：得此爻者，改旧从新，则会如意。女命勤俭持家，性忠直者多福。\n\n傅佩荣解卦手册\n\n时运：顺势而行，不可草率。\n\n财运：旧债积弊，缓和处理。\n\n家宅：母系擅权，忍耐协调;可得佳妇。\n\n身体：大人寒症，小孩补气。\n\n九二变卦\n\n\n\n九二爻动变得 周易第52卦：艮为山 。这个卦是同卦(下艮上艮)相叠。艮为山，二山相重，喻静止。它和震卦相反。高潮过后，必然出现低潮，进入事物的相对静止阶段。静止如山，宜止则止，宜行则行。行止即动和静，都不可失机，应恰到好处，动静得宜，适可而止。\n\n周易第18卦九三爻详解\n\n九三爻辞\n\n九三。干父之蛊，小有悔，无大咎。\n\n象曰：干父之蛊，终无咎也。\n\n白话文解释\n\n九三：继承父业，即使稍有过错，也不会出大问题。\n\n《象辞》说：继承父业，最终不会遭逢灾难。\n\n邵雍河洛理数爻辞解释\n\n凶 ：得此爻者，躁进者有失，不听信谗言者则无难。\n\n傅佩荣解卦手册\n\n时运：痛改前非，仍有未来。\n\n财运：重立旧业，小损大利。\n\n家宅：改造住宅。\n\n身体：应可痊愈。\n\n九三变卦\n\n\n\n九三爻动变得 周易第4卦：山水蒙 。这个卦是异卦(下坎上艮)相叠，艮是山的形象，喻止;坎是水的形象，喻险。卦形为山下有险，仍不停止前进，是为蒙昧，故称蒙卦。但因把握时机，行动切合时宜，因此，具有启蒙和通达的卦象。", "shaoyong": ""}, {"position": "六四", "text": "", "xiang": "裕父之蛊，往未得也。", "baihua": "光大父业，施行起来困难重重。\n\n《象辞》说：光大父业(困难重重)，施行之中未尽得当。\n\n邵雍河洛理数爻辞解释\n\n凶 ：得此爻者，事事见忧，有足疾。\n\n傅佩荣解卦手册\n\n时运：不可因循，否则自误。\n\n财运：未能除弊，难以获利。\n\n家宅：父业难保。\n\n身体：急救内患，以免不治。\n\n六四变卦\n\n\n\n六四爻动变得 周易第50卦：火风鼎 。这个卦是异卦(下巽上离)相叠。燃木煮食，化生为熟，除旧布新的意思。鼎为重宝大器，三足稳重之象。煮食，喻食物充足，不再有困难和困扰。在此基础上宜变革，发展事业。", "shaoyong": ""}, {"position": "六五", "text": "", "xiang": "干父之蛊，承以德也。", "baihua": "继承父业，博得了赞誉。\n\n《象辞》说：继承父业而博得了赞誉，因为继承了其父的美好品德。\n\n邵雍河洛理数爻辞解释\n\n吉 ：得此爻者，多喜庆之事，家中或进人口。做官的进取有望，名誉远播。\n\n傅佩荣解卦手册\n\n时运：自行振作，仍可扬名。\n\n财运：改善旧业，仍然有利。\n\n家宅：努力兴家;嫁娶高亲。\n\n身体：应觅名医。\n\n六五变卦\n\n  \n六五爻动变得 周易第57卦：巽为风 。这个卦是同卦(下巽上巽)相叠，巽为风，两风相重，长风不绝，无孔不入，巽义为顺。谦逊的态度和行为可无往不利。", "shaoyong": ""}, {"position": "上九", "text": "", "xiang": "不事王侯，志可则也。", "baihua": "不服务于王侯，因为其人看重自身价值。\n\n《象辞》说：不服务于王侯，这种志趣可以效法。\n\n邵雍河洛理数爻辞解释\n\n平 ：得此爻者，宜守旧，好运者，多遇尊贵，能获得提拔。做官的宜退守，或告休。\n\n傅佩荣解卦手册\n\n时运：以退为进，较为有利。\n\n财运：不必急售，获利可期。\n\n家宅：住在高处;良缘天成。\n\n身体：大限将至，安其天年。\n\n上九变卦\n\n\n\n上九爻动变得 周易第46卦：地风升 。这个卦是异卦相叠(下巽上坤)。坤为地、为顺;巽为木、为逊。大地生长树木，逐的成长，日渐高大成材，喻事业步步高升，前程远大，故名“升”。\n\n未经允许不得转载： 易学界 » 周易第18卦\\_蛊卦(山风蛊)\\_艮上巽下\\_上艮下巽\\_周易六十四卦详解", "shaoyong": ""}]
  },
  {
    id: 19,
    name: "地泽临",
    shortName: "临卦",
    upper: "坤",
    lower: "兑",
    symbol: "☱\n☷",
    text: "临。元，亨，利，贞。至于八月有凶。",
    xiangZhuan: "泽上有地，临。",
    baihua: "大吉大利，吉利的卜问。到了八月，可能有凶险。\n\n《象辞》说：本卦下卦为兑为泽，上卦为坤为地，堤岸高出大泽，河泽容于大地，这是临卦的卦象。君子观此卦象，君临天下，教化万民，覃恩极虑，保容万民，德业无疆。",
    duanyi: "临卦坤上兑下，为坤宫二世卦。临卦下兑为悦，上坤为顺，欢悦而顺从，保证可以亨通。",
    shaoyong: "以上临下，相佐相互；居安思危，时时慎戒。\n\n得此卦者，好运来到，诸事如意，人情和合，但行事不宜过于急进。",
    chuantong: "这个卦是异卦（下兑上坤）相叠。坤为地，兑为泽，地高于泽，泽容于地。喻君主亲临天下，治国安邦，上下融洽。",
    yaoci: [{"position": "初九", "text": "咸临，贞吉。", "xiang": "咸临贞吉，志行正也。", "baihua": "以感化的政策治民。卜问得吉兆。\n\n《象辞》说：以感化的政策治民，治道贞正，自然吉利，因为居心端正，作风正派。", "shaoyong": "吉： 得此爻者，会交好运，营谋称意。做官的会得到众人的拥戴，能升迁。读书人参加考试者必能考出佳绩。"}, {"position": "九二", "text": "咸临，吉，无不利。", "xiang": "咸临，吉无不利，未顺命也。", "baihua": "用温和的政策治民，吉利，无不吉利。\n\n《象辞》说：用温和的政策治民，吉利，无不吉利，因为百姓尚未驯化从命。", "shaoyong": "吉： 得此爻者，营谋获利，但宜认清时机，不然不能成事，美中不足。做官的会光明磊落，地位清高。"}, {"position": "六三", "text": "甘临，无攸利。即忧之，无咎。", "xiang": "甘临，位不当也。", "baihua": "用压服的政策治民，没有什么好处。如果有所忧悔，灾祸可以消除。\n\n《象辞》说：用压服的政策治民，正如六三阴爻不当居阳位一样，这样的君王不是称职的君主。如果能有所忧悔，其灾祸则可消除。", "shaoyong": "凶： 得此爻者，有忧愁，会受苦劳累。做官的会受到小人的谗言攻击，志不能伸。"}, {"position": "六四", "text": "至临，无咎。", "xiang": "至临无咎，位当也。", "baihua": "亲自理国治民，没有害处。\n\n《象辞》说：亲自理国治民，没有害处，正如六四阴爻居阴位一样。这样的君王是称职的君王。", "shaoyong": "平： 得此爻者，人情和合，经营得利，但要成大事者，须谨慎而行，做好准备再进取。做官的会得到同僚的帮助。"}, {"position": "六五", "text": "知临，大君之宜，吉。", "xiang": "大君之宜，行中之谓也。", "baihua": "以明智治民，得君王之体，自然吉利。\n\n《象辞》说：得君王之体，因为六五之爻居上卦中位，像人行事得中正之道。", "shaoyong": "吉： 得此爻者，万事如意。做官的会得到上司的赏识。"}, {"position": "上六", "text": "敦临，吉，无咎。", "xiang": "敦临之吉，志在内也。", "baihua": "以敦厚之道治民，吉利，自然无灾祸。\n\n《象辞》说：以敦厚之道治民，吉利，因为敦厚诚实之意存于内心。", "shaoyong": "吉： 得此爻者，多获利，无往不利，但谨防气势太盛而变衰。做官的会得到上司的器重，委以重用。"}]
  },
  {
    id: 20,
    name: "风地观",
    shortName: "观卦",
    upper: "巽",
    lower: "坤",
    symbol: "☷\n☴",
    text: "观。盥而不荐，有孚顒若。",
    xiangZhuan: "风行地上，观。",
    baihua: "祭祀时灌酒降神而不献人牲，因为用作祭祀的俘虏的头部肿了，不能用作祭品。\n\n《象辞》说：本卦上卦为巽为风，下卦为坤为地，风行大地吹拂万物，这是观的卦象。先王观此卦象取法于周流八方的风，从而巡视邦国，观察民情，推行教化。",
    duanyi: "观卦巽上坤下，为乾宫四世卦。观卦象征将道义展示于众人面前。观卦风在上而地在下，是春风浩荡、万物滋生之象。",
    shaoyong: "以下观上，周游观览；平心静气，坚守岗位。\n\n得此卦者，处身于变化之中，心神不宁，宜多观察入微，待机行事，切勿妄进。",
    chuantong: "这个卦是异卦（下坤上巽）相叠，风行地上，喻德教遍施。观卦与临卦互为综卦，交相使用。在上者以道义观天下；在下者以敬仰瞻上，人心顺服归从。",
    yaoci: [{"position": "初六", "text": "童观，小人无咎，君子吝。", "xiang": "初六童观，小人道也。", "baihua": "愚蠢近视，对一般百姓来讲尚无大碍，但对于担负政治责任的君子来说，将会铸成大错。\n\n《象辞》说：初六爻辞讲，愚蠢近视，这正是小人们的思想特征。", "shaoyong": "凶： 得此爻者，宜防小人，诸事有困难，弄巧成拙。做官的有危难，不宜进取。"}, {"position": "六二", "text": "窥观，利女贞。", "xiang": "窥观女贞，亦可丑也。", "baihua": "囿于一孔之见，这是有利于女人的贞兆。\n\n《象辞》说：女人窥视男人，即使操行贞正，亦属可丑的行为。", "shaoyong": "平： 得此爻者，在家不如意，外出谋事则好，或喜或忧，或因妇人而起是非，大抵宜动不宜静。此爻女喜，男悲。"}, {"position": "六三", "text": "观我生，进退。", "xiang": "观我生进退，未失道也。", "baihua": "观察亲族的思想动向，从而决定为政的措施。\n\n《象辞》说：观察亲族的思想动向，从而决定为政的措施，这才未失去用人行政的正道。", "shaoyong": "平： 得此爻者，三心二意，须谨慎行事，知难而退。做官的进退无常。"}, {"position": "六四", "text": "观国之光，利用宾于王。", "xiang": "观国之光，尚宾也。", "baihua": "观察国家政绩风俗的辉煌表现。筮遇此爻，有利于朝觐君王。\n\n《象辞》说：观察国家政绩风俗的辉煌表现，此来者为国宾。", "shaoyong": "平： 得此爻者，宜出外谋事，多与外人交往，则有利。做官的或居闲职，清高之地。"}, {"position": "九五", "text": "观我生，君子无咎。", "xiang": "观我生，观民也。", "baihua": "善于观察亲族之意向，君子可以无过错。\n\n《象辞》说：观察亲族之意向，就是观察天下万民的意向。", "shaoyong": "吉： 得此爻者，时来运转，利益丰厚，对于妇人则有怀孕之喜，病重者有生命之忧。做官的会因为自己良好的官德，爵禄有升。"}, {"position": "上九", "text": "观其生，君子无咎。", "xiang": "观其生，志未平也。", "baihua": "观察其他部族的意向，君子可以无过错。\n\n《象辞》说：观察其他部族的意向，是因为尚未全面摸清情况，心不踏实，决心难下。", "shaoyong": "平： 得此爻者，运势不通，心有余而力不足，怀孕者利于生育，久病者会痊愈。做官的宜退守，修德养身。"}]
  },
  {
    id: 21,
    name: "火雷噬嗑",
    shortName: "噬嗑卦",
    upper: "离",
    lower: "震",
    symbol: "☳\n☲",
    text: "噬嗑。亨。利用狱。",
    xiangZhuan: "雷电噬嗑。",
    baihua: "通泰。利于讼狱。\n\n《象辞》说：本卦下卦为震为雷，上卦为离为电，雷电交合是噬嗑的卦象。先王观此卦象，取法于威风凛凛的雷、照彻幽隐的电，思以严明治政，从而明察其刑罚，修正其法律。",
    duanyi: "噬嗑卦离上震下，为巽宫五世卦。噬嗑为咬合之意，象征物品咬碎之后才能通过。此卦于诉讼有利。",
    shaoyong: "咬碎硬骨，强硬态度；事多困阻，积极谋求。\n\n得此卦者，事不遂心，纷争难免，诸事被阻，宜坚守常规，不为利诱，可保平安。",
    chuantong: "这个卦是异卦（下震上离）相叠。离为阴卦；震为阳卦。阴阳相交，咬碎硬物，喻恩威并施，宽严结合，刚柔相济。噬嗑为上下颚咬合，咀嚼。",
    yaoci: [{"position": "初九", "text": "屦校灭趾，无咎。", "xiang": "屦校灭趾，不行也。", "baihua": "拖着刑具，磨破了脚趾，但没有大的灾难。\n\n《象辞》说：拖着刑具，磨破了脚趾，小惩则可大戒，使之不重犯过错。", "shaoyong": "凶： 得此爻者，宜谨慎行事，以免生祸端。做官的会遭到贬职。\n\n台湾国学大儒傅佩荣解\n\n时运： 须防小灾，慎免大患。\n\n财运： 谨慎交易，避开木业。\n\n家宅： 兴工改造；婚嫁不宜。\n\n身体： 足病初发，宜早医治。\n\n初九变卦\n\n\n\n初九爻动变得 周易第35卦：火地晋 。这个卦是异卦（下坤上离）相叠。离为日，为光明；坤为地。太阳高悬，普照大地，大地卑顺，万物生长，光明磊落，柔进上行，喻事业蒸蒸日上。"}, {"position": "六二", "text": "噬肤灭鼻，无咎。", "xiang": "噬肤灭鼻，乘刚也。", "baihua": "大吃鲜鱼嫩肉，遭受割鼻之刑，但没有大难。\n\n《象辞》说：大吃鲜鱼嫩肉，遭受割鼻之刑，因为六二之爻居于阳爻之上，像人享受非分之福。", "shaoyong": "平： 得此爻者，进退艰难，是非不断，或生暗疾，骨肉有伤。做官的不会顺利，会有所纠结。"}, {"position": "六三", "text": "噬腊肉，遇毒。小吝，无咎。", "xiang": "遇毒，位不当也。", "baihua": "吃腊肉，中毒。碰上了麻烦，但不十分严重。\n\n《象辞》说：中毒，因为六三阴爻居于阳位，像人不称其位。", "shaoyong": "凶： 得此爻者，不易成事，运气不顺，或生心腹之疾，或有惊险。做官的才力不及，有失。"}, {"position": "九四", "text": "噬干胏，得金矢。利艰贞，吉。", "xiang": "利艰贞吉，未光也。", "baihua": "啃吃骨头，发现骨头中有金属箭头。卜问艰难之事，结果是吉利的。\n\n《象辞》说：卜问艰难之事，结果是吉利的，但目前仍处于艰难之中，尚未进入光明之境。", "shaoyong": "吉： 得此爻者，经商必获利。做官的会升迁，读书人会成名。"}, {"position": "六五", "text": "噬干肉，得黄金。贞厉，无咎。", "xiang": "贞厉无咎，得当也。", "baihua": "吃干肉，发现金属箭头。卜问得危险之兆，但最终可以无灾祸。\n\n《象辞》说：卜问得危险之兆，但最终可以无灾祸，因为六五之爻居上卦中位，位象得当，可以化险为夷。", "shaoyong": "吉： 得此爻者，行好运，有病的会痊愈，有冤的会昭雪，读书人进取成名，做官的会剪除小人。"}, {"position": "上九", "text": "何校灭耳，凶。", "xiang": "何校灭耳，聪不明也。", "baihua": "肩上扛着大枷，磨破了耳朵，凶险。\n\n《象辞》说：肩上杠着大枷，磨破了耳朵，因为其人不听劝阻，触犯了刑律。", "shaoyong": "凶： 得此爻者，须防争诉，不良者，耳目不明，血气不顺，或有生命之忧。做官的须防止小人的谗言而遭致贬职。"}]
  },
  {
    id: 22,
    name: "山火贲",
    shortName: "贲卦",
    upper: "艮",
    lower: "离",
    symbol: "☲\n☶",
    text: "贲。亨。小利有攸往。",
    xiangZhuan: "山下有火，贲。",
    baihua: "通达。有所往则有小利。\n\n《象辞》说：本卦上卦为艮为山，下卦为离为火，山下有火，火燎群山，这是贲卦的卦象。君子观此卦象，思及猛火燎山，玉石俱焚，草木皆尽，以此为戒，从而明察各项政事，不敢以威猛断狱。",
    duanyi: "贲卦艮上离下，为艮宫初世卦。贲为装饰之意，离为明，艮为止，表示有文明的制度使人们止于一定的规范，因此多为吉兆。",
    shaoyong: "文饰光明，外实内需；隐忧之时，量力而为。\n\n得此卦者，表面风光，内在空虚，多虚少实。宜充实自己，稳重行事，量力而为。",
    chuantong: "这个卦是异卦（下离上艮）相叠。离为火为明；艮为山为止。文明而有节制。贲卦论述文与质的关系，以质为主，以文调节。贲，文饰、修饰。",
    yaoci: [{"position": "初九", "text": "贲其趾，舍车而徒。", "xiang": "舍车而徒，义弗乘也。", "baihua": "脚穿花鞋，舍车不乘，徒步而行。\n\n《象辞》说：舍车不乘，徒步而行，为显示鞋子之美丽，理应不乘车。", "shaoyong": "平： 得此爻者，多奔波，静凶动吉。做官的须防退职之患。"}, {"position": "六二", "text": "贲其须。", "xiang": "贲其须，与上兴也。", "baihua": "修饰自己的胡须。\n\n《象辞》说：修饰自己的胡须，说明老人不服老，帮助君王振兴国家。", "shaoyong": "平： 得此爻者，得人提拔，好运可期，但也要相时而动，不可随性而为，以免遭难。做官的会因人成事，升迁有望。"}, {"position": "九三", "text": "贲如，濡如，永贞吉。", "xiang": "永贞之吉，终莫之陵也。", "baihua": "奔跑向前，汗流浃背。卜问长时期的凶吉而得吉兆。\n\n《象辞》说：永远贞正，必吉利，因为决没有人侵凌正人君子。", "shaoyong": "吉： 得此爻者，好运来到，不必费力，自然荣盛，即使有是非纠纷，也不足为患。做官的与人和睦，能居要职。"}, {"position": "六四", "text": "贲如，皤如，白马翰如，匪寇婚媾。", "xiang": "六四当位疑也。", "baihua": "奔跑气吁吁，太阳火辣辣。高头白马，向前飞奔。不是来抢劫，而是来娶亲。\n\n《象辞》说：六四阴爻居阴位，所处恰当。既知不是来抢劫，而是来娶亲，疑虑冰释，终无灾祸。", "shaoyong": "平： 得此爻者，先凶后吉，忧中有喜，虽有危险，终得安宁。未婚者，有望成家。做官的先难后易。"}, {"position": "六五", "text": "贲于丘园，束帛戋戋。吝，终吉。", "xiang": "六五之吉，有喜也。", "baihua": "奔向丘园，送上许多布帛，初遇困难，终则顺利。\n\n《象辞》说：六五爻辞说的吉利，是指有婚姻之喜。", "shaoyong": "吉： 得此爻者，会遇贵人，经营获利，多喜事。做官的闲职者会受到重用，在职者福禄双全。"}, {"position": "上九", "text": "白贲，无咎。", "xiang": "白贲无咎，上得志也。", "baihua": "送上白底饰以诸色花纹的布帛，不会坏事。\n\n《象辞》说：白底的布帛饰以诸色花纹，没有灾祸，因为上九居一卦之首位，像人高高在上，志得意满。", "shaoyong": "平： 得此爻者，须防好运转凶，家中、亲属有长辈或命终。做官的会升迁。"}]
  },
  {
    id: 23,
    name: "山地剥",
    shortName: "剥卦",
    upper: "艮",
    lower: "坤",
    symbol: "☷\n☶",
    text: "剥。不利有攸往。",
    xiangZhuan: "山附于地，剥。",
    baihua: "有所往则不利。\n\n《象辞》说：本卦上卦为艮为山，下卦为坤为地，山在地上，风雨剥蚀，这是剥卦的卦象。君子观此卦象，以山石剥落，岩角崩塌为戒，从而厚结民心，使人民安居乐业。",
    duanyi: "剥卦艮上坤下，为乾宫五世卦。剥卦象征剥落，因山高倾危而剥落。此时为阴气极盛之时，君子宜谨慎隐忍，不可贸然行动。",
    shaoyong: "剥削蚀烂，灾情之忧；进取难成，顺时而止。\n\n得此卦者，时运不佳，多有损失，前进有阻，宜顺时而止，安份自守。",
    chuantong: "这个卦是异卦（下坤上艮）相叠。五阴在下，一阳在上，阴盛而阳孤；高山附于地。二者都是剥落象，故为“剥卦”。此卦阴盛阳衰，喻小人得势，君子困顿，事业败坏。",
    yaoci: [{"position": "初六", "text": "剥床以足，蔑贞，凶。", "xiang": "剥床以足，以灭下也。", "baihua": "床足脱落。无须占问，这是凶险之象。\n\n《象辞》说：床足脱落，这是自毁根基。", "shaoyong": "凶： 得此爻者，营谋不遂，或有手足之灾，或兄弟不睦，凶则家破身亡。做官的有升迁之机会，但宜见机行事。"}, {"position": "六二", "text": "剥床以辨，蔑贞，凶。", "xiang": "剥床以辨，未有与也。", "baihua": "床板脱落。无须占问，这是凶险之象。\n\n《象辞》说：床板脱落，这是自毁辅佐。", "shaoyong": "凶： 得此爻者，营谋不遂，或受到小人的侵辱，或受到他人的猜忌。做官的须防被贬职。"}, {"position": "六三", "text": "剥之，无咎。", "xiang": "剥之无咎，失上下也。", "baihua": "割取邻国邻邑的土地人民，可以无灾祸。\n\n《象辞》说：割取邻国邻邑的土地人民，可以无灾祸，因为邻国邻邑的统治者已失去了上下臣民的支持。", "shaoyong": "平： 得此爻者，难遇知己，生涯不顺，欲求名利，必须创新，此爻像父母妻子或有忧，须谨防。做官的会遇到明主或大官提拔。"}, {"position": "六四", "text": "剥床以肤，凶。", "xiang": "剥床以肤，切近灾也。", "baihua": "剥取床上的垫席，这是凶险之象。\n\n《象辞》说：剥取床上的垫席，灾祸就在眼前。", "shaoyong": "凶： 得此爻者，时运不佳，危难之时，多有争诉刑克之事。做官的须谨防小人的谗言，以免遭难。"}, {"position": "六五", "text": "贯鱼，以宫人宠，无不利。", "xiang": "以宫人宠，终无尤也。", "baihua": "宫人依次当夕受宠，无所不利。\n\n《象辞》说：宫人依次当夕受宠，秩序不乱，厚薄均匀，因而终无忧患。", "shaoyong": "吉： 得此爻者，人情和合，营谋得时，家和福生，妇人进财。做官的升高进职，居要位。读书人、学子考试必能考出佳绩。"}, {"position": "上九", "text": "硕果不食，君子得舆，小人剥庐。", "xiang": "君子得舆，民所载也；小人剥庐，终不可用也。", "baihua": "劳者不得食，不劳者得食；君子乘坐华丽的车子，小人的草屋不蔽风雨。\n\n《象辞》说：君子乘坐华丽的车辆，这是老百姓沉重的负担。小人的破屋不蔽风雨，这种取象表明终究难保平安。", "shaoyong": "平： 得此爻者，须谨慎，踏实稳重者可无忧。商人生意买卖会不错。做官的会有权柄。"}]
  },
  {
    id: 24,
    name: "地雷复",
    shortName: "复卦",
    upper: "坤",
    lower: "震",
    symbol: "☳\n☷",
    text: "复。亨。出入无疾，朋来无咎。反复其道，七日来复，利有攸往。",
    xiangZhuan: "雷在地中，复。",
    baihua: "通泰。出门、居处均无疾病。有钱可赚而可以无灾祸。往返途中，七日可归。有所往则有所利。\n\n《象辞》说：本卦内卦为震为雷，外卦为坤为地，天寒地冻，雷返归地中，往而有复，依时回归，这是复卦的卦象。先王观此卦象，取法于雷，在冬至之日关闭城门，不接纳商旅，君王也不巡视邦国。",
    duanyi: "复卦坤上震下，为坤宫初世卦。复代表阴阳去而复返，使万物生生不息，预示已逝去的可能会再回来。",
    shaoyong: "循环往复，生机复萌；成功在望，性急即败。\n\n得此卦者，时运好转，顺势而为，谋事可成，但不宜过于急进。",
    chuantong: "这个卦是异卦（下震上坤）相叠。震为雷、为动；坤为地、为顺，动则顺，顺其自然。动在顺中，内阳外阴，循序运动，进退自如，利于前进。",
    yaoci: [{"position": "初九", "text": "不远复，无只悔，元吉。", "xiang": "不远之复，以修身也。", "baihua": "出外不远就返回，没有大的过失，大吉大利。\n\n《象辞》说：出外不远就返回，比喻能时时反省，严于修身。", "shaoyong": "吉： 得此爻者，万事如意，经营获利。做官的会位高权重。读书人会取得佳绩。"}, {"position": "六二", "text": "休复，吉。", "xiang": "休复之吉，以下仁也。", "baihua": "圆满而归，吉利。\n\n《象辞》说：圆满而归之所以吉利，是能够去位让贤。", "shaoyong": "吉： 得此爻者，与人共利，事业兴旺，病者痊愈。做官的遭贬者会复职。"}, {"position": "六三", "text": "频复，厉，无咎。", "xiang": "频复之厉，义无咎也。", "baihua": "愁眉苦脸地回来，是遇到了危险，知难而退可以无灾祸。\n\n《象辞》说：虽然愁眉苦脸地回来，但已脱离危险，理应没有灾祸。", "shaoyong": "平： 得此爻者，事多反复，阴阳差错，时好时坏。做官的职位不稳定，更变无定。"}, {"position": "六四", "text": "中行独复。", "xiang": "中行独复，以从道也。", "baihua": "中途独自返回。\n\n《象辞》说：中途独自返回，这是返回到道义上来。", "shaoyong": "平： 得此爻者，好运可期，营谋得利。做官的会复职。"}, {"position": "六五", "text": "敦复，无悔。", "xiang": "敦复无悔，中以自考也。", "baihua": "经过考察，决定返回，可以无悔。\n\n《象辞》说：经过考察，决定返回，可以无悔，意思是从内心用正道检察自己。", "shaoyong": "吉： 得此爻者，会有积蓄，但要谨防父亲出意外。做官的有升职之机会。"}, {"position": "上六", "text": "迷复，凶，有灾眚。用行师，终有大败，以其国君凶，至于十年不克征。", "xiang": "迷复之凶，反君道也。", "baihua": "迷途难返，凶险，有灾祸。筮遇此爻，出兵打仗，终有大败，连累国君遭遇凶险，元气大伤，十年后还不能再举征伐。\n\n《象辞》说：迷途难返遭遇凶险，这是由于君王违反君道。", "shaoyong": "凶： 得此爻者，做事乖张，诸事不顺，静吉动凶。做官的会过于贪婪权力而有损。"}]
  },
  {
    id: 25,
    name: "天雷无妄",
    shortName: "无妄卦",
    upper: "乾",
    lower: "震",
    symbol: "☳\n☰",
    text: "无妄。元，亨，利，贞。其匪正有眚，不利有攸往。",
    xiangZhuan: "天下雷行，物与无妄。",
    baihua: "嘉美通泰，卜问得吉兆。行为不正当，则有灾殃，有所往则不利。\n\n《象辞》说：本卦上卦为乾为天，下卦为震为雷，天宇之下，春雷滚动，万物萌发，孳生繁衍，这是无妄的卦象。先王观此卦象，从而奋勉努力，顺应时令，保育万物。",
    duanyi: "无妄卦乾上震下，为巽宫四世卦。无妄卦为天雷震响之象，表示事与愿违，可能会有小的灾祸，但先凶后吉。",
    shaoyong: "不欺不妄，真实至诚；顺乎自然，福禄深宏。\n\n得此卦者，顺其自然，守正道者，诸事皆宜。但行为不检者，必招灾祸。",
    chuantong: "这个卦是异卦（下震上乾）相叠。乾为天为刚为健；震为雷为刚为动。动而健，刚阳盛，人心振奋，必有所得，但唯循纯正，不可妄行。无妄必有获，必可致福。",
    yaoci: [{"position": "初九", "text": "无妄，往吉。", "xiang": "无妄之往，得志也。", "baihua": "不要妄行非正，吉利。\n\n《象辞》说：没有悖妄的行为，因为所有行动受到意志的控制。", "shaoyong": "吉： 得此爻者，营谋得利。做官的会得到上司的赞许，百姓的爱戴。"}, {"position": "六二", "text": "不耕获，不菑畲，则利有攸往。", "xiang": "不耕获，未富也。", "baihua": "不耕种就想收获，不开荒地就想种熟地。这些妄谬的行径怎能有利?\n\n《象辞》说：不耕种而想收获，这种空妄的念头不能带来财富。", "shaoyong": "吉： 得此爻者，正当好运，不劳而获。富人进财多，商人出外获利。当官的会升官。读书人会取得佳绩。"}, {"position": "六三", "text": "无妄之灾。或系之牛，行人之得，邑人之灾。", "xiang": "行人得牛，邑人灾也。", "baihua": "意外的灾难。比喻说有人将牛系在不该系的地方，行人顺手牵牛获意外之得，邑人失牛受到意外之灾。\n\n《象辞》说：行人意外得牛，邑人意外蒙灾。", "shaoyong": "凶： 得此爻者，无妄之灾，破财损身。做官的不宜进取。"}, {"position": "九四", "text": "可贞，无咎。", "xiang": "可贞无咎，固有之也。", "baihua": "称心的占问，没有灾难。\n\n《象辞》说：具有贞正的品德，没有灾难，理应如此。", "shaoyong": "平： 得此爻者，宜守旧，图谋有实，不致虚浮。做官的宜守职，勿妄动。"}, {"position": "九五", "text": "无妄之疾，勿药有喜。", "xiang": "无妄之药，不可试也。", "baihua": "患意外之病，不要忙乱服药，自可痊愈。\n\n《象辞》说：出人意外的药物，不可随便服用。", "shaoyong": "平： 得此爻者，营谋有成，病得愈，或有生育之喜。做官的纵有祸难，也会不辩自明，不解自释。"}, {"position": "上九", "text": "无妄，行有眚，无攸利。", "xiang": "无妄之行，穷之灾也。", "baihua": "不要胡作妄行！将有灾殃，没有好处。\n\n《象辞》说：谬妄的行为，是绝望无聊的表现。", "shaoyong": "平： 得此爻者，好运已过，不可妄动，否则是非迭生，唯有变通可免祸。做官的妄动有被贬职之忧。"}]
  },
  {
    id: 26,
    name: "山天大畜",
    shortName: "大畜卦",
    upper: "艮",
    lower: "乾",
    symbol: "☰\n☶",
    text: "大畜。利贞，不家食，吉。利涉大川。",
    xiangZhuan: "天在山中，大畜。",
    baihua: "吉利的贞兆。不食于家，食于朝廷，吉利。筮遇此卦，有利于涉水渡河。\n\n《象辞》说：内卦为乾为天，外卦为艮为山，太阳照耀于山中，万物摄取阳光雨露，各遂其生，这是大畜的卦象。君子观此卦象，从而广泛地了解古人的嘉言善行，来培养自己的德行。",
    duanyi: "大畜卦艮上乾下，为艮宫二世卦。畜为积蓄之意，艮为止，提示人们要停止下来积蓄力量，多主吉。",
    shaoyong: "以阳畜阴，制止欲进；坚守正道，先凶后吉。\n\n得此卦者，宜坚守正道，脚踏实地，务实行事，方可成就大业。切勿骄傲自满，目空一切。",
    chuantong: "这个卦是异卦（下乾上艮）相叠。乾为天，刚健；艮为山，笃实。畜者积聚，大畜意为大积蓄。为此不畏严重的艰难险阻，努力修身养性以丰富德业。",
    yaoci: [{"position": "初九", "text": "有厉，利已。", "xiang": "有厉利已，不犯灾也。", "baihua": "将有危险，祭祀鬼神则能化凶为吉。\n\n《象辞》说：将有危险，停止所为则能化凶为吉，因为这样就不会犯灾触难。", "shaoyong": "凶： 得此爻者，宜守旧，不然会有不测之祸。做官的宜退居闲职，或退位。"}, {"position": "九二", "text": "舆说輹。", "xiang": "舆说輹，中无尤也。", "baihua": "车辐脱落，车轮坏了。\n\n《象辞》说：车辐脱落车轮坏了，九二之爻居下卦中位，这种爻象表明毕竟没有忧患。", "shaoyong": "凶： 得此爻者，须谨防是非，或有足疾、腰疾。"}, {"position": "九三", "text": "良马逐，利艰贞。曰闲舆卫，利有攸往。", "xiang": "利有攸往，上合志也。", "baihua": "良马交配。占问艰难之事吉利。每天练习防卫性车战。有所往则有利。\n\n《象辞》说：有所往则有利，所往必得，尚可符合心意。", "shaoyong": "平： 得此爻者，会得到长辈的重用，或知己相助，前运辛苦，后可有获。做官的会有实权。"}, {"position": "六四", "text": "童豕之牿，元吉。", "xiang": "六四元吉，有喜也。", "baihua": "将木棒横缚在好斗公牛的犄角上。筮遇此爻，大吉大利。\n\n《象辞》说：六四爻辞讲的大吉大利，是指将有喜庆之事。", "shaoyong": "吉： 得此爻者，营谋有望，财富增加。做官的会有升迁之喜。"}, {"position": "六五", "text": "豮豕之牙，吉。", "xiang": "六五之吉，有庆也。", "baihua": "将好奔突的大猪圈起来，吉利。\n\n《象辞》说：六五爻辞讲的吉利，是指有吉庆之事。", "shaoyong": "吉： 得此爻者，营谋遂意，多有喜庆之事。做官的会高升。"}, {"position": "上九", "text": "何天之衢，亨。", "xiang": "何天之衢，道大行也。", "baihua": "得到上天的福佑，大吉大利。\n\n《象辞》说：得到上天的福佑，行事畅通无阻。", "shaoyong": "吉： 得此爻者，万事如意，心想事成，好运连连。做官的会得到上司的提拔，或被举荐而高升。读书人会进取成名。"}]
  },
  {
    id: 27,
    name: "山雷颐",
    shortName: "颐卦",
    upper: "艮",
    lower: "震",
    symbol: "☳\n☶",
    text: "颐。贞吉。观颐，自求口实。",
    xiangZhuan: "山下有雷，颐。",
    baihua: "占卜得吉兆。研究颐养之道，在于自食其力。\n\n《象辞》说：本卦上卦为艮为山，下卦为震为雷，雷出山中，万物萌发，这是颐卦的卦象。君子观此卦象，思生养之不易，从而谨慎言语，避免灾祸。节制饮食，修身养性。",
    duanyi: "颐卦艮上震下，为巽宫游魂卦。颐为修养、调养，雷震于山，为春来之兆，万物开始生养，因此颐卦为发展之兆，多主吉。",
    shaoyong: "养正养育，谨言节食；观察实务，自知审慎。\n\n得此卦者，对于言语及饮食，均须谨慎。宜守正道，谨言慎行，心怀阴谋者会招灾祸。",
    chuantong: "这个卦是异卦（下震上艮）相叠。震为雷，艮为山。山在上而雷在下，外实内虚。春暖万物养育，依时养贤育民。阳实阴虚，实者养人，虚者为人养。自食其力。",
    yaoci: [{"position": "初九", "text": "舍尔灵龟，观我朵颐，凶。", "xiang": "观我朵颐，亦不足贵也。", "baihua": "自己储藏着大量的财宝，还要羡嫉人家的财物，必遭凶险之事。\n\n《象辞》说：羡嫉人家的财物，这不是高尚的行为。", "shaoyong": "凶： 得此爻者，为争夺财利而起祸，大凡心底善良守正道者可无忧。做官的会受贿，失其廉。"}, {"position": "六二", "text": "颠颐，拂经；于丘颐，征凶。", "xiang": "六二征凶，行失类也。", "baihua": "为了糊口，就得在山坡上开荒种地。为了生计而去抢劫别人，这是凶险之事。\n\n《象辞》说：六二爻辞说抢劫则凶，因为这种行径违反道义。", "shaoyong": "凶： 得此爻者，大起大落，是非不一，凶者病致死。做官的须防被贬职。"}, {"position": "六三", "text": "拂颐，贞凶。十年勿用，无攸利。", "xiang": "十年勿用，道大悖也。", "baihua": "违背养生正道，靠歪门邪道过活，占问得凶兆。十年都得倒霉，永无好处。\n\n《象辞》说：十年都得倒霉，因为这种行为大有悖于道义。", "shaoyong": "凶： 得此爻者，运势低迷，荒诞无稽，甚至有生死离别之伤。做官的有丧名失节之患。"}, {"position": "六四", "text": "颠颐，吉。虎视眈眈，其欲逐逐，无咎。", "xiang": "颠颐之吉，上施光也。", "baihua": "所求不过糊口，害人之心不可存，吉利。虎视眈眈，防人之心不可无。这样就可以安享天年，悠然自得，无灾祸。\n\n《象辞》：所求不过餬口，之所以吉利，因为君上施舍甚广，足以养民。", "shaoyong": "吉： 得此爻者，会得到好人的帮助，营谋遂意。做官的会得到祖上的恩惠，幸宠有加。"}, {"position": "六五", "text": "拂经，居贞吉。不可涉大川。", "xiang": "居贞之吉，顺以从上也。", "baihua": "开荒种地，平居度日，占问得吉兆。筮遇此爻，不可涉水渡河。\n\n《象辞》说：平居守正，之所以吉利，因为其人安份循道，服从君上。", "shaoyong": "吉： 得此爻者，会有依靠，事可成，但不可乘船涉险。做官的会因人而功可成，位可保。"}, {"position": "上九", "text": "由颐，厉吉。利涉大川。", "xiang": "由颐厉吉，大有庆也。", "baihua": "遵循生活正道，先艰难而终吉利。筮遇此爻，有利于涉水渡河。\n\n《象辞》说：遵循生活正道，先艰难而终吉利，因为善良之人终得善报。", "shaoyong": "吉： 得此爻者，营谋有成，无往不利。做官的爵禄荣重。读书人会取得佳绩。"}]
  },
  {
    id: 28,
    name: "泽风大过",
    shortName: "大过卦",
    upper: "兑",
    lower: "巽",
    symbol: "☴\n☱",
    text: "大过。栋桡。利有攸往，亨。",
    xiangZhuan: "泽灭木，大过。",
    baihua: "屋粱压得弯曲了。有所往则有利，通泰。\n\n《象辞》说：本卦上卦为兑为泽，下卦为巽为木，上兑下巽，泽水淹没木舟，这是大过的卦象。君子观此卦象，以舟重则覆为戒，领悟到遭逢祸变，应守节不屈，稳居不仕，清静淡泊。",
    duanyi: "大过卦兑上巽下，为震宫游魂卦。大过即太过，事情过头了，但大过卦仍是中庸顺从之象，主其人得协助、能前进。",
    shaoyong: "阳多阴少，势将颠覆；本未俱弱，量力而为。\n\n得此卦者，身心不安，事不如意，却又强意而行，大有后悔之时，谨防官非及水险。",
    chuantong: "这个卦是异卦（下巽上兑）相叠。兑为泽、为悦，巽为木、为顺，泽水淹舟，遂成大错。阴阳爻相反，阳大阴小，行动非常，有过度形象，内刚外柔。",
    yaoci: [{"position": "初六", "text": "藉用白茅，无咎。", "xiang": "藉用白茅，柔在下也。", "baihua": "恭敬地用白茅垫着祭品，可以无灾祸。\n\n《象辞》说：“恭敬地用白茅垫着祭品”，柔软之物铺垫在下面，正像初六阴爻居一卦之下位。", "shaoyong": "平： 得此爻者，谨慎行事，财利可固。凶者，防孝服之忧。做官的小心谨慎则禄位巩固。"}, {"position": "九二", "text": "枯杨生稊，老夫得其女妻，无不利。", "xiang": "老夫女妻，过以相与也。", "baihua": "枯杨发芽，老头子娶少女为妻，并无不吉利。\n\n《象辞》说：夫老妻少，年龄不当，这是错误的婚配。", "shaoyong": "吉： 得此爻者，或娶妻纳妾，或生子，君子得少妻义子。做官的去位者会复职。"}, {"position": "九三", "text": "栋桡，凶。", "xiang": "栋桡之凶，不可以有辅也。", "baihua": "屋梁弯曲，这是凶险之象。\n\n《象辞》说：屋梁弯曲之所以凶险，因为栋曲即屋倾，无法支撑。", "shaoyong": "凶： 得此爻者，须防大难而遭致家产有失，或有足目之疾。做官的须谨防被贬职。"}, {"position": "九四", "text": "栋隆，吉。有它吝。", "xiang": "栋隆之吉，不桡乎下也。", "baihua": "屋梁挺直，吉利。但有意外之患则不好应付。\n\n《象辞》说：屋梁挺直之所以吉利，因为屋梁不弯曲则房屋不倾倒。", "shaoyong": "吉： 得此爻者，多有修造之事，可做大事，勿谋小事。做官的必能受到重用。读书人进取成名。"}, {"position": "九五", "text": "枯杨生花，老妇得其士夫，无咎无誉。", "xiang": "枯杨生花，何可久也。", "baihua": "枯杨开花，老妇人嫁给一个年轻人，这件事不好也不坏。\n\n《象辞》说：枯杨开花，其花怎能长开不谢。老妇人嫁给年轻人，这种事总不大光彩。", "shaoyong": "平： 得此爻者，营谋不利，或喜中生忧，美事成丑；先逆后顺之象。做官的不可久任。"}, {"position": "上六", "text": "过涉灭顶，凶，无咎。", "xiang": "过涉之凶，不可咎也。", "baihua": "盲目涉水，水深过顶，虽遇凶险，但终归没有灾难。\n\n《象辞》说：盲目涉水遭致危险，事已至此，谴责亦属无益。", "shaoyong": "凶： 得此爻者，不宜进取，退守为安，面部或有疾。做官的有功高震主身危之祸。"}]
  },
  {
    id: 29,
    name: "坎为水",
    shortName: "坎卦",
    upper: "坎",
    lower: "坎",
    symbol: "☵\n☵",
    text: "坎。习坎，有孚，维心亨，行有尚。",
    xiangZhuan: "水洊至，习坎。",
    baihua: "抓获俘虏，劝慰安抚他们，通泰。途中将得到帮助。\n\n《象辞》说：坎为永，水长流不滞，是坎卦的卦象。君子观此卦象，从而尊尚德行，取法于细水长流之象，学习教化人民的方法。",
    duanyi: "坎卦坎上坎下，为坎宫本位卦。坎为陷入、陷阱，为险难之境。此时应坚持信心，才能豁然贯通。",
    shaoyong: "艰难危险，重险重陷；事多困阻，谨慎行事。\n\n得此卦者，运气不佳，多难危险，事多困阻，宜谨言慎行，退守保安。",
    chuantong: "这个卦是同卦（下坎上坎）相叠。坎为水、为险，两坎相重，险上加险，险阻重重。一阳陷二阴。所幸阴虚阳实，诚信可豁然贯通。虽险难重重，却方能显人性光彩。",
    yaoci: [{"position": "初六", "text": "习坎，入于坎窞。凶。", "xiang": "习坎入坎，失道凶也。", "baihua": "坎坑之中又有坎坑，陷入重坑之中，凶险。\n\n《象辞》说：“坎坑之中又有坎坑，陷入重坑当中”，不行坦途，偏要走险道，必招致灾殃。", "shaoyong": "凶： 得此爻者，时运不佳，宜防跌入陷阱灾难之中。做官的须防小人。"}, {"position": "九二", "text": "坎有险，求小得。", "xiang": "求小得，未出中也。", "baihua": "坑坑坎坎，道有险阻。敢于行险道，或小有收获。\n\n《象辞》说：敢于行险道，或小有收获，因为九二之爻居下卦的中位，像人尚未偏离正道。", "shaoyong": "平： 得此爻者，有小成就，女命或为侍妾，凶者防险难或生心腹血气之疾。做官的会有小的成就，大事不成。"}, {"position": "六三", "text": "来之坎坎，险且枕，入于坎窞，勿用。", "xiang": "来之坎坎，终无功也。", "baihua": "向坑坎走来，这坑坎既险又深，陷入重坎之中，非常不利。\n\n《象辞》说：来到这多坎之地，终无功利。", "shaoyong": "凶： 得此爻者，多坎坷，多争诉之事。做官的宜退守。"}, {"position": "六四", "text": "樽酒簋贰，用缶，纳约自牖，终无咎。", "xiang": "樽酒簋贰，刚柔际也。", "baihua": "用铜樽盛酒，用圆簋盛饭。然而对于关押在坎窖里的犯人，只须用瓦盆子就行了，牢饭从天窗里送进取出，其人遭此噩运，但最后还是没有危险。\n\n《象辞》说：“平时享受美食美器，此时用瓦盆子吃牢饭”，爻象表明六四阴爻处于九五阳爻之卞，像人被强者所压，受此磨难。", "shaoyong": "平： 得此爻者，多喜事，或有结婚之喜。做官的多饮食之乐。"}, {"position": "九五", "text": "坎不盈，只既平，无咎。", "xiang": "坎不盈，中未大也。", "baihua": "坎坑虽没有填满，小山头却被锄平。没有灾难。\n\n《象辞》说：小山头虽锄平，但坎坑尚未填满，说明道路不平，未成坦途。", "shaoyong": "平： 得此爻者，平淡无常，宜养精蓄锐。做官的没有危难，职位无忧。"}, {"position": "上六", "text": "系用徵纆，寘于丛棘，三岁不得，凶。", "xiang": "上六失道，凶三岁也。", "baihua": "把犯人用绳索捆紧，投入周围有丛棘的监狱中，三年不得释放，这是凶险之事。\n\n《象辞》说：上六爻辞所描述的，正说明官吏违背正道，违法囚人，历时三年之久。", "shaoyong": "凶： 得此爻者，须防牢狱之灾。做官的须防职权旁落之忧。"}]
  },
  {
    id: 30,
    name: "离为火",
    shortName: "离卦",
    upper: "离",
    lower: "离",
    symbol: "☲\n☲",
    text: "离。利贞，亨。畜牝牛，吉。",
    xiangZhuan: "明两作，离。",
    baihua: "吉利的占问，通泰。饲养母牛，吉利。\n\n《象辞》说：今朝太阳升，明朝太阳升，相继不停顿，这是离卦的卦象。贵族王公观此卦象，从而以源源不断的光明照临四方。",
    duanyi: "离卦离上离下，为离宫本位卦。离可取光明、美丽、离散之意，利文章而不利出师。",
    shaoyong: "附丽光明，谦虚缓进；公正柔和，顺守则吉。\n\n得此卦者，宜谦虚谨慎，稳步进取，则前途光明。急进及意气用事者必有所损失。",
    chuantong: "这个卦是同卦（下离上离）相叠。离者丽也，附着之意，一阴附丽，上下二阳，该卦象征火，内空外明。离为火、为明，太阳反复升落，运行不息，柔顺为心。",
    yaoci: [{"position": "初九", "text": "履错然，敬之，无咎。", "xiang": "履错之敬，以辟咎也。", "baihua": "听到纷来沓至的脚步声，立时警惕戒备，可以无灾难。\n\n《象辞》说：听到纷至沓来的脚步声，立时警惕戒备，可以避免灾难。", "shaoyong": "平： 得此爻者，须防无妄之灾，宜谨慎，或有足疾。做官的宜安守。"}, {"position": "六二", "text": "黄离，元吉。", "xiang": "黄离元吉，得中道也。", "baihua": "天空出黄霓，大吉大利。\n\n《象辞》说：黄色附丽于身，大吉大利，因为六二之爻居下卦中位，像人得中正之道。", "shaoyong": "吉： 得此爻者，财利可获。做官的会受到重用。读书人会取得佳绩。"}, {"position": "九三", "text": "日昃之离。不鼓缶而歌，则大耋之嗟，凶。", "xiang": "日昃之离，何可久也。", "baihua": "黄昏时分有霓虹出现在天空，这是凶兆，人们居然不击鼓唱歌禳除它，老人感到悲哀，灾殃快要来了。\n\n《象辞》说：黄昏时分的霓虹，怎么会长留不散。", "shaoyong": "凶： 得此爻者，乐中生悲，吉中生愁，险难迭生。做官的告休。"}, {"position": "九四", "text": "突如其来如，焚如，死如，弃如。", "xiang": "突如其来如，无所容也。", "baihua": "灾难突然降临，敌人见房屋就烧，见人就杀，此处变成一片废墟。\n\n《象辞》说：灾难来得如此突然，人们无处藏身逃命。", "shaoyong": "凶： 得此爻者，时运不济，困难重重，或和长辈不睦，或遭官灾。"}, {"position": "六五", "text": "出涕沱若，戚嗟若，吉。", "xiang": "六五之吉，离王公也。", "baihua": "灾难过后，人们痛哭，人们悲叹，然而吉利。\n\n《象辞》说：六五爻辞所讲的吉利，因为爻象表明，六五之爻处于上九之下，像人们能够附丽于王公而得救。", "shaoyong": "平： 得此爻者，不宜进取，宜守常。做官的在位者得志，退职者多险危。"}, {"position": "上九", "text": "王用出征，有嘉。折首，获匪其丑，无咎。", "xiang": "王用出征，以正邦也。", "baihua": "国王出征，反击敌人，将有嘉国的国君斩首，抓到了许多俘虏，无灾无难。\n\n《象辞》说：君王出兵反击，以安定邦国。抓到了许多俘虏，是说大获胜仗。", "shaoyong": "吉： 得此爻者，时运佳，多喜事，经营获利。做官的会功成名就，读书人会取得好成绩。"}]
  },
  {
    id: 31,
    name: "泽山咸",
    shortName: "咸卦",
    upper: "兑",
    lower: "艮",
    symbol: "☶\n☱",
    text: "咸。亨，利贞。取女吉。",
    xiangZhuan: "山上有泽，咸。",
    baihua: "通达，吉利的贞卜。娶女，吉利。\n\n《象辞》说：本卦下卦为艮，艮为山，上卦为兑，兑为泽，山中有泽，山气水息，互相感应，是咸卦的卦象。君子观此卦象，取法于深邃的山谷，深广的大泽，从而虚怀若谷，以谦虚的态度，接受他人的教益。",
    duanyi: "咸卦兑上艮下，为兑宫三世卦。咸为感应，万物皆有感应，男女感应，夫妇康宁，感应之事，无有不亨。",
    shaoyong: "两性交感，正道感应；物击则鸣，识时知机。\n\n得此卦者，宜谦虚待人，则会吉祥如意，谋事可成。但勿为不正当感情而意乱情迷。",
    chuantong: "这个卦是异卦（下艮上兑）相叠。艮为山；泽为水。兑柔在上，艮刚在下，水向下渗，柔上而刚下，交相感应。感则成。",
    yaoci: [{"position": "初六", "text": "咸其拇。", "xiang": "咸其拇，志在外也。", "baihua": "伤其大脚趾。\n\n《象辞》说：大脚趾在动，说明其志在于出行。", "shaoyong": "平： 得此爻者，行事过急，多难成就。做官的须修身养性，等待机会，京官出，闲官起。"}, {"position": "六二", "text": "咸其腓，凶，居吉。", "xiang": "虽凶居吉，顺不害也。", "baihua": "伤其腿肚子，这是凶兆。小腿负伤，不宜出门，安居不动，自然平安。\n\n《象辞》说：虽遇凶兆，但安居不动，则可以转凶为吉。顺从贞卜之象可以避免灾害。", "shaoyong": "平： 得此爻者，奔波徒劳，宜静不宜动。做官的在位者吉，出差者有险。"}, {"position": "九三", "text": "咸其股，执其随，往吝。", "xiang": "咸其股，亦不处也。", "baihua": "伤其股，并伤及股下之肉。带伤出行，定遭灾难。\n\n《象辞》说：挪动其大腿说明他不安所处。但是其志向不过是追随他人，可见他所持的主张也卑下，不足取。", "shaoyong": "平： 得此爻者，最好退守，做官的谨防被贬。"}, {"position": "九四", "text": "贞吉悔亡，憧憧往来，朋从尔思。", "xiang": "贞吉悔亡，未感害也。", "baihua": "贞卜吉利，无所悔恨。纷沓往来，朋友们都顺从你的意旨。\n\n《象辞》说：贞正，吉利，无所悔恨，因为没有蒙受损害。虽然有几个朋友纷沓往来，但还是要耗费不少心思。", "shaoyong": "平： 得此爻者，朋友相助，可谋小事，大事有困难，心绪不定。做官的秉公执政，升迁有望。"}, {"position": "九五", "text": "咸其脢，无悔。", "xiang": "咸其脢，志末也。", "baihua": "伤其背肉，但没有灾祸。\n\n《象辞》说：耸动其背，作出背负重物的反应，看来其志在卑微之事。", "shaoyong": "平： 得此爻者，人情不合，营谋微小。做官的多与同僚不睦。"}, {"position": "上六", "text": "咸其辅，颊，舌。", "xiang": "咸其辅颊舌，滕口说也。", "baihua": "伤其腮帮、脸颊、舌头。\n\n《象辞》说：伤其腮帮、脸颊、舌头，这是翻腾口说招引的灾祸。", "shaoyong": "平： 得此爻者，多口舌之争，防止被他人诽谤，从事演讲、技艺、评论者吉。做官的或遭言责。"}]
  },
  {
    id: 32,
    name: "雷风恒",
    shortName: "恒卦",
    upper: "震",
    lower: "巽",
    symbol: "☴\n☳",
    text: "恒。亨，无咎，利贞。利有攸往。",
    xiangZhuan: "雷风，恒。",
    baihua: "通达，没有过失，吉利的卜问。有所往则有利。\n\n《象辞》说：本卦上卦为震，震为雷，下卦为巽，巽为风，风雷荡涤，宇宙常新，这是恒卦的卦象。君子观此卦象，从而立于正道，坚守不易。",
    duanyi: "恒卦震上巽下，为震宫三世卦。恒卦的意思就是要坚持、恒定、有恒心，这样才能获得亨通。",
    shaoyong: "经常恒久，长久不变；君子以利，不易其方。\n\n得此卦者，须立身正道，坚守不易，持续努力，必能亨通。缺少毅力，朝三暮四者则不会成功。",
    chuantong: "这个卦是异卦（下巽上震）相叠。震为男、为雷；巽为女、为风。震刚在上，巽柔在下。刚上柔下，造化有常，相互助长。阴阳相应，常情，故称为恒。",
    yaoci: [{"position": "初六", "text": "浚恒，贞凶，无攸利。", "xiang": "浚恒之凶，始求深也。", "baihua": "掘进不止，卜问凶险，没有什么好处。\n\n《象辞》说：掘进不止之所以凶险，因为冒险求深，必遭崩塌之祸。", "shaoyong": "凶： 得此爻者，人情乖离，前途渺茫，静守可免祸。做官的难于受到上司的赏识。"}, {"position": "九二", "text": "悔亡。", "xiang": "九二悔亡，能久中也。", "baihua": "没有悔恨。\n\n《象辞》说：九二爻辞说没有悔恨，因为能坚守中正之道。", "shaoyong": "平： 得此爻者，安分守己则无忧。做官的宜洁身自爱，谨慎行事。"}, {"position": "九三", "text": "不恒其德，或承之羞，贞吝。", "xiang": "不恒其德，无所容也。", "baihua": "不能保持其德行，必然蒙受耻辱。卜问得艰难之兆。\n\n《象辞》说：不能保持其德行，反复无常，无人信任，必然落到无所容身的地步。", "shaoyong": "凶： 得此爻者，须防小人诽谤，争诉之扰。做官的须防被贬。"}, {"position": "九四", "text": "田无禽。", "xiang": "久非其位，安得禽也。", "baihua": "畋猎无所获。\n\n《象辞》说：长久处于不适宜的环境，怎会有收获？", "shaoyong": "凶： 得此爻者，营谋费力，难以成事。做官的时运不济，有所退步。"}, {"position": "六五", "text": "恒其德，贞。妇人吉，夫子凶。", "xiang": "妇人贞吉，从一而终也。", "baihua": "操行一贯。卜得妇人吉利，丈夫凶险。\n\n《象辞》说：爻辞讲妇人操守贞洁则吉利，这是符合从夫以终其身的道理。丈夫则因事制义，其道多方，如果以妇德来约束男子，则必遭凶险。", "shaoyong": "凶： 得此爻者，多招毁谤，有所损失。做官的多阿谀权势而有失。"}, {"position": "上六", "text": "振恒，凶。", "xiang": "振恒在上，大无功也。", "baihua": "久动不息，凶险。\n\n《象辞》说：统治者朝令夕改，政令无常，其结果必所向无功。", "shaoyong": "凶： 得此爻者，求名望利，小能成，大则无功，女人不利夫子。做官的会很劳累，多动少静。"}]
  },
  {
    id: 33,
    name: "天山遁",
    shortName: "遁卦",
    upper: "乾",
    lower: "艮",
    symbol: "☶\n☰",
    text: "遁。亨。小利贞。",
    xiangZhuan: "天下有山，遁。",
    baihua: "通达。小有利之占问。\n\n《象辞》说：本卦上卦为乾，乾为天，下卦为艮，艮为山，天下有山，天高山远，是遁卦的卦象。君子观此卦象，从而不用以恶报恶的方法对付小人，而是采取严厉的态度，挂冠悬笏，自甘退隐，远离小人。",
    duanyi: "遁卦乾上艮下，为乾宫二世卦。卦下阴爻逐渐生长，是阳道将衰，恶事将起之兆，说明小人欲制君子，此时君子处于退避的状态。",
    shaoyong: "逃避退隐，盛极必衰；言行严禁，待机再举。\n\n得此卦者，宜退不宜进。退守可以保身，若轻举妄动则会招灾。宜谨言慎行，待机行事。",
    chuantong: "这个卦是异卦（下艮上乾）相叠。乾为天，艮为山。天下有山，山高天退。阴长阳消，小人得势，君子退隐，明哲保身，伺机救天下。",
    yaoci: [{"position": "初六", "text": "遁尾，厉。勿用有攸往。", "xiang": "遁尾之厉，不往何灾也。", "baihua": "君子全部隐退，国家就危险了。不能有所作为了。\n\n《象辞》说：逃遁隐藏仍未脱离危险，若能坚持苦斗，设法取胜，有什么灾难？", "shaoyong": "凶： 得此爻者，宜安分守己，可无忧。做官的宜择机而退。"}, {"position": "六二", "text": "执之用黄牛之革，莫之胜说。", "xiang": "执用黄牛，固志也。", "baihua": "抓来用黄牛革绳紧紧捆绑，这样就不能解脱了。\n\n《象辞》说：用黄牛革绳捆绑，表示意志坚固。", "shaoyong": "平： 得此爻者，家中有争执，安常守分无忧，农人有进牛畜之喜 。"}, {"position": "九三", "text": "系遁，有疾厉。畜臣妾，吉。", "xiang": "系遁之厉，有疾惫也。", "baihua": "被拖累而不能决然隐退，就像身染重病，情形危险。在这种情况下，蓄养奴婢或可有利。\n\n《象辞》说：被拖累以至不能决然隐退所造成的危险，有如被疾病折腾得疲惫不堪，所以说蓄养奴婢则吉，意思是暂且养疾疗伤，不可贸然行动。", "shaoyong": "平： 得此爻者，多灾多难，良善者，得妻之力，或进人口。做官的宜急流勇退。"}, {"position": "九四", "text": "好遁，君子吉，小人否。", "xiang": "君子好遁，小人否也。", "baihua": "喜爱隐居，这对君子是吉利的，对小人则未必。\n\n《象辞》说：君子不以利禄为心，喜爱隐居；小人以利禄为心，不甘退隐。", "shaoyong": "平： 得此爻者，虽有收获，但谨防因小人而受祸。做官的宜告休避难。"}, {"position": "九五", "text": "嘉遁，贞吉。", "xiang": "嘉遁贞吉，以正志也。", "baihua": "退隐以时，值得赞美，卜问前程，通泰吉利。\n\n《象辞》说：退隐以时，值得赞美；遵循正道，所以吉利，因为他存心正直，品德崇高。", "shaoyong": "吉： 得此爻者，近贵多利。做官的或升迁，或功成身退。"}, {"position": "上九", "text": "肥遁，无不利。", "xiang": "肥遁无不利，无所疑也。", "baihua": "远走高飞，退隐山林，无不利。\n\n《象辞》说：上九爻辞讲远走高飞，退隐山林，无不利，说明其人善观形势，急流勇退。", "shaoyong": "吉： 得此爻者，营谋获利，家肥业厚。做官的乐天知命，退居闲职。"}]
  },
  {
    id: 34,
    name: "雷天大壮",
    shortName: "大壮卦",
    upper: "震",
    lower: "乾",
    symbol: "☰\n☳",
    text: "大壮。利贞。",
    xiangZhuan: "雷在天上，大壮。",
    baihua: "吉利的卜问。\n\n《象辞》说：本卦上卦为震，震为雷，下卦为乾，乾为天，天上鸣雷是大壮的卦象。君子观此卦象，以迅雷可畏，礼法森严，从而畏威知惧，唯礼是遵。",
    duanyi: "大壮卦震上乾下，为坤宫四世卦。此卦中的大壮表示壮大，阳隆盛，象征君子，君子壮大当然亨通。",
    shaoyong: "光明正大，强盛壮大；容忍和气，切忌冲动。\n\n得此卦者，运势过于强盛，宜心平气和，谨慎行事，否则必生过失。",
    chuantong: "这个卦是异卦（下乾上震）相叠。震为雷；乾为天。乾刚震动。天鸣雷，云雷滚，声势宏大，阳气盛壮，万物生长。刚壮有力故曰壮。大而且壮，故名大壮。四阳壮盛，积极而有所作为，上正下正，标正影直。",
    yaoci: [{"position": "初九", "text": "壮于趾，征凶，有孚。", "xiang": "壮于趾，其孚穷也。", "baihua": "伤于脚趾。筮遇此爻，出征则凶，但尚有收获。\n\n《象辞》说：自恃兵强，侵略他国，虽有收获，但信用扫地。", "shaoyong": "凶： 得此爻者，会有争诉，动则凶，须防足疾。做官的须防小人的谗言而受辱。"}, {"position": "九二", "text": "贞吉。", "xiang": "九二贞吉，以中也。", "baihua": "卜问得吉兆。\n\n《象辞》说：九二爻辞讲贞正吉利，因为九二之爻居下卦中位，像人守中正之道。", "shaoyong": "吉： 得此爻者，营谋得意。做官的中庸处事，心中无愧。"}, {"position": "九三", "text": "小人用壮，君子用罔，贞厉。羝羊触藩，羸其角。", "xiang": "小人用壮，君子罔也。", "baihua": "小人捕兽凭气力，君子捕兽靠网围。卜问得险兆。公羊以角撞藩，结果被篱笆卡住。\n\n《象辞》说：小人捕兽凭气力，君子捕兽靠网围。", "shaoyong": "凶： 得此爻者，或有官司之事，或家中有丧，人财不利。做官的多祸难，进退难安。"}, {"position": "九四", "text": "贞吉，悔亡；藩决不羸，壮于大舆之輹。", "xiang": "藩决不羸，尚往也。", "baihua": "卜问得吉兆，没有悔恨。因为公羊冲决篱笆，摆脱了拘系，但又被车轮撞伤，不能乱冲乱撞了。\n\n《象辞》说：冲决篱笆，摆脱掏系，恐其冲撞别处。", "shaoyong": "吉： 得此爻者，常人得福，久静者必动，动则吉。做官的闲职者复职，进取如意。"}, {"position": "六五", "text": "丧羊于易，无悔。", "xiang": "丧羊于易，位不当也。", "baihua": "丧羊于狄。筮遇此爻，没有大的灾祸。\n\n《象辞》说：丧羊于狄，因为六五阴爻而居处阳位，是所处不当，像人所处环境不适当，将蒙受损失。", "shaoyong": "凶： 得此爻者，一筹莫展，不能得利，病者有丧身之兆。做官的会荒于政务。"}, {"position": "上六", "text": "羝羊触藩，不能退，不能遂，无攸利。艰则吉。", "xiang": "不能退，不能遂，不详也；艰则吉，咎不长也。", "baihua": "羊角插进了篱笆，退不了，进不了，处境不利。但是，目前虽处于艰难之中，最终可以化解逢吉。\n\n《象辞》说：不能退，不能进，陷入进退维谷之中，这是遭逢不祥。虽陷入艰难之中，最终可以化解逢吉，是说灾难不会长久。", "shaoyong": "平： 得此爻者，进退两难，多是非争诉，宜守常。做官的宜退不宜进，恐有遭贬之危。"}]
  },
  {
    id: 35,
    name: "火地晋",
    shortName: "晋卦",
    upper: "离",
    lower: "坤",
    symbol: "☷\n☲",
    text: "晋。康侯用锡马蕃庶，昼日三接。",
    xiangZhuan: "明出地上，晋。",
    baihua: "康侯用成王赐予的良马来繁殖马匹，一天多次配种。\n\n《象辞》说：“本卦上卦为离，离为日；下卦为坤，坤为地。太阳照大地，万物沐光辉”，是晋卦的卦象。君子观此卦象，从而光大自身的光明之德。",
    duanyi: "晋卦离上坤下，为乾宫游魂卦。晋取前进、晋见、晋升之意，上离下坤，为太阳普照大地，万物和顺之象，多主吉。",
    shaoyong: "日出地上，万物进展；赏赐隆重，百谋皆遂。\n\n得此卦者，如旭日东升，气运旺盛，收入颇丰，谋事可成，百事如意。",
    chuantong: "这个卦是异卦（下坤上离）相叠。离为日，为光明；坤为地。太阳高悬，普照大地，大地卑顺，万物生长，光明磊落，柔进上行，喻事业蒸蒸日上。",
    yaoci: [{"position": "初六", "text": "晋如，摧如，贞吉。罔孚，裕，无咎。", "xiang": "晋如摧如，独行正也。", "baihua": "攻击敌人，打垮敌人，卜问得吉兆。胜利之师没有捕捉俘虏，没有抢掠财物，不会有灾难。\n\n《象辞》说：攻击敌人，打垮敌人，这是因为将帅能遵循正道，所以取得了胜利。从容部署，克敌制胜，没有灾难，说明将帅能因势制宜，独断于心。", "shaoyong": "平： 得此爻者，忧愁参半，静则吉，动则凶。做官的不宜进取，须防流言。\n\n台湾国学大儒傅佩荣解\n\n时运： 耐心等待，不必急进。\n\n财运： 稍待时日，可获大利。\n\n家宅： 吉屋可居；婚姻缓成。\n\n身体： 宽心解怀。\n\n初六变卦\n\n\n\n初六爻动变得 周易第21卦：火雷噬嗑 。这个卦是异卦（下震上离）相叠。离为阴卦；震为阳卦。阴阳相交，咬碎硬物，喻恩威并施，宽严结合，刚柔相济。噬嗑为上下颚咬合，咀嚼。"}, {"position": "六二", "text": "晋如，愁如，贞吉。受兹介福，于其王母。", "xiang": "受之介福，以中正也。", "baihua": "攻击敌人，压倒敌人，卜问得吉兆。因为得到了先祖母的庇佑获得大福。\n\n《象辞》说：之所以受此大福，因为六二之爻居下卦中位，像人得中正之道。", "shaoyong": "吉： 得此爻者，求谋称意，多得母亲扶助，或得妻财。做官的守正者会进取。"}, {"position": "六三", "text": "众允，悔亡。", "xiang": "众允之，志上行也。", "baihua": "万众一心，全力进攻，无所悔恨。\n\n《象辞》说：众人信任，其志向就会实现。", "shaoyong": "平： 得此爻者，得朋友之助，营谋遂意，但谨防意外之险。做官的有升迁之机。"}, {"position": "九四", "text": "晋如鼫鼠，贞厉。", "xiang": "鼫鼠贞厉，位不当也。", "baihua": "攻击敌人而胆小如鼠，卜问得凶兆。\n\n《象辞》说：攻击敌人而胆小如鼠，卜问得凶兆，因为九四阳爻而居阴位，像人处于不利的地位。", "shaoyong": "凶： 得此爻者，时运不佳，或有争诉。做官的不宜进取，有阻力，须守正。"}, {"position": "六五", "text": "悔亡，失得勿恤，往吉，无不利。", "xiang": "失得勿恤，往有庆也。", "baihua": "无所悔恨，吃了败仗，不要气馁。只要再接再厉，终必转败为胜。无所不利。\n\n《象辞》说：受到挫失，不要气馁，勇往直前，定有喜庆降临。", "shaoyong": "吉： 得此爻者，好运到来，营谋获利。做官的有升迁之喜。"}, {"position": "上九", "text": "晋其角，维用伐邑，厉吉无咎，贞吝。", "xiang": "维用伐邑，道未光也。", "baihua": "攻击敌人，必须较量敌我双方的力量，可以考虑攻击敌人的城邑。但其结局难料：或许危险，或许吉利，或许没有灾难，或许正践凶兆。\n\n《象辞》说：考虑到攻击敌人的城邑，这说明王道未能广泛实行，以致属邑叛乱。", "shaoyong": "平： 得此爻者，有修屋宇之喜，不良者有争诉之忧。做官的有食邑之荣。"}]
  },
  {
    id: 36,
    name: "地火明夷",
    shortName: "明夷卦",
    upper: "坤",
    lower: "离",
    symbol: "☲\n☷",
    text: "明夷。利艰贞。",
    xiangZhuan: "明入地中，明夷。",
    baihua: "卜问艰难之事则利。\n\n《象辞》说：本卦内卦为离，离为日，外卦为坤，坤为地。太阳没入地中，是明夷的卦象。君子观此卦象，治民理政，不以苛察为明，而是外愚内慧，容物亲众。",
    duanyi: "明夷卦坤上离下，为坎宫游魂卦。明夷即明德被伤，象征君子受厄，此时百事宜息，静观待变。",
    shaoyong: "日入地中，光明被伤；万事阻滞，等待时运。\n\n得此卦者，时运不佳，事事劳苦，宜坚守正道，忍耐自重，等待时机。",
    chuantong: "这个卦是异卦（下离上坤）相叠。离为明，坤为顺；离为日；坤为地。日没入地，光明受损，前途不明，环境困难，宜遵时养晦，坚守正道，外愚内慧，韬光养晦。",
    yaoci: [{"position": "初九", "text": "明夷于飞，垂其翼。君子于行，三日不食。有攸往，主人有言。", "xiang": "君子于行，义不食也。", "baihua": "“鹈鹕在飞翔，停栖在沼畔。君子离家走，三日无食粮。”筮遇此爻，有所往，则必遭主人谴责。\n\n《象辞》说：君子在旅途中，依礼义不能蒙羞受食。", "shaoyong": "平： 得此爻者，或有手足之伤，善者有进财纳福之喜。做官的有飞黄腾达之象，但谨防有失。"}, {"position": "六二", "text": "明夷，夷于左股，用拯马壮，吉。", "xiang": "六二之吉，顺以则也。", "baihua": "鹈鹕，鹈鹕，伤于左股，君子负伤，因马获救。吉利。\n\n《象辞》说：六二爻辞所讲的吉利，是因为六二阴爻处于九三阳爻之下，正像马顺从主人善体人意。", "shaoyong": "吉： 得此爻者，常人或有难，但会得贵人之助。做官的会有实权，能当大任。读书人会取得好成绩。"}, {"position": "九三", "text": "明夷于南狩，得其大首，不可疾，贞。", "xiang": "南狩之志，乃大得也。", "baihua": "在南方的猎区，拉弓射箭，获得一些大野兽。筮遇此爻，占问疾病则不利。\n\n《象辞》说：决心在南方狩猎，大称其意。", "shaoyong": "平： 得此爻者，有修屋宇造作之兆。不良者，左股或有伤，多忧愁分离之患。"}, {"position": "六四", "text": "入于左腹，获明夷之心，出于门庭。", "xiang": "入于左腹，获心意也。", "baihua": "回到深隐之处吧！走出居室，进入社会，就感到环境的险恶，退隐的念头油然而生。\n\n《象辞》说：回到深隐之处，就满足了退隐的心意。", "shaoyong": "平： 得此爻者，出外营谋者会顺利，妇人有孕者生男，不良者或生心腹之疾。做官的闲职者会复职，在职者，多出外任职，韬光养晦者必出身成名。"}, {"position": "六五", "text": "箕子之明夷，利贞。", "xiang": "箕子之贞，明不可息也。", "baihua": "殷亡后，箕子逃到东方邻国避难，卜问得吉兆。\n\n《象辞》说：箕子退隐守正，他的光辉形像千古不灭。", "shaoyong": "平： 得此爻者，难逢知己，或有家难之祸。做官的须修德养性可保无忧。"}, {"position": "上六", "text": "不明晦。初登于天，后入于地。", "xiang": "初登于天，照四国也。", "baihua": "阳光消失了，天黑了。太阳初升，君子进仕之象；太阳隐没，君子退隐之象。\n\n《象辞》说：太阳初升，君子进仕，光照四方。太阳隐没，君子引退，国无楷模。", "shaoyong": "凶： 得此爻者，先喜后忧，老者或不寿。做官的防止遭人流言，或被贬。"}]
  },
  {
    id: 37,
    name: "风火家人",
    shortName: "家人卦",
    upper: "巽",
    lower: "离",
    symbol: "☲\n☴",
    text: "家人。利女贞。",
    xiangZhuan: "风自火出，家人。",
    baihua: "卜问妇女之事吉利。\n\n《象辞》说：本卦外卦为巽，巽为风；内卦为离，离为火，内火外风，风助火势，火助风威，相辅相成，是家人的卦象。君子观此卦象，从而省悟到言辞须有内容才不致于空洞，德行须持之以恒才能充沛。",
    duanyi: "家人卦巽上离下，为巽宫二世卦。家人卦为家庭和睦、和合之象，多主吉。",
    shaoyong: "人心内向，家道兴隆；严正有恒，不能移心。\n\n得此卦者，与人合作共事者会有利，且多有喜事之象，家庭和睦者，能同心协力，发展事业。",
    chuantong: "这个卦是异卦（下离上巽）相叠。离为火；巽为风。火使热气上升，成为风。一切事物皆应以内在为本，然后伸延到外。发生于内，形成于外。喻先治家而后治天下，家道正，天下安乐。",
    yaoci: [{"position": "初九", "text": "闲有家，悔亡。", "xiang": "闲有家，志未变也。", "baihua": "防范家庭出现意外事故，没有悔恨。\n\n《象辞》说：防范家庭出现意外事故，就是警惕未然事变。", "shaoyong": "平： 得此爻者，谋事有成，未婚者会结婚，老者不利于寿。做官的闲职者会晋升有实权，当职者则权力旁落。"}, {"position": "六二", "text": "无攸遂，在中馈，贞吉。", "xiang": "六二之吉，顺以巽也。", "baihua": "妇女在家中料理家务，安排饍食，没有失误，这是吉利之象。\n\n《象辞》说：六二爻辞之所以称吉利，因为六二阴爻居九三阳爻之下，像妇人对男人顺从而又谦逊。", "shaoyong": "吉： 得此爻者，营谋成家，多喜事。做官的会荣华富贵。"}, {"position": "九三", "text": "家人嗃嗃，悔厉，吉；妇子嘻嘻，终吝。", "xiang": "家人嗃嗃，未失也；妇子嘻嘻，失家节也。", "baihua": "贫困之家，众口嗷嗷待哺，这是愁苦之事，但能辛勤劳作，可以脱贫致富。而富贵之家，骄奢淫逸，妻室儿女只知嬉笑作乐，终将败落。\n\n《象辞》说：贫困之家，而能辛勤劳作，未失正派家风。富贵之冢，一味嬉笑作乐，则有失勤俭之道。", "shaoyong": "凶： 得此爻者，忧喜参半，谨防沉迷于享乐中。做官的严而少宽恕之恩。"}, {"position": "六四", "text": "富家，大吉。", "xiang": "富家大吉，顺在位也。", "baihua": "幸福家庭，大吉大利。\n\n《象辞》说：幸福家庭，大吉大利，因为六四阴爻居于九五阳爻之下，像家人和顺而各守其职。", "shaoyong": "吉： 得此爻者，时运正佳，贵人提拔，孤寡见亲。做官的仕途顺利，升迁有望。"}, {"position": "九五", "text": "王假有家，勿恤，吉。", "xiang": "王假有家，交相爱也。", "baihua": "君王到家庙祭祀祖先，不要忧虑，祖先福佑家人，凡事吉利。\n\n《象辞》说：君王到臣民之家，说明君臣交相爱护。", "shaoyong": "吉： 得此爻者，营谋得利，会得到贵人的提携。做官的显贵，进取有望。"}, {"position": "上九", "text": "有孚威如，终吉。", "xiang": "威如之吉，反身之谓也。", "baihua": "君上掌握杀罚之权，威风凛凛，权柄不移，终归吉利。\n\n《象辞》说：上九爻辞讲杀罚立威，终归吉利，因为君上能够内省己身，外树威望。", "shaoyong": "吉： 得此爻者，营谋称意，女命更好。做官的位高权重，读书人进取成名。"}]
  },
  {
    id: 38,
    name: "火泽睽",
    shortName: "睽卦",
    upper: "离",
    lower: "兑",
    symbol: "☱\n☲",
    text: "睽。小事吉。",
    xiangZhuan: "上火下泽，睽。",
    baihua: "筮遇此卦，小事吉利。\n\n《象辞》说：本卦上卦为离，离为火；下卦为兑，兑为泽。上火下泽，两相乖离，是睽卦的卦象。君子观此卦象，从而综合万物之所同，分析万物之所异。",
    duanyi: "睽卦离上兑下，为艮宫四世卦。睽象征乖离、乖异，筮遇此卦，大事不吉，小事顺利。",
    shaoyong: "人心外向，背道而驰；难以成事，不宜大举。\n\n得此卦者，运气不佳，水火不容，相互矛盾，诸事难成。",
    chuantong: "这个卦是异卦（下兑上离）相叠。离为火；兑为泽。上火下泽，相违不相济。克则生，往复无空。万物有所不同，必有所异，相互矛盾。睽即矛盾。",
    yaoci: [{"position": "初九", "text": "悔亡，丧马勿逐，自复。见恶人，无咎。", "xiang": "见恶人，以辟咎也。", "baihua": "不必悔恨，丢失了马匹，不必寻找，它自会回来，途中碰见坏人，也不会有灾祸。\n\n《象辞》说：遇见坏人之所以无灾祸，意在消除恶人的恶意。", "shaoyong": "平： 得此爻者，营谋先失而后得，人事先离而后合，谨防凶恶之灾患。做官的闲职者复职，被贬者复升。"}, {"position": "九二", "text": "遇主于巷，无咎。", "xiang": "遇主于巷，未失道也。", "baihua": "遇着了热情好客的主人，没有灾难。\n\n《象辞》说：遇着了热情好客的主人，这说明没有迷失道路。", "shaoyong": "平： 得此爻者，会得知己，营谋遂意。做官的会遇到明主，升迁有望。"}, {"position": "六三", "text": "见舆曳，其牛掣。其人天且劓，无初有终。", "xiang": "见舆曳，位不当也；无初有终，遇刚也。", "baihua": "看见一辆拉货的车，拉车的牛一俯一仰拉得很费劲，赶车的人是一个烙了额，割了鼻的奴隶。起初车子陷着不动，后来终于拉动了。\n\n《象辞》说：看见一个烙额割鼻的奴隶在拉车，爻象表明：六三阴爻而居于阳位，所处不当，像人落入了悲苦的境地。起初不顺，结局倒好，因为六三阴爻上进遇到九四阳爻，像人得到强者的帮助。", "shaoyong": "凶： 得此爻者，谋望有阻，险中求安，先迷后顺。不良者有骨肉刑伤之厄。做官的须防小人的谗言。"}, {"position": "九四", "text": "睽孤，遇元夫。交孚，厉无咎。", "xiang": "交孚无咎，志行也。", "baihua": "旅人孤单地行路，遇上一个跛子，一同被抓住，情形危险，但终无灾祸。\n\n《象辞》说：交相信任，必无灾难，说明其志得行，目的达到。", "shaoyong": "平： 得此爻者，能得到朋友的帮助，转危为安，求婚者必配。做官的会得到同僚的推荐，升迁有机。"}, {"position": "六五", "text": "悔亡，厥宗噬肤，往何咎。", "xiang": "厥宗噬肤，往有庆也。", "baihua": "没有悔恨。瞧见同族宗人在吃肉，孤单的旅人欣然结伴同行，一路平安无事。\n\n《象辞》说：同族宗人在吃肉，前往，必有喜庆之事。", "shaoyong": "平： 得此爻者，经营获利，抬举有人。不良者，亲朋怨恶，骨肉刑伤，官司牵连。做官的会获得成就与名望，读书人会取得佳绩。"}, {"position": "上九", "text": "睽孤，见豕负涂，载鬼一车。先张之弧，后说之弧，匪寇婚媾。往遇雨则吉。", "xiang": "遇雨之吉，群疑亡也。", "baihua": "旅人孤单地行路，见一头大猪伏在路上，又遇上一辆大车，上面满载着打扮得奇形怪状的人。旅人搭弓欲射，后来又放下弓箭。因为这伙人不是强盗，而是去订婚的。旅人照常行进，遇上大雨，但一切平安。\n\n《象辞》说：上九爻辞讲的旅人途遇婚媾之人，开始相互猜疑，几致动武，后来相安无事，照常旅行。这是因为双方疑惧消失了。", "shaoyong": "平： 得此爻者，遭污受诬，先损后益。做官的须防被诽谤之忧。"}]
  },
  {
    id: 39,
    name: "水山蹇",
    shortName: "蹇卦",
    upper: "坎",
    lower: "艮",
    symbol: "☶\n☵",
    text: "蹇。利西南，不利东北。利见大人，贞吉。",
    xiangZhuan: "山上有水，蹇。",
    baihua: "筮遇此卦，利西南行，不利东北行。利见贵族王公，获吉祥之兆。\n\n《象辞》说：上卦为坎，坎为水；下卦为艮，艮为山，山石磷峋，水流曲折，是蹇卦的卦象。君子观此卦象，悟行道之不易，从而反求诸己，修养德行。",
    duanyi: "蹇卦坎上艮下，为兑宫四世卦。此卦利于向西南方向行，不利于向东北方向，又利见大人。",
    shaoyong: "踏步难行，艰辛万苦；进退维谷，容忍待时。\n\n得此卦者，身心忧苦，举步维艰，宜守正道，不可妄动，涉险境者会有灾难。",
    chuantong: "这个卦是异卦（下艮上坎）相叠。坎为水，艮为山。山高水深，困难重重，人生险阻，见险而止，明哲保身，可谓智慧。蹇，跋行艰难。",
    yaoci: [{"position": "初六", "text": "往蹇来誉。", "xiang": "往蹇来誉，宜待也。", "baihua": "出门艰难，归来安适。\n\n《象辞》说：出门艰难，归来安适，知难而退，坐待时机。", "shaoyong": "平： 得此爻者，宜守旧安常。做官的稳步进取，好运将至。"}, {"position": "六二", "text": "王臣蹇蹇，匪躬之故。", "xiang": "王臣蹇蹇，终无尤也。", "baihua": "王臣之所以屡犯艰难，并不是为自身私利。\n\n《象辞》说：王臣出以公心屡犯艰难，其自身始终没有过失。", "shaoyong": "凶： 得此爻者，涉艰历险，营谋有阻。做官的宜保持忠贞，报效国家。"}, {"position": "九三", "text": "往蹇来反。", "xiang": "往蹇来反，内喜之也。", "baihua": "出门困难重重，归来笑逐颜开。\n\n《象辞》说：出门困难重重，归来笑逐颜开，这是发自内心的喜悦。", "shaoyong": "平： 得此爻者，不宜进取，或有妻子之喜。做官的位高者会晋升。"}, {"position": "六四", "text": "往蹇来连。", "xiang": "往蹇来连，当位实也。", "baihua": "出门步履艰难，归来时却有车可乘。\n\n《象辞》说：出门步履艰难，归来时却有车可乘，因为六四阴爻居阴位，像人才正当其位，德符其名。", "shaoyong": "凶： 得此爻者，不良者会有争诉。做官的进升有机，求名望利皆有实而不虚。"}, {"position": "九五", "text": "大蹇朋来。", "xiang": "大蹇朋来，以中节也。", "baihua": "经历了很多艰难困苦，终予获得大利。\n\n《象辞》说：大难当前，得到友人相助，因为九五之爻居上卦中位，像人节操贞正自能获救。", "shaoyong": "吉： 得此爻者，会得到贵人提举，无往不利。"}, {"position": "上六", "text": "往蹇来硕，吉。利见大人。", "xiang": "往蹇来硕，志在内也；利见大人，以从贵也。", "baihua": "出门困难重重，归来欢喜跳跃。筮遇此爻，吉利，利于会见贵族王公。\n\n《象辞》说：出门困难重重，归来欢喜跳跃，说明志气高昂，奋勇取胜。爻辞说：利于会见贵族王公，说明追随贵人，必获福利。", "shaoyong": "吉： 得此爻者，好运来到，营谋遂意。做官的会身居要职，读书人进取成名。"}]
  },
  {
    id: 40,
    name: "雷水解",
    shortName: "解卦",
    upper: "震",
    lower: "坎",
    symbol: "☵\n☳",
    text: "解。利西南。无所往，其来复吉。有攸往，夙吉。",
    xiangZhuan: "雷雨作，解。",
    baihua: "利于西南行，但是，若没有确定的目标，则不如返回，返回吉利。如果有确定的目标，则宜早行，早行吉利。\n\n《象辞》说：本卦上卦为震，震为雷；下卦为坎，坎为雨，雷雨并作，化育万物，是解卦的卦象。君子观此卦象，从而赦免过失，宽宥罪人。",
    duanyi: "解卦震上坎下，为震宫二世卦。震为动，坎为险，遇险而动，为即将脱险走出困境之兆，因此多主吉。",
    shaoyong: "艰难化散，排难解纷；把握时机，趁早进行。\n\n得此卦者，能解脱先前之困难，宜把握良机，求谋事业，出外谋事者更佳。",
    chuantong: "这个卦是异卦（下坎上震）相叠。震为雷、为动；坎为水、为险。险在内，动在外。严冬天地闭塞，静极而动。万象更新，冬去春来，一切消除，是为解。",
    yaoci: [{"position": "初六", "text": "无咎。", "xiang": "刚柔之际，义无咎也。", "baihua": "筮遇此爻，没有灾难。\n\n《象辞》说：初六与九二相接，为刚柔相应之象，喻君臣、夫妻和衷共济，其义自无灾难。", "shaoyong": "平： 得此爻者，经营者吉，未婚者配。做官的德位相称，晋升有望，读书人会取得好成绩。"}, {"position": "九二", "text": "田获三狐，得黄矢，贞吉。", "xiang": "九二贞吉，得中道也。", "baihua": "畋猎获得三只狐狸，猎物身上带着铜箭头。卜问得吉兆。\n\n《象辞》说：九二爻辞讲的卜问得吉兆，因为九二之爻居下卦中位，像其人行事遵循正道。", "shaoyong": "吉： 得此爻者，正当好运，财利可获。做官的会荣华富贵，读书人会取得佳绩。"}, {"position": "六三", "text": "负且乘，致寇至，贞吝。", "xiang": "负且乘，亦可丑也；自我致戎，又谁咎也。", "baihua": "带着许多财物，又是背负，又是车拉，招摇惹盗，自然招致盗寇抢劫，卜问有灾祸之象。\n\n《象辞》说：带着许多财物，又是背负，又是车拉，招摇惹盗，这是愚蠢可耻之事，由于自己慢藏诲盗，招致盗寇，又能谴责谁呢？", "shaoyong": "凶： 得此爻者，须防窃盗，是非诉讼。做官的谨防被贬之忧。"}, {"position": "九四", "text": "解而拇，朋至斯孚。", "xiang": "解而拇，未当位也。", "baihua": "赚了钱，而懒怠不想走，结果被人虏去。\n\n《象辞》说：懒怠不想动，说明其人怠于职守，不称其位。", "shaoyong": "凶： 得此爻者，须防小人，或有交友不慎之祸。"}, {"position": "六五", "text": "君子维有解，吉，有孚于小人。", "xiang": "君子有解，小人退也。", "baihua": "君子被拘囚后又获释，吉利；小人则将受罚。\n\n《象辞》说：君子解除了小人的职务，说明小人被摒退。", "shaoyong": "吉： 得此爻者，正当好运，君子有利，病者愈。做官的会身居要职。"}, {"position": "上六", "text": "公用射隼，于高墉之上，获之无不利。", "xiang": "公用射隼，以解悖也。", "baihua": "在高高的城墙上，王公射中一只鹰，并且抓到了，这没有什么不吉利的。\n\n《象辞》说：王公射鹰，意在除强去暴。", "shaoyong": "吉： 得此爻者，运途顺利，多营谋获利。做官的闲职者会复职，居要位。"}]
  },
  {
    id: 41,
    name: "山泽损",
    shortName: "损卦",
    upper: "艮",
    lower: "兑",
    symbol: "☱\n☶",
    text: "损。有孚，元吉，无咎，可贞。利有攸往。曷之用？二簋可用享。",
    xiangZhuan: "山下有泽，损。",
    baihua: "筮遇此卦，将有所俘获，大吉大利，没有灾难，是称心的卜问。而且所往将获利。将有人送来两盆食物，可享口福。\n\n《象辞》说：本卦上卦为艮，艮为山；下卦为兑，兑为泽，可见山下有泽是损卦的卦象。君子观此卦象，以泽水浸蚀山脚为戒，从而制止其忿怒，杜塞其贪欲。",
    duanyi: "损卦艮上兑下，为艮宫三世卦。损象征损益、减少，为损己之兆，多主不吉，但只要坚守诚信，就会有利。",
    shaoyong: "损下益上，损盈益虚；先难后易，量入为出。\n\n得此卦者，损己利人，虽然开始会有所不顺，但付出总会有所回报，因祸得福之象。",
    chuantong: "这个卦是异卦（下兑上艮）相叠。艮为山；兑为泽。上山下泽，大泽浸蚀山根。损益相间，损中有益，益中有损。二者之间，不可不慎重对待。损下益上，治理国家，过度会损伤国基。应损则损，但必量力、适度。少损而益最佳。",
    yaoci: [{"position": "初九", "text": "已事遄往，无咎，酌损之。", "xiang": "已事遄往，尚合志也。", "baihua": "祭祀大事，得赶快去参加，这才不会有灾难。祭品过丰，可以酌情减损。\n\n《象辞》说：“祭祀大事，得赶快去参加”，这是体现了敬畏鬼神的心意。", "shaoyong": "平： 得此爻者，谋事得当，可获利，不良者，或因酒食误事。做官的会因为工作忙碌而顾不得家庭，声望日盛。"}, {"position": "九二", "text": "利贞，征凶。弗损，益之。", "xiang": "九二利贞，中以为志也。", "baihua": "吉利的卜问。征伐他国则凶。因为这样作对于他国非但不能损伤，反而有利。\n\n《象辞》说：九二爻辞讲的吉利的卜问，因为九二之爻居下卦中位，像人行事以处正守贞为心。", "shaoyong": "凶： 得此爻者，宜谨守勿动。做官的时机未成熟，难于升迁。"}, {"position": "六三", "text": "三人行，则损一人；一人行，则得其友。", "xiang": "一人行，三则疑也。", "baihua": "三人同行，难免意见分岐，必有一人被孤立。一人独行，孤单无助，则主动邀人作伴。\n\n《象辞》说：一人独行，凡事自作主张，事无掣肘。三人同行，遇事各持己见，滋生疑惑。", "shaoyong": "平： 得此爻者，合力经营，获利者多，未婚者配。做官的与同僚关系融洽，进取有望。"}, {"position": "六四", "text": "损其疾，使遄有喜，无咎。", "xiang": "损其疾，亦可喜也。", "baihua": "要消除疾病，赶快求巫祭神，病就会有好转，必无灾难。\n\n《象辞》说：“求巫祭神消除疾病”，也是可喜之事。", "shaoyong": "平： 得此爻者，多喜庆之事，有灾者转好运，有病者愈，有忧者转喜。做官的闲职者将被起复。"}, {"position": "六五", "text": "或益之，十朋之龟，弗克违。元吉。", "xiang": "六五元吉，自上佑也。", "baihua": "有人送给他价值十朋的大龟，这不能拒而不收，得龟用于占卜这是大吉之事。\n\n《象辞》说：六五爻辞讲的大吉大利，因为上天保佑他，赐以灵龟，所以大吉。", "shaoyong": "吉： 得此爻者，运势大好，财利丰富。做官的会得到领导的赞赏和提拔。读书人会取得佳绩。"}, {"position": "上九", "text": "弗损，益之，无咎。贞吉。利有攸往，得臣无家。", "xiang": "弗损益之，大得志也。", "baihua": "不要减损，不要增益，一任其旧，没有灾难，卜问得吉兆。筮遇此爻，有所往则必获利，将得到一单身奴隶。\n\n《象辞》说：不要减损，不要增益，公允执中，如此行事，平生志愿当能实现。", "shaoyong": "吉： 得此爻者，贵人扶持，财利可期。做官的会得到下属的爱戴，领导的器重。"}]
  },
  {
    id: 42,
    name: "风雷益",
    shortName: "益卦",
    upper: "巽",
    lower: "震",
    symbol: "☳\n☴",
    text: "益。利有攸往，利涉大川。",
    xiangZhuan: "风雷，益。",
    baihua: "筮遇此爻，利于有所往，利于涉水渡河。\n\n《象辞》说：本卦上卦为巽，巽为风；下卦为震，震为雷，风雷激荡，是益卦的卦象。君子观此卦象，惊恐于风雷的威力，从而见善则从之，有过则改之。",
    duanyi: "益卦巽上震下，为巽宫三世卦。益卦为损益、收益之意，利有所往，利涉大川，多主吉。",
    shaoyong: "损上益下，奋发有为；进取成名，商贾获利。\n\n得此卦者，正当好运，奋发图进，得人帮助，能获名利。",
    chuantong: "这个卦是异卦（下震上巽）相叠。巽为风；震为雷。风雷激荡，其势愈强，雷愈响，风雷相助互长，交相助益。此卦与损卦相反。它是损上以益下，后者是损下以益上。二卦阐述的是损益的原则。",
    yaoci: [{"position": "初九", "text": "利用为大作，元吉，无咎。", "xiang": "元吉无咎，下不厚事也。", "baihua": "筮遇此爻，利于大兴土木，大吉大利，并无灾祸。\n\n《象辞》说：大吉大利，并无灾祸，因为百姓努力工作，加快了工程进度。", "shaoyong": "吉： 得此爻者，大事可成，万事称心。做官的会高升，读书人会取得大的成绩。\n\n台湾国学大儒傅佩荣解\n\n时运： 大事可为，无不如意。\n\n财运： 有人有谋，大利在前。\n\n家宅： 新宅宽大，婚姻大吉。\n\n身体： 健康无虞。\n\n初九变卦\n\n\n\n初九爻动变得 周易第20卦：风地观 。这个卦是异卦（下坤上巽）相叠，风行地上，喻德教遍施。观卦与临卦互为综卦，交相使用。在上者以道义观天下；在下者以敬仰瞻上，人心顺服归从。"}, {"position": "六二", "text": "或益之，十朋之龟，弗克违，永贞吉。王用享于帝，吉。", "xiang": "或益之，自外来也。", "baihua": "有人赐予价值十朋的大龟，不可拒违其命。卜问得长久的吉兆。君王祭祀天帝，吉利。\n\n《象辞》说：有人赐予我们宝龟，说明这大宝龟是从外面送来的。", "shaoyong": "吉： 得此爻者，商贾获利，福份多多。做官的仕途一帆风顺，读书人进取成名。"}, {"position": "六三", "text": "益之用凶事，无咎。有孚中行，告公用圭。", "xiang": "益用凶事，固有之也。", "baihua": "因为武王逝世，增加祭祀鬼神的祭物，没有灾祸。武庚乘国丧作乱，周公发兵征讨，大获胜仗，抓获俘虏。中衍向周公报告，从而举行祭祀。\n\n《象辞》说：因为有丧事，增加祭祀鬼神的祭物，这是自然之理。", "shaoyong": "平： 得此爻者，常人获利，不良者大凶，官灾祸患并至。做官的会受到重用，委以重职。"}, {"position": "六四", "text": "中行，告公从。利用为依迁国。", "xiang": "告公从，以益志也。", "baihua": "中衍向周公报告了处理殷室遗民之事，周公听从了，顺利地将殷商遗民分封给各封国。\n\n《象辞》说：周公听从了王命，说明君臣上下团结更加巩固。", "shaoyong": "平： 得此爻者，或会迁居，或有修造，诉者利，官者伸。做官的会被领导委以重任。"}, {"position": "九五", "text": "有孚惠心，勿问元吉。有孚惠我德。", "xiang": "有孚惠心，勿问之矣。", "baihua": "捕获了很多俘虏，安抚他们，不必追究，大吉大利。这些俘虏，将感戴我的恩德。\n\n《象辞》说：捕获了很多俘虏，安抚他们，不要追究他们的责任，使他们感戴我的恩德，说明这样可以笼络人心。", "shaoyong": "吉： 得此爻者，谋望称意，事多顺利。做官的会遇到明主，仕途顺利。"}, {"position": "上九", "text": "莫益之，或击之，立心勿恒，凶。", "xiang": "莫益之，偏辞也。", "baihua": "没有人帮助他，还有人攻击他。在这种情况下，立志不坚定，就要坏事。\n\n《象辞》说：没有人帮助他，这是周遍之辞，表示根本没有相助者。有人攻击他，说明这攻击来自外部。", "shaoyong": "凶： 得此爻者，贪图名利，或有意外之祸，刑克损伤之灾。做官的因为贪求名位，或被贬职。"}]
  },
  {
    id: 43,
    name: "泽天夬",
    shortName: "夬卦",
    upper: "兑",
    lower: "乾",
    symbol: "☰\n☱",
    text: "夬。扬于王庭，孚号，有厉。告自邑，不利即戎，利有攸往。",
    xiangZhuan: "泽上于天，夬。",
    baihua: "王庭里正跳舞作乐。有人呼告：“有敌人来犯。”邑中传来命令：“出击不利，要严阵以待。”筮遇此爻，出外旅行则吉利。\n\n《象辞》说：本卦上卦为兑，兑为泽；下卦为乾，乾为天，可见泽水上涨，浇灌大地，是夬卦的卦象。君子观此卦象，从而泽惠下施，不敢居功自傲，并以此为忌。",
    duanyi: "夬卦兑上乾下，为坤宫五世卦。此卦中的夬为决断、决裂，象征会有危险之事，利有攸往，往前有利。",
    shaoyong: "排除决去，必须刚断；始吉终凶，谨慎自重。\n\n得此卦者，大运将过，困难将至，宜提高警惕，谨言慎行。",
    chuantong: "这个卦是异卦（下乾上兑）相叠。乾为天为健；兑为泽为悦。泽气上升，决注成雨，雨施大地，滋润万物。五阳去一阴，去之不难，决（去之意）即可，故名为夬（guài），夬即决。",
    yaoci: [{"position": "初九", "text": "壮于前趾，往不胜为咎。", "xiang": "不胜而往，咎也。", "baihua": "脚趾受伤，仍然继续前进，将因为脚力不胜而遭致灾难。\n\n《象辞》说：脚力不胜而继续行进，将遭灾难。", "shaoyong": "凶： 得此爻者，会有无妄之灾，宜静守。做官的躁动者有损。"}, {"position": "九二", "text": "惕号，莫夜有戎，勿恤。", "xiang": "有戎勿恤，得中道也。", "baihua": "恐惧地惊叫，夜间有敌来犯，但不足为患。\n\n《象辞》说：有敌来犯，不足为患，因为九二之爻居下卦中位，像人得中正之道。", "shaoyong": "凶： 得此爻者，多忧愁，多惊险，谨防盗窃之事发生。做官的多掌兵权。"}, {"position": "九三", "text": "壮于頄，有凶。君子夬夬，独行遇雨，若濡有愠，无咎。", "xiang": "君子夬夬，终无咎也。", "baihua": "颧骨受伤，这是凶象。君子匆匆忙忙地独个儿行路，碰上了雨，全身淋湿了，令人很不快，但没有灾难。\n\n《象辞》说：君子匆匆忙忙地独个儿行路，但最后没有灾难。", "shaoyong": "凶： 得此爻者，会有争诉之忧，品行端正者无忧，初见艰难，终得安乐。做官的除奸不成，反被倒咬一口。"}, {"position": "九四", "text": "臀无肤，其行次且。牵羊悔亡，闻言不信。", "xiang": "其行次且，位不当也；闻言不信，聪不明也。", "baihua": "臀部受伤，走起路来踉踉跄跄。牵羊上路，悔恨丢失了羊儿，这是由于对别人的告诫不相信。\n\n《象辞》说：行路艰难，因为九四阳爻而居阴位，像人处境不利。对于别人的告诫不相信，说明听觉虽好，但不明事理。", "shaoyong": "凶： 得此爻者，心绪不定，所谋不成。做官的有心而力不足，难于升迁。"}, {"position": "九五", "text": "苋陆夬夬，中行无咎。", "xiang": "中行无咎，中未光也。", "baihua": "细角山羊在道路中间蹦蹦跳跳，筮遇此爻无灾难。\n\n《象辞》说：行中正之道，仅称无灾难，大概是没有将中行之道推广施行。", "shaoyong": "平： 得此爻者，营谋遂意，诉者伸，有病者愈。做官的须防奸邪之辈侵害。"}, {"position": "上六", "text": "无号，终有凶。", "xiang": "无号之凶，终不可长也。", "baihua": "狗在哭叫，预兆着终将有凶险之事。\n\n《象辞》说：国无号令，其势必遭凶险，说明国运衰微，终不可保。", "shaoyong": "凶： 得此爻者，营谋不成，宜守常，不良者，骨肉刑克，是非缠绕。做官的难于久任，激流勇退为佳。"}]
  },
  {
    id: 44,
    name: "天风姤",
    shortName: "姤卦",
    upper: "乾",
    lower: "巽",
    symbol: "☴\n☰",
    text: "姤。女壮，勿用取女。",
    xiangZhuan: "天下有风，姤。",
    baihua: "梦见女子受伤。筮遇此卦，不利于娶女。\n\n《象辞》说：本卦上卦为乾，乾为天；下卦为巽，巽为风，可见天下有风，是姤卦的卦象，君王观此卦象，从而效法于风之吹拂万物，施教化于天下，昭告四方。",
    duanyi: "姤卦乾上巽下，一阴五阳，为乾宫初世卦。姤卦以阴遇阳，以柔乘刚，含有不期而遇之意，但不宜娶女。遇此卦适宜谋事，如果遇火，还会有喜事。",
    shaoyong: "阴长阳消，鸿运中衰；诸多阻滞，谨慎以防。\n\n得此卦者，阴长阳衰，诸事不顺，宜谨慎行事，更应注意桃色纠纷。",
    chuantong: "这个卦是异卦（下巽上乾）相叠。乾为天，巽为风。天下有风，吹遍大地，阴阳交合，万物茂盛。姤（gǒu）卦与夬卦相反，互为“综卦”。姤即媾，阴阳相遇。但五阳一阴，不能长久相处。",
    yaoci: [{"position": "初六", "text": "系于金柅，贞吉。有攸往，见凶。羸豕孚蹢躅。", "xiang": "系于金柅，柔道牵也。", "baihua": "细柔之线牵附于黄铜柅子之上。这是吉利的贞兆。若占问有所往，则必逢凶险，就象瘦弱的猪被不情愿地拖回来。\n\n《象辞》说：细柔之线牵附于黄铜柅子上，是说柔物被牵制于刚物，以像柔弱者依附于刚强者，则获吉利。", "shaoyong": "平： 得此爻者，或遇贵人好友提携而发财，女人有生育之喜。不良者，须防疾诉忧患，或女人有不贞之事。做官的有被贬职之忧。"}, {"position": "九二", "text": "包有鱼，无咎，不利宾。", "xiang": "包有鱼，义不及宾也。", "baihua": "厨中有鱼。占得此爻，没有灾祸，但不利宴请宾客。\n\n《象辞》说：厨中有鱼，有鱼无肉，乃小康之象，不宜大肆宴请宾客。", "shaoyong": "平： 得此爻者，有财运，妇人则有怀孕之喜。做官的晋升有望。"}, {"position": "九三", "text": "臀无肤，其行次且。厉，无大咎。", "xiang": "其行次且，行未牵也。", "baihua": "臀部负伤，行走困难。占得此爻，有危险，但尚无大的灾难。\n\n《象辞》说：行走困难，因为没有人扶持。", "shaoyong": "凶： 得此爻者，多灾难。做官的会退步，或者被贬。"}, {"position": "九四", "text": "包无鱼，起凶。", "xiang": "无鱼之凶，远民也。", "baihua": "厨中无鱼。筮遇此爻，有所动作必遭凶险。\n\n《象辞》说：厨中无鱼之爻，显示其人必遭凶险。因为九四阳爻而居阴位，像君王失其权位，脱离民众。", "shaoyong": "凶： 得此爻者，多是非之扰，年老者不利于寿。做官的有损，多难。"}, {"position": "九五", "text": "以杞包瓜，含章，有陨自天。", "xiang": "九五含章，中正也；有陨自天，志不舍命也。", "baihua": "匏瓜缠着杞树生长，隐印的瓜纹很好看。忽然从头顶上方掉下一个瓜来。\n\n《象辞》说：九五爻辞讲的隐含文彩，即指九五之爻居上卦中位，像人秉含中正之德。自天上殒落，说明高尚的志行不得施行，故舍命而殉志。", "shaoyong": "平： 得此爻者，会遇到贵人提携，有意外之喜，妇人有怀孕之喜。做官的会为栋梁之才。"}, {"position": "上九", "text": "姤其角，吝，无咎。", "xiang": "姤其角，上穷吝也。", "baihua": "遭遇野兽，处于它的角锋之下，不是好兆头，但没有大的灾难。\n\n《象辞》说：遭遇野兽，处于它的角锋之下，因为上九阳爻居一卦之尽头，像人处于穷困之境地。", "shaoyong": "凶： 得此爻者，营谋艰辛，孤立无助。做官的功名大显，但好运将尽。读书人努力进取者能取得佳绩。"}]
  },
  {
    id: 45,
    name: "泽地萃",
    shortName: "萃卦",
    upper: "兑",
    lower: "坤",
    symbol: "☷\n☱",
    text: "萃。亨，王假有庙。利见大人，亨，利贞。用大牲吉。利有攸往。",
    xiangZhuan: "泽上于地，萃。",
    baihua: "通泰。王到宗庙举行祭祀。占得此卦，利于会见贵族王公，亨通，这是吉利的贞兆。用牛牲祭祀，也很吉利，并且出行吉利。\n\n《象辞》说：本卦上卦为兑，兑为泽；下卦为坤，坤为地。泽水淹地，是萃卦的卦象。君子观此卦象，以洪水横流，祸乱丛聚为戒，从而修治兵器，戒备意外的变乱。",
    duanyi: "萃卦兑上坤下，为兑宫二世卦。此卦指水在地上聚集成泽以滋润万物，造福于民。占得此卦，利于见大人，祭祀用大牲畜则吉利。",
    shaoyong: "物产丰富，聚合丰盛；得贵接引，无往不利。\n\n得此卦者，运气大好，能得到贵人的帮助，获利丰厚，无往不利。",
    chuantong: "这个卦是异卦（下坤上兑）相叠。坤为地、为顺；兑为泽、为水。泽泛滥淹没大地，人众多相互斗争，危机必四伏，务必顺天任贤，未雨绸缪，柔顺而又和悦，彼此相得益彰，安居乐业。萃，聚集、团结。",
    yaoci: [{"position": "初六", "text": "有孚不终，乃乱乃萃。若号，一握为笑。勿恤，往无咎", "xiang": "乃乱乃萃，其志乱也。", "baihua": "捕获了俘虏，却又逃跑了，引起纷乱和忧虑，大家呼喊着四处追捕。终于追回了，又高兴得嘻嘻哈哈，用不着担忧了。占得此爻，大胆前往，没有灾难。\n\n《象辞》说：混乱啊，憔悴啊，其人神志昏乱。", "shaoyong": "平： 得此爻者，会受到小人的陷害，先凶后吉，宜谨慎从事。做官的会被贬职。"}, {"position": "六二", "text": "引吉，无咎。孚乃利用禴。", "xiang": "引吉无咎，中未变也。", "baihua": "占得此爻，长时间吉利，没有灾难。占问祭祀，贞兆显示：春祭要用俘虏作人牲才好。\n\n《象辞》说：“长时间吉利，没有灾难”，因为六二阴爻居于下卦中位，象人坚守正道，绝不改变。", "shaoyong": "吉： 得此爻者，正当好运，贵人提举，营谋得利。做官的得人引荐，能升迁。"}, {"position": "六三", "text": "萃如，嗟如，无攸利。往无咎，小吝。", "xiang": "往无咎，上巽也。", "baihua": "忧愁嗟叹。占得此爻，无所利。出行则无灾难，但有小小的麻烦。\n\n《象辞》说：出行无灾难，因为六三阴爻居于九四阳爻之下，像臣下顺从君上，行为谨慎。", "shaoyong": "凶： 得此爻者，家里不安，六亲有损，老者多凶。做官的在位不得安宁，出外则艰辛。"}, {"position": "九四", "text": "大吉，无咎。", "xiang": "大吉无咎，位不当也。", "baihua": "大吉大利，没有灾难。\n\n《象辞》说：贞兆本来是大吉大利，但结果仅仅是没有灾难，因为九四阳爻而居阴位，像人才小德薄而居高位，论其官运则谓亨通，论其居官则求无灾祸而已。", "shaoyong": "平： 得此爻者，不从正道者，会有凶祸，惟大德君子，可改过得福。做官的须防他人猜忌，宜弃高就低，急流勇退为吉。"}, {"position": "九五", "text": "萃有位，无咎。匪孚，元永贞，悔亡。", "xiang": "萃有位，志未光也。", "baihua": "瘁心力于其职守，没有灾祸。不轻易责罚别人，卜问长期的吉凶，贞兆显示：没有大的悔恨。\n\n《象辞》说：瘁心力于其职守，结果仅仅是没有灾祸，因为才具驽下，不能有所建树。", "shaoyong": "平： 得此爻者，人情不合，营谋有阻。做官的不得人心，其志未光。"}, {"position": "上六", "text": "赍咨涕洟，无咎。", "xiang": "赍咨涕洟，未安上也。", "baihua": "叹息流涕，忧心忡忡，但没有灾难。\n\n《象辞》说：叹息流涕，忧心忡仲，因为上六之爻居于一卦的尽头，孤悬无据，像人虽居高位，但如履薄冰，惊恐度日。", "shaoyong": "凶： 得此爻者，事多烦扰，不能安宁，或上下无情，长幼忧愁，名利成虚。"}]
  },
  {
    id: 46,
    name: "地风升",
    shortName: "升卦",
    upper: "坤",
    lower: "巽",
    symbol: "☴\n☷",
    text: "升。元亨。用见大人，勿恤，南征吉。",
    xiangZhuan: "地中生木，升。",
    baihua: "非常亨通，有利于会见王公贵族，不用担忧。占得此爻，出征南方吉利。\n\n《象辞》说：本卦外卦为坤，坤为地；内卦为巽，巽为木。可见木植于地中，是升卦的卦象。君子观此卦象，从而遵循德义，加强修养，从细小起步，逐步培育崇高的品德。",
    duanyi: "升卦坤上巽下，为震宫四世卦。升卦的意思就是上升、长进，为出暗向明，积小成大的亨达之象。",
    shaoyong: "升腾上进，畅行其志；出暗向明，遂渐升进。\n\n得此卦者，运气升腾，诸事皆积极向上发展，谋事有成，名利双收。",
    chuantong: "这个卦是异卦（下巽上坤）相叠。坤为地、为顺；巽为木、为逊。大地生长树木，逐渐成长，日渐高大成材，喻事业步步高升，前程远大，故名“升”。",
    yaoci: [{"position": "初六", "text": "允升，大吉。", "xiang": "允升大吉，上合志也。", "baihua": "前进发展，大吉大利。\n\n《象辞》说：前进发展，大吉大利，是说尚能契合心意。", "shaoyong": "吉： 得此爻者，名利双收，营谋遂心。做官的晋升有望。"}, {"position": "九二", "text": "孚乃利用禴，无咎。", "xiang": "九二之孚，有喜也。", "baihua": "春祭宜用俘虏作为人牲，则无灾祸。\n\n《象辞》说：九二爻辞讲祭祀鬼神必以忠信，从而将有喜庆之事。", "shaoyong": "平： 得此爻者，常人有喜，病者安，谋事可成。做官的有升迁之机。"}, {"position": "九三", "text": "升虚邑。", "xiang": "升虚邑，无所疑也。", "baihua": "登临于建立在大丘之上的城邑。\n\n《象辞》说：登临于建立在大丘之上的城邑，登高望远，所见甚明，故无所疑惑。", "shaoyong": "平： 得此爻者，营谋遂意。做官的会身居要位，读书人可成名。"}, {"position": "六四", "text": "王用亨于岐山，吉，无咎。", "xiang": "王用亨于岐山，顺事也。", "baihua": "周王在岐山祭祀鬼神。筮遇此爻，吉利，并无灾祸。\n\n《象辞》说：周王在岐山祭祀鬼神，之所以吉而无灾祸，因为这是顺乎天理之事。", "shaoyong": "吉： 得此爻者，得山林之利，隐者有山林之乐。做官的会升迁，身居要职。"}, {"position": "六五", "text": "贞吉，升阶。", "xiang": "贞吉升阶，大得志也。", "baihua": "占得吉兆，所占之事将逐步发展。\n\n《象辞》说：信守正道，自然吉利，其事业必然逐步发展，说明其志愿得伸，目的达到。", "shaoyong": "吉： 得此爻者，正行好运，大愿可成。做官的会高升。"}, {"position": "上六", "text": "冥升，利于不息之贞。", "xiang": "冥升在上，消不富也。", "baihua": "深夜不眠，勤勉不息地工作则符合此吉兆。\n\n《象辞》说：上六爻辞讲深夜不眠，因为上六之爻据一卦之首，爻位孤悬，其人虽处高位，但环境不利，不过，勤于职守则可以消灾得福。", "shaoyong": "平： 得此爻者，有贪得无厌之祸。做官的会告休。"}]
  },
  {
    id: 47,
    name: "泽水困",
    shortName: "困卦",
    upper: "兑",
    lower: "坎",
    symbol: "☵\n☱",
    text: "困。亨，贞，大人吉，无咎。有言不信。",
    xiangZhuan: "泽无水，困。",
    baihua: "通泰。卜问王公贵族之事吉利，没有灾难。筮遇此爻，有罪之人无法申辩清楚。\n\n《象辞》说：本卦上卦为兑，兑为泽；下卦为坎，坎为水，水渗泽底，泽中干涸，是困卦的卦象。君子观此卦象，以处境艰难自励，穷且益坚，舍身捐命，以行其夙志。",
    duanyi: "困卦兑上坎下，为兑宫初世卦。此卦君子受困于小人，阳为阴蔽，大人则吉而无咎。所闻之言没有诚信。",
    shaoyong: "泽上无水，受困穷之；万物不生，修德静守。\n\n得此卦者，陷入困境，事事不如意，宜坚守正道，等待时机。",
    chuantong: "这个卦是异卦（下坎上兑）相叠。兑为阴为泽喻悦；坎为阳为水喻险。泽水困，陷入困境，才智难以施展，仍坚守正道，自得其乐，必可成事，摆脱困境。",
    yaoci: [{"position": "初六", "text": "臀困于株木，入于幽谷，三岁不见。", "xiang": "入于幽谷，幽不明也。", "baihua": "臀部被狱吏的刑杖打伤，被投入黑暗的牢房中，三年不见其人。\n\n《象辞》说：进入了幽深的山谷，自然幽暗不明。", "shaoyong": "凶： 得此爻者，有惊忧，或有丧服之灾。做官的会退职。"}, {"position": "九二", "text": "困于洒食，朱绂方来，利用享祀。征凶，无咎。", "xiang": "困于洒食，中有庆也。", "baihua": "酒醉未醒，穿着红色服装的蛮夷前来进犯，忧患猝临，宜急祭神求佑。至于占问出征，则有危险。其他事无大的灾祸。\n\n《象辞》说：酒醉未醒，天予命赐公卿之服，因为九二之爻居下卦中位，这是将有喜庆之事的兆头。", "shaoyong": "平： 得此爻者，得贵人提携，营谋获利，静吉动凶。做官的有晋升之机。"}, {"position": "六三", "text": "困于石，据于疾藜。入于其宫，不见其妻，凶。", "xiang": "据于疾藜，乘刚也；入于其宫，不见其妻，不祥也。", "baihua": "被石头绊倒，被蒺藜刺伤，历难归家，妻子又不见了，这是凶险之兆。\n\n《象辞》说：被石头绊倒，被蒺藜刺伤，之所以屡遇艰难，因为六三阴爻居于九二阳爻之上，像弱者攀附于强暴之人，必受其挟持威凌。回到家中，妻子又不见了，这是不祥之兆。", "shaoyong": "凶： 得此爻者，多难之时，宜守正谨慎。"}, {"position": "九四", "text": "来徐徐，困于金车，吝，有终。", "xiang": "来徐徐，志在下也。", "baihua": "其人被关押在囚车里，慢慢地走来。真不幸，但最后还是被释放。\n\n《象辞》说：行走缓慢，不求速进，志向卑微的表现。九四之爻居于九五之下，像人甘居下位，因为态度谦卑，倒能得人帮助。", "shaoyong": "凶： 得此爻者，谋事虽然不利，但终有出险之时，从商者或周转不利。做官的闲职者会被起用。"}, {"position": "九五", "text": "劓刖，困于赤绂。乃徐，有说，利用祭祀。", "xiang": "劓刖，志未得也。", "baihua": "割了鼻子，断了腿，被身着红色服装的蛮夷虏去。后来慢慢找到脱身的机会，终于逃脱回家。宜急祭神酬谢。\n\n《象辞》说：割了鼻子，断了腿，是说其人不得志，身处险境。后来慢慢地脱离了险境，因为九五之爻居上卦中位，像人立身正直，自能化险为夷。宜祭祀鬼神，因为爻象指示：祈求鬼神保佑，承受其福荫。", "shaoyong": "凶： 得此爻者，先难后易，不良者有诉刑之扰，丧服之忧。做官的先阻后顺。"}, {"position": "上六", "text": "困于葛藟，于臲卼，曰动悔。有悔，征吉。", "xiang": "困于葛藟，未当也。", "baihua": "被葛藟绊倒，被小木桩刺伤，处境如此艰难，不宜有所行动，否则悔上加悔。至于占问出征则吉利。\n\n《象辞》说：被葛藟绊倒，因为行为不得当。悔悟到动则招悔，必能谦慎行事丽逢吉利。", "shaoyong": "平： 得此爻者，防惊忧丧服，惟商人、旅行者利有攸往。做官的会有刑罚束缚之忧。"}]
  },
  {
    id: 48,
    name: "水风井",
    shortName: "井卦",
    upper: "坎",
    lower: "巽",
    symbol: "☴\n☵",
    text: "井。改邑不改井，无丧无得。往来井井。汔至，亦未繘井，羸其瓶，凶。",
    xiangZhuan: "木上有水，井。",
    baihua: "改建邑落而不改建水井，等于什么也没有干。人们往来井边汲水，水井干涸淤塞，不去加以淘洗，反而将吊水罐打破，这是凶险之象。\n\n《象辞》说：本卦下卦为巽，巽为木；上卦为坎，坎为水。水下浸而树木生长，这是井卦的卦象。君子观此卦象，取法于井水养人，从而鼓励人民勤劳而互相劝勉。",
    duanyi: "井卦坎上巽下，为震宫五世卦。井不可移动，象征静止，此卦也是提示占卦者要安身守道，不可贪求。",
    shaoyong: "静水通源，气运平静；不变所守，维持现状。\n\n得此卦者，宜修身养性，顺其自然，泰然处之，静有利，动则凶。",
    chuantong: "这个卦是异卦（下巽上坎）相叠。坎为水；巽为木。树木得水而蓬勃生长。人靠水井生活，水井由人挖掘而成。相互为养，井以水养人，经久不竭，人应取此德而勤劳自勉。",
    yaoci: [{"position": "初六", "text": "井泥不食，旧井无禽。", "xiang": "井泥不食，下也。", "baihua": "井水混浊不可食用。墤塌的陷阱已关不住野兽。\n\n《象辞》说：井水混浊不可食用，因为泥土落入其中。墤塌的陷阱已关不住野兽，是说人们已将这陷阱舍弃不用了。", "shaoyong": "凶： 得此爻者，谋事有阻。做官的会退居闲职，求名者不遂。"}, {"position": "九二", "text": "井谷射鲋，瓮敝漏。", "xiang": "井谷射鲋，无与也。", "baihua": "在井口张弓射井中小鱼。瓮瓶又破又漏。\n\n《象辞》说：在井口张弓射井中小鱼，如此谋食求生，可见其人无依无靠。", "shaoyong": "凶： 得此爻者，宜谨守以避祸。做官的宜退以自保。"}, {"position": "九三", "text": "井渫不食，为我心恻。可用汲，王明，并受其福。", "xiang": "井渫不食，行恻也。", "baihua": "君上看见井水污浊不能食用，为我们感刭伤心。淘洗干净，就可汲饮。君上英明，众人都获得他们的好处。\n\n《象辞》说：井水污浊不能食用，这是触景生情的感叹。盼求君王英明，是企望获得好处。", "shaoyong": "平： 得此爻者，安分守己为吉，不良者或有灾。做官的难逢明主，需另觅良机。"}, {"position": "六四", "text": "井甃，无咎。", "xiang": "井甃无咎，修井也。", "baihua": "用砖石垒筑井壁，进行顺利。\n\n《象辞》说：用砖石垒筑井壁，进行顺利，这是讲修井之事。", "shaoyong": "平： 得此爻者，宜安分守己，或有迁居之喜。做官清廉者，修身立命，可望上进。"}, {"position": "九五", "text": "井冽，寒泉食。", "xiang": "寒泉之食，中正也。", "baihua": "水洁泉寒，清凉可口，可以食用。\n\n《象辞》说：九五爻辞讲水洁泉寒，清凉可口，因为九五之爻居上卦中位，象征人得中正之道。", "shaoyong": "吉： 得此爻者，营谋遂意。做官的品行端正，会得到上司的赞赏。"}, {"position": "上六", "text": "井收勿幕，有孚元吉。", "xiang": "元吉在上，大成也。", "baihua": "陷阱下宽上窄，十分隐蔽，甚至可以不加伪装。果然捕获了野兽，大吉大利。\n\n《象辞》说：上六爻辞讲大吉大利，因为上六之爻处一卦之首位，说明其人爵位高登，大有成就。", "shaoyong": "吉： 得此爻者，谋事顺利，财用充足。做官的功高德厚，能得升迁。"}]
  },
  {
    id: 49,
    name: "泽火革",
    shortName: "革卦",
    upper: "兑",
    lower: "离",
    symbol: "☲\n☱",
    text: "革。己日乃孚。元亨利贞。悔亡。",
    xiangZhuan: "泽中有火，革。",
    baihua: "祭祀之日用俘虏作人牲，亨通，吉利的卜问。没有悔恨。\n\n《象辞》说：本卦外卦为兑，兑为泽；内卦为离，离为火。内蒸外煏，水涸草枯，如同水泽之中，大火燃烧，这是革卦的卦象。君子观此卦象，了解到泽水涨落，草木枯荣的周期变化，从而修治历法，明确时令。",
    duanyi: "革卦兑上离下，为坎宫四世卦。革就是需要变革，提醒占筮者需要变革才会更进一步。",
    shaoyong: "事多变动，坚守正道；顺天应人，实施变革。\n\n得此卦者，凡事均在变动之中，宜去旧立新，以应革新之象，则会吉祥。",
    chuantong: "这个卦是异卦（下离上兑）相叠。离为火、兑为泽，泽内有水。水在上而下浇，火在下而上升。火旺水干，水大火熄。二者相生亦相克，必然出现变革。变革是宇宙的基本规律。",
    yaoci: [{"position": "初九", "text": "巩用黄牛之革。", "xiang": "巩用黄牛，不可以有为也。", "baihua": "用黄牛的皮革束紧加固(战车)。\n\n《象辞》说：用黄牛的皮革束紧加固，说明其人被紧紧束缚不能有作为。", "shaoyong": "平： 得此爻者，宜谨守常规，不可存非分之想。做官的不宜进取，切不可怀出位之念。"}, {"position": "六二", "text": "己日乃革之。征吉，无咎。", "xiang": "己日革之，行有嘉也。", "baihua": "祭祀的日期要改变。随之要重新卜问征战的日期，结果卜得吉兆，没有灾难。\n\n《象辞》说：祭祀的日期要改变，大概是因为将有喜庆之事。", "shaoyong": "吉： 得此爻者，多喜庆之事，做官的会升迁。"}, {"position": "九三", "text": "征凶，贞厉。革言三就，有孚。", "xiang": "革言三就，又何之矣。", "baihua": "出征，吃了败仗，卜问得凶兆。但是，只要振奋精神，整顿装备，重新开战，则能转败为胜，生擒强敌。\n\n《象辞》说：犯人屡次推翻供辞，只得反复进行审讯，这说明抵赖无用，只能招出实情。", "shaoyong": "凶： 得此爻者，多事之时，谨慎而行。做官的有躁动失政之忧。"}, {"position": "九四", "text": "悔亡，有孚，改命，吉。", "xiang": "改命之吉，信志也。", "baihua": "没有悔恨。至于占问战争，则小有战果，如果改帅易将，则将大吉。\n\n《象辞》说：九四爻辞讲改帅易将之所以吉利，因为这样能使有才德的人施展抱负。", "shaoyong": "平： 得此爻者，会有转变，有收获。做官的会有升迁之机。"}, {"position": "九五", "text": "大人虎变，未占有孚。", "xiang": "大人虎变，其文炳也。", "baihua": "王公大人赫然斯怒，化柔弱为威猛，不用卜占，即知将大获胜仗。\n\n《象辞》说：王公赫然斯怒，威猛如虎，说明其人仪表威严，光采照人。", "shaoyong": "吉： 得此爻者，时运转好，多吉利之事。做官的晋升有望。"}, {"position": "上六", "text": "君子豹变，小人革面。征凶，居贞吉。", "xiang": "君子豹变，其文蔚也。", "baihua": "君子精神振奋，但基层官兵一反常态。筮遇此爻，占问征伐，则凶险。卜问居处则吉利。\n\n《象辞》说：君子精神振奋，说明其仪态清朗雍容。小人洗心革面，说明小人去恶从善，服从君上。", "shaoyong": "平： 得此爻者，安分守己则是非不扰。做官的进取者会晋升，离退休者会功成身退。"}]
  },
  {
    id: 50,
    name: "火风鼎",
    shortName: "鼎卦",
    upper: "离",
    lower: "巽",
    symbol: "☴\n☲",
    text: "鼎。元吉，亨。",
    xiangZhuan: "木上有火，鼎。",
    baihua: "大吉大利，亨通。\n\n《象辞》说：本卦下卦为巽，巽为木；上卦为离，离为火。可见木上有火，以鼎烹物，这是《鼎》卦的卦象。君子观此卦象，取法于鼎足三分，正立不倚，从而持正守位，为君上所倚重，不负使命。",
    duanyi: "鼎卦离上巽下，为离宫二世卦。鼎为鼎定、和美之意，多主吉，但对诉讼、求官不利。",
    shaoyong: "因败致功，因人成事；万事通达，平步青云。\n\n得此卦者，时运正佳，能得到朋友的帮助，取得不错的成就。与人合伙共事更佳。",
    chuantong: "这个卦是异卦（下巽上离）相叠。燃木煮食，化生为熟，除旧布新的意思。鼎为重宝大器，三足稳重之象。煮食，喻食物充足，不再有困难和困扰。在此基础上宜变革，发展事业。",
    yaoci: [{"position": "初六", "text": "鼎颠趾，利出否。得妾以其子，无咎。", "xiang": "鼎颠趾，未悖也。", "baihua": "将鼎倾覆，鼎足向上，筮遇此爻，利于清除恶人。以无子而纳妾。因纳妾而得子，没有灾祸。\n\n《象辞》说：将鼎倾覆，这不是悖乱之举。清除朝中恶人，这是听从了上面的旨意。", "shaoyong": "平： 得此爻者，因人成事，多喜事，或结婚，或生子，忧者喜，贱者贵。做官的会因功得晋升。\n\n台湾国学大儒傅佩荣解\n\n时运： 因祸得福，荣封之喜。\n\n财运： 小损大利，以商为家。\n\n家宅： 修整有吉；妾生贵子。\n\n身体： 腹下泻症，即可痊愈。\n\n初六变卦\n\n\n\n初六爻动变得 周易第14卦：火天大有 。这个卦是异卦（下乾上离）相叠。上卦为离，为火；下卦为乾，为天。火在天上，普照万物，万民归顺，顺天依时，大有所成。"}, {"position": "九二", "text": "鼎有实，我仇有疾，不我能即，吉。", "xiang": "鼎有实，慎所之也。", "baihua": "鼎中有食物。筮遇此爻，家里有饭吃，仇家有疾病，再没有什么东西困扰我，吉利。\n\n《象辞》说：家里有饭吃，家境优裕，犹宜重其身家，慎其出处。仇家有疾病，我可以安亨清福，终于没有灾祸。", "shaoyong": "吉： 得此爻者，虽有收获，但须防忧。做官的秉公执政，须防小人的谗言之扰。"}, {"position": "九三", "text": "鼎耳革，其行塞，雉膏不食。方雨，亏悔，终吉。", "xiang": "鼎耳革，失其义也。", "baihua": "鼎耳脱落了。筮遇此爻，打猎无所获。野味莫吃光，老天要下雨，不知何日能出猎，坐吃山空，食物将匮乏，节约渡难关，终于得吉利。\n\n《象辞》说：鼎耳脱落，意在说其人行动失宜。", "shaoyong": "平： 得此爻者，先难后易，老者多福，年轻人多不如意。做官的会遇到阻力，但最终的结果会好。\n\n台湾国学大儒傅佩荣解\n\n时运： 妄意改变，难免有悔。\n\n财运： 目前滞销，须待三年。\n\n家宅： 须防突变；可能悔婚。\n\n身体： 小心失聪。\n\n九三变卦\n\n\n\n九三爻动变得 周易第64卦：火水未济 。这个卦是异卦（下坎上离）相叠。离为火，坎为水。火上水下，火势压倒水势，救火大功未成，故称未济。《周易》以乾坤二卦为始，以既济、未济二卦为终，充分反映了变化发展的思想。"}, {"position": "九四", "text": "鼎折足，覆公餗，其形渥，凶。", "xiang": "覆公餗，信如何也。", "baihua": "鼎足太轻，不堪重负，以致折断，倾覆王公的珍馐美味，弄得汁液满地，形容狼藉。这是凶险之兆。\n\n《象辞》说：倾覆了王公的珍馐美味，这是喻指其人德薄而位尊，力小而任重，以致败坏军国大事，其结果如何呢？", "shaoyong": "凶： 得此爻者，多灾之时，或生足疾。做官的有被贬职之忧。"}, {"position": "六五", "text": "鼎黄耳金铉，利贞。", "xiang": "鼎黄耳，中以为实也。", "baihua": "豪华之鼎，上面装配有铜耳、铜铉。筮遇此爻吉利。\n\n《象辞》说：豪华之鼎，上面装配着铜耳、铜铉，这样的食鼎，理应盛着佳霉美味。", "shaoyong": "吉： 得此爻者，时运不错，多获利。做官的多吉兆，多升迁。"}, {"position": "上九", "text": "鼎玉铉，大吉，无不利。", "xiang": "玉铉在上，刚柔节也。", "baihua": "金属之鼎配以玉石之铉。占得此爻，大吉，无所不利。\n\n《象辞》说：上九爻辞讲玉石之铉配在金属之鼎上面，表明刚柔相接，上下安份，没有凌乱侵夺的现象。", "shaoyong": "吉： 得此爻者，安稳利达，谋求遂意。做官的闲职者复职，离退者功成身退。"}]
  },
  {
    id: 51,
    name: "震为雷",
    shortName: "震卦",
    upper: "震",
    lower: "震",
    symbol: "☳\n☳",
    text: "震。亨。震来虩虩，笑言哑哑。震惊百里，不丧匕鬯。",
    xiangZhuan: "洊雷，震。",
    baihua: "临祭之时，雷声传来，有的人吓得浑身发抖，片刻之后，才能谈笑如常。巨雷猝响，震惊百里，有的人却神态自若，手里拿着酒勺子，连一滴酒都没有洒出来。\n\n《象辞》说：本卦上下卦都为震，震为雷。可见巨雷连击，是震卦的卦象。君子观此卦象，从而戒惧恐惧，修省其身。",
    duanyi: "震卦震上震下，为震宫本位卦。震即雷，空闻其响，不见其形。主求谋难遂，官爵难成。",
    shaoyong: "重雷发响，奋发图强；先难后易，先苦后甜。\n\n得此卦者，奋发振作，大可有为，但表面风光，内恐有难，宜谨言慎行，以免损失。",
    chuantong: "这个卦是同卦（下震上震）相叠。震为雷，两震相叠，反响巨大，可消除沉闷之气，亨通畅达。平日应居安思危，怀恐惧心理，不敢有所怠慢，遇到突发事变，也能安然自若，谈笑如常。",
    yaoci: [{"position": "初九", "text": "震来虩虩，后笑言哑哑，吉。", "xiang": "震来虩虩，恐致福也。", "baihua": "雷声传来，吓得浑身发抖，后来听到雷声，仍谈笑如常，吉利。\n\n《象辞》说：雷声传来，吓得浑身发抖，是因为相信敬畏重大的天象可以免罪得福。后来听到雷声仍能谈笑如常，是说后来对这类事情有了些经验。", "shaoyong": "吉： 得此爻者，好运到来，先惊后喜。"}, {"position": "六二", "text": "震来厉，亿丧贝。跻于九陵，勿逐，七日得。", "xiang": "震来厉，乘刚也。", "baihua": "雷电交加，十分危险，惊慌之中丢失了钱币，翻山越蛉，走了很远的路程去寻找也没有找到。筮者告诉他：“不必追寻了，七八日内，这损失可得补偿。”\n\n《象辞》说：雷电交加之时，翻越九重山，爻象显示其人触犯雷电，处境危险。", "shaoyong": "凶： 得此爻者，多难之时，或有争诉，小心为妙。做官的有遭奸邪之辈陷害之忧。"}, {"position": "六三", "text": "震苏苏，震行无眚。", "xiang": "震苏苏，位不当也。", "baihua": "出门时遇到电闪雷鸣，感到疑惧不安。继续前进，不会有灾祸。\n\n《象辞》说：出门时遇到电闪雷鸣，感到疑惧不安，因为六三阴爻而居阳位，像人处境不利。", "shaoyong": "凶： 得此爻者，多忧愁，多灾难，宜谨慎，可免祸。做官的不宜进取。"}, {"position": "九四", "text": "震遂泥。", "xiang": "震遂泥，未光也。", "baihua": "雷电下击，接触到地面。\n\n《象辞》说：其人猝闻惊雷，吓得坠入泥中，说明其人见识不广，胆量不大。", "shaoyong": "凶： 得此爻者，一筹莫展，前进有阻。做官的有被贬职之危。"}, {"position": "六五", "text": "震往来厉，亿无丧，有事。", "xiang": "震往来厉，危行也。", "baihua": "巨雷轰鸣，危险在前。只要小心谨慎，不至于酿成灾祸，亦无损于事。\n\n《象辞》说：巨雷轰鸣，危险在前，喻指人的行动将有危险。但是其事合符义理，故能没有大的损失。", "shaoyong": "凶： 得此爻者，不吉之时，或有手足受损之忧。做官的守常者无忧。"}, {"position": "上六", "text": "震索索，视矍矍，征凶。震不于其躬，于其邻，无咎。婚媾有言。", "xiang": "震索索，未得中也。", "baihua": "雷电交加，其人行动谨慎，警戒四顾，因为行路艰难，危险四伏。但是雷电不会击在他身上，而是落在邻人的头上。因为他本人没有什么过错，而其他邻人却犯有罪责。\n\n《象辞》说：雷电交加，行动谨慎，因为内心虚空，精神紧张。虽然凶险但毕竟没有灾祸，因为对于邻人的遭遇有所警戒，从而能远恶近善。", "shaoyong": "凶： 得此爻者，须谨防意外，或夫妻有刑克，亲邻遭难。做官的要谨防被贬职之忧。"}]
  },
  {
    id: 52,
    name: "艮为山",
    shortName: "艮卦",
    upper: "艮",
    lower: "艮",
    symbol: "☶\n☶",
    text: "艮。艮其背，不获其身。行其庭，不见其人。无咎。",
    xiangZhuan: "兼山，艮。",
    baihua: "卸掉责任，挂笏隐退，朝列之中已看不到他的身影，在他的庭院中寻找，也没有找到。其人远走高飞，自无灾祸。\n\n《象辞》说：本卦为两艮卦相重，艮为山，可见艮卦的卦象是高山重立，渊深稳重。君子观此卦象，以此为戒，谋不踰位，明哲保身。",
    duanyi: "艮卦艮上艮下，为艮宫本位卦。艮为停止的意思，为钱财散失之象，需谨慎提防。",
    shaoyong: "停留阻止，无可再进；随份勿贪，不可强求。\n\n得此卦者，前路受阻，不宜妄进，宜守待机。",
    chuantong: "这个卦是同卦（下艮上艮）相叠。艮为山，二山相重，喻静止。它和震卦相反。高潮过后，必然出现低潮，进入事物的相对静止阶段。静止如山，宜止则止，宜行则行。行止即动和静，都不可失机，应恰到好处，动静得宜，适可而止。",
    yaoci: [{"position": "初六", "text": "艮其趾，无咎。利永贞。", "xiang": "艮其趾，未失正也。", "baihua": "歇脚养息，不要轻举妄动，自然无灾难，这是长期吉利的贞兆。\n\n《象辞》说：歇脚养息，不要轻举妄动，远离不义，不失正道，自然永远吉利。", "shaoyong": "平： 得此爻者，宜守本份，不要纵欲。做官的保守己职者无失。"}, {"position": "六二", "text": "艮其腓，不拯其随，其心不快。", "xiang": "不拯其随，未退听也。", "baihua": "停立不行，但腿部肌肉还是负伤。心里很不愉快。\n\n《象辞》说：腿部肌肉还是负伤，因为其人固执己见，没有退回来，听取别人的意见。", "shaoyong": "凶： 得此爻者，运势受阻，或奔波在外，多劳苦；或有足疾。做官的得不到他人的帮助，不宜上进。"}, {"position": "九三", "text": "艮其限，列其夤，厉薰心。", "xiang": "艮其限，危薰心也。", "baihua": "卸掉重担，保护腰部，但是胁间肉却已裂开了，引退不及时，则罹凶险。这是由于为名利所惑，不能迅速引退卸职所招致的灾祸。\n\n《象辞》说：“卸掉重担，保护腰部，胁间肉却已裂开了，引退不及时，则罹凶险”，危险是由为名利迷惑所致。", "shaoyong": "凶： 得此爻者，不顺之时，危难不安。"}, {"position": "六四", "text": "艮其身，无咎。", "xiang": "艮其身，止诸躬也。", "baihua": "引退保身，没有灾祸。\n\n《象辞》说：引退保身，是说其人注意力全部集中在自身的安危上，所以不会招惹灾难。", "shaoyong": "平： 得此爻者，宜安分守常，不可有非分之想。"}, {"position": "六五", "text": "艮其辅，言有序，悔亡。", "xiang": "艮其辅，以中正也。", "baihua": "闭口少言，讲话有分寸，自然没有悔恨。\n\n《象辞》说：闭口少言，讲话有分寸，没有悔恨，因为六五之爻居上卦中位，像人谨守中正之道。", "shaoyong": "平： 得此爻者，正人君子，人情和合，谋望遂意。做官的会居要职。"}, {"position": "上九", "text": "敦艮，吉。", "xiang": "敦艮之吉，以厚终也。", "baihua": "注意保护自己的脑袋，首级不失，自然吉利。\n\n《象辞》说：爻辞讲以忠厚为归宿之所以吉利，因为上九之爻为一卦之终爻，像人秉守忠厚，必得善终。", "shaoyong": "吉： 得此爻者，多福多利，但易防不吉之事。做官的会升迁，读书人会取得佳绩。"}]
  },
  {
    id: 53,
    name: "风山渐",
    shortName: "渐卦",
    upper: "巽",
    lower: "艮",
    symbol: "☶\n☴",
    text: "渐。女归吉，利贞。",
    xiangZhuan: "山上有木，渐。",
    baihua: "女大当嫁，这是好事。这是吉利的贞卜。\n\n《象辞》说：本卦下卦为艮，艮为山；上卦为巽，巽为木，木植山上，不断生长，是渐卦的卦象。君子观此卦象，取法于山之育林，从而以贤德自居，担负起改善风俗的社会责任。",
    duanyi: "渐卦巽上艮下，为艮宫归魂卦。渐为渐进，筮遇此卦，女嫁则吉，举事有利。",
    shaoyong: "循序渐进，积少成多；渐进即利，性急即败。\n\n得此卦者，逐步开运，凡事宜循序渐进，则谋事可成，不宜急进，性急则败。",
    chuantong: "这个卦是异卦（下艮上巽）相叠。艮为山，巽为木。山上有木，逐渐成长，山也随着增高。这是逐渐进步的过程，所以称渐，渐即进，渐渐前进而不急速。",
    yaoci: [{"position": "初六", "text": "鸿渐于干，小子厉。有言，无咎。", "xiang": "小子之厉，义无咎也。", "baihua": "鸿雁走进了山涧。筮遇此爻，警惕小孩顽皮，遭遇危险，应该加以谴责，则没有灾难。\n\n《象辞》说：小孩顽皮遭遇危险，因为有家长呵责制止，理应不会出事故。", "shaoyong": "凶： 得此爻者，运气不佳，谋为不利。"}, {"position": "六二", "text": "鸿渐于磐，饮食衎衎，吉。", "xiang": "饮食衎衎，不素饱也。", "baihua": "鸿雁走上水边高地，饱饮饱食，自得喜乐。筮遇此爻，吉利。\n\n《象辞》说：饱饮饱食，自得喜乐，喻指其人，自食其力，从不白吃白喝。", "shaoyong": "吉： 得此爻者，无往不利，随处皆安。"}, {"position": "九三", "text": "鸿渐于陆，夫征不复，妇孕不育，凶。利御寇。", "xiang": "夫征不复，离群丑也。", "baihua": "鸿雁走到旱地上。筮遇此爻，丈夫出征可能不再回返，妇女怀孕可能流产，这是凶险之兆。但有利于抵御敌寇。\n\n《象辞》说：丈夫出征不再回返，说明其人掉队遇险。妇女怀孕而流产，说明其人失其保胎之道。利于抵御敌寇，说明国人能够同心同德，保家卫国。", "shaoyong": "凶： 得此爻者，多惊扰，人情不睦，盗贼侵害。做官的上进有阻力，有被贬之忧。"}, {"position": "六四", "text": "鸿渐于木，或得其桷，无咎。", "xiang": "或得其桷，顺以巽也。", "baihua": "鸿雁飞到树木上，有的停息在河边堆放的桷木上。筮遇此爻，没有灾难。\n\n《象辞》说：有的鸿雁停息在河边堆放的桷木上之所以没有灾难，因为六四阴爻居于九五阳爻之下，像人有驯服而又谦逊之德。", "shaoyong": "平： 得此爻者，利于修造，自给自足。做官的须随遇而安，升迁无定。"}, {"position": "九五", "text": "鸿渐于陵，妇三岁不孕，终莫之胜，吉。", "xiang": "终莫之胜，吉，得所愿也。", "baihua": "鸿雁走到山陵上。筮遇此爻，妻子多年不能怀孕，但始终不会被人取代，吉利。\n\n《象辞》说：始终没有被人取代，吉利，妻子实现了与其丈夫和谐白头的愿望。", "shaoyong": "吉： 得此爻者，先难后易，做官的多招诽谤，先暗后明。"}, {"position": "上九", "text": "鸿渐于陆，其羽可用为仪，吉。", "xiang": "其羽可用为仪，吉，不可乱也。", "baihua": "鸿雁走到山头上，它的羽毛可用来编织舞具。这是吉利之兆。\n\n《象辞》说：鸿雁的羽毛可用来编织舞具，这是吉利之兆，编织舞具的羽毛应该纯而不杂，像人心志不乱。", "shaoyong": "吉： 得此爻者，得人荐举，谋望有成，祸患不侵，多福多利。做官的大运来到，会得到重用。读书人会取得好成绩。"}]
  },
  {
    id: 54,
    name: "雷泽归妹",
    shortName: "归妹卦",
    upper: "震",
    lower: "兑",
    symbol: "☱\n☳",
    text: "归妹。征凶，无攸利。",
    xiangZhuan: "泽上有雷，归妹。",
    baihua: "筮遇此爻，出征凶险。无所利。\n\n《象辞》说：归妹之卦，下卦为兑，兑为泽；上卦为震，震为雷。可见泽上雷鸣，雷鸣水动，用以喻男女心动相爱而成眷属。这是归妹卦的卦象。君子观此卦象，从而在长期的婚姻生活中，体察到婚姻的成功与失败。",
    duanyi: "归妹卦震上兑下，为兑宫归魂卦。占得此卦，天地不交，闭塞不通，有殃有咎，无始无终，所作不顺，百事不利。",
    shaoyong: "违反常理，其道将穷；明察事理，止绝妄念。\n\n得此卦者，困难之时，做事有违常理，灾祸不断。宜明察事理，修身养性，断绝妄念。",
    chuantong: "这个卦是异卦（下兑上震）相叠。震为动、为长男；兑为悦、为少女。以少女从长男，产生爱慕之情，有婚姻之动，有嫁女之象，故称归妹。",
    yaoci: [{"position": "初九", "text": "归妹以娣，跛能履，征吉。", "xiang": "归妹以娣，以恒也。", "baihua": "嫁女而将其妹妹一同陪嫁。跛脚而能行走。筮遇此爻，出行吉利。\n\n《象辞》说：嫁女而将其妹妹一同陪嫁，是说姊妹共嫁一夫，这是古代贵族婚嫁的常规。跛脚而能行走，出行吉利，因为跛者获得别人的帮助。", "shaoyong": "吉： 得此爻者，有小德，谋望顺遂。做官的或有政绩。"}, {"position": "九二", "text": "眇能视，利幽人之贞。", "xiang": "利幽人之贞，未变常也。", "baihua": "眼睛瞎了而能看得见。这是利于囚徒的贞卜。\n\n《象辞》说：这是利于囚徒的贞卜，因为身处囚笼尚不失正道，故能重见光明。", "shaoyong": "平： 得此爻者，不宜进取，守旧者则祸害不生。"}, {"position": "六三", "text": "归妹以须，反归以娣。", "xiang": "归妹以须，未当也。", "baihua": "嫁女而用其姊陪嫁，随后又与其妹妹返归父母家。\n\n《象辞》说：嫁女而用其姊陪嫁，这件事不妥当。", "shaoyong": "凶： 得此爻者，进退无常，劳役悲苦。做官的有被降职之忧。"}, {"position": "九四", "text": "归妹愆期，迟归有时。", "xiang": "愆期之志，有待而行也。", "baihua": "出嫁时超过了婚龄，迟迟不嫁是因为有所等待。\n\n《象辞》说：超龄而不嫁，因为她决意找到合意的郎君。", "shaoyong": "平： 得此爻者，不是佳期，须待时运。"}, {"position": "六五", "text": "帝乙归妹，其君之袂，不如其娣之袂良。月几望，吉。", "xiang": "帝乙归妹，不如其娣之袂良也。", "baihua": "帝乙嫁女于周文王，以其次女陪嫁。论嫁妆姊的不如妹的好。良辰择在某月十四日，吉利。\n\n《象辞》说：帝乙嫁女于周文王，姊的嫁妆不如妹的好。六五之爻居上卦中位，像女嫁夫家处于尊贵之位。", "shaoyong": "吉： 得此爻者，正值好运，或成婚，或得财。做官的会受到重用，身居要职。"}, {"position": "上六", "text": "女承筐无实，士刲羊无血，无攸利。", "xiang": "上六无实，承虚筐也。", "baihua": "献祭之时，新娘捧着盛祭品的筐具，但筐中无物；新郎以刀刺羊，但羊不流血。此不祥之兆，无所利。\n\n《象辞》说：上六之爻居一卦之尽头，孤悬无所依赖，正宜其捧着空空的筐具。", "shaoyong": "凶： 得此爻者，事多不顺，营谋皆空。做官的居虚位而无实禄。"}]
  },
  {
    id: 55,
    name: "雷火丰",
    shortName: "丰卦",
    upper: "震",
    lower: "离",
    symbol: "☲\n☳",
    text: "丰。亨。王假之，勿忧，宜日中。",
    xiangZhuan: "雷电皆至，丰。",
    baihua: "举行祭祀，君王将亲临宗庙。不要担心，最佳时刻当在正午时分。\n\n《象辞》说：本卦上卦为震，震为雷；下卦为离，离为电。电闪雷鸣，是上天垂示的重大天象，这也是丰卦的卦象。君子观此卦象，有感于电光雷鸣的精明和威严，从而裁断讼狱，施行刑罚。",
    duanyi: "丰卦震上离下，为坎宫五世卦。丰即为盛大，本是吉兆，但盛极必衰，丰盛中也藏着隐忧，需小心谨慎。",
    shaoyong: "盛大丰满，进财获利；谋望克遂，必有喜庆。\n\n得此卦者，运势正强，谋事可成，名利双收。但不宜过贪，要知足常乐，谨防乐极生悲，损财甚至火险。",
    chuantong: "这个卦是异卦（下离上震）相叠，电闪雷鸣，成就巨大，喻达到顶峰，如日中天。告戒：务必注意事物向相反方面发展，盛衰无常，不可不警惕。",
    yaoci: [{"position": "初九", "text": "遇其配主，虽旬无咎；往有尚。", "xiang": "虽旬无咎，过旬灾也。", "baihua": "旅途之中受到一位女主人的接待，与这位寡居的女人结成夫妻。占卜结果显示：不会遭人议论，而且能得到人们的赞同。\n\n《象辞》说：十日之内没有灾难，意思是超过一旬就有灾了。", "shaoyong": "平： 得此爻者，得贵人提拔，谋望有成，不良者有大过，必招灾殃。做官的会遇到明主，得以晋升。"}, {"position": "六二", "text": "丰其蔀，日中见斗。往得疑疾。有孚发若，吉。", "xiang": "有孚发若，信以发志也。", "baihua": "将小席拼缀起来，躺下休息。正午时分，有人说看见北斗星。看来旅伴之中有人精神错乱。对他加以刺激，或许可以使他清醒。\n\n《象辞》说：存心诚信，一言一行都能表现出来，因为这是坦白直率地表达了自己的心愿。", "shaoyong": "吉： 得此爻者，有久困发财之美，有讼者不辩自明，有病者会愈。做官的忠言多阻于邪议，先失后得。"}, {"position": "九三", "text": "丰其沛，日中见昧。折其右肱，无咎。", "xiang": "丰其沛，不可大事也。", "baihua": "将铺草加厚，躺下休息。正午时分，此人又说看见鬼魅。将他的右臂折断。经此一吓，或许他能清静。\n\n《象辞》说：将铺草加厚，这起不了什么大的作用。将其右臂折断，那他就终身残废了。", "shaoyong": "平： 得此爻者，营谋难遂，或明而受蔽，争诉日起，或手足有疾，难于做事。做官的有告休之兆。\n\n台湾国学大儒傅佩荣解\n\n时运： 气运颠倒，须防灾难。\n\n财运： 涨跌难测，颇有损耗。\n\n家宅： 只可暂居。\n\n身体： 右臂受伤。\n\n九三变卦\n\n\n\n九三爻动变得 周易第51卦：震为雷 。这个卦是同卦（下震上震）相叠。震为雷，两震相叠，反响巨大，可消除沉闷之气，亨通畅达。平日应居安思危，怀恐惧心理，不敢有所怠慢，遇到突发事变，也能安然自若，谈笑如常。"}, {"position": "九四", "text": "丰其蔀，日中见斗。遇其夷主，吉。", "xiang": "丰其蔀，位不当也。", "baihua": "将小席拼缀起来，躺下休息。正午时分，此人还在说看见北斗星，看来还未恢复正常。幸好遇着了他的老店主，把他托付给老店主，这一下可清静平安了。\n\n《象辞》说：将小席拼缀起来，随地休息，是所处不得当，正如九四阳爻而处于阴位一样。正午时分看见北斗，也许天空迷暗不明的缘故。遇着他的老店主，这是吉利之行。", "shaoyong": "平： 得此爻者，明而受蔽，得人解释而吉。做官的受到领导和同僚的猜忌，位不安。\n\n台湾国学大儒傅佩荣解\n\n时运： 际遇不佳，由暗向明。\n\n财运： 走出暗昧，找到买主。\n\n家宅： 成败在人；巧遇良缘。\n\n身体： 眼疾待良医。\n\n九四变卦\n\n\n\n九四爻动变得 周易第36卦：地火明夷 。这个卦是异卦（下离上坤）相叠。离为明，坤为顺；离为日；坤为地。日没入地，光明受损，前途不明，环境困难，宜遵时养晦，坚守正道，外愚内慧，韬光养晦。"}, {"position": "六五", "text": "来章，有庆誉，吉。", "xiang": "六五之吉，有庆也。", "baihua": "赚得美玉，大家都庆贺夸奖他。这是吉利之兆。\n\n《象辞》说：六五爻辞所讲的吉利，是因为有吉庆之事。", "shaoyong": "吉： 得此爻者，会得好人提举，谋望称意。读书人会取得佳绩。\n\n台湾国学大儒傅佩荣解\n\n时运： 实至名归，自然吉祥。\n\n财运： 经商有成，利名并至。\n\n家宅： 名门正户；天作之合。\n\n身体： 名医治之。\n\n六五变卦\n\n\n\n六五爻动变得 周易第49卦：泽火革 。这个卦是异卦（下离上兑）相叠。离为火、兑为泽，泽内有水。水在上而下浇，火在下而上升。火旺水干，水大火熄。二者相生亦相克，必然出现变革。变革是宇宙的基本规律。"}, {"position": "上六", "text": "丰其屋，蔀其家，窥其户，阒其无人，三岁不见，凶。", "xiang": "丰其屋，天际翔也。", "baihua": "房子空荡荡的，屋顶上散乱盖着草席，从门缝里探视，寂无一人。看样子这里多年未住人了。这是不祥之兆。\n\n《象辞》说：增修扩建房屋，看来此人如鸟飞蓝天，志得意满，发财不小。从门缝里探视，寂无一人，看来财多害身，横遭灾祸，他逃生去了。", "shaoyong": "凶： 得此爻者，骨肉相残，离祖成家，难免口舌之争。做官的位高者有危。"}]
  },
  {
    id: 56,
    name: "火山旅",
    shortName: "旅卦",
    upper: "离",
    lower: "艮",
    symbol: "☶\n☲",
    text: "旅。小亨，旅贞吉。",
    xiangZhuan: "山上有火，旅。",
    baihua: "稍见亨通。贞卜旅行，吉利。\n\n《象辞》说：本卦上卦为离，离为火；下卦为艮，艮为山。山上有火，洞照幽隐，这是旅卦的卦象。君子观此卦象，从而明察刑狱，慎重判决，既不敢滥施刑罚，也不敢延宕滞留。",
    duanyi: "旅卦离上艮下，为离宫初世卦。旅为做客、旅游之意，先主乐而后悲啼。\n\n北宋易学家邵雍解\n\n旅途穷困，飘摇不定；小望可成，宏愿难求。\n\n得此卦者，事多变动，如在异乡，小事可成，大事难成，宜谨守常规。",
    shaoyong: "凶： 得此爻者，运气不佳，须防祸难。做官的有才但不能受到上司的重用。",
    chuantong: "这个卦是异卦（下艮上离）相叠。此卦与丰卦相反，互为“综卦”。山中燃火，烧而不止，火势不停地向前蔓延，如同途中行人，急于赶路。因而称旅卦。",
    yaoci: [{"position": "初六", "text": "旅琐琐，斯其所取灾。", "xiang": "旅琐琐，志穷灾也。", "baihua": "旅人三心二意，进退犹豫，最后还是离开住所，结果自遭灾祸。\n\n《象辞》说：旅人三心二意，说明其人四处碰壁，精神疲惫。", "shaoyong": "凶： 得此爻者，运气不佳，须防祸难。做官的有才但不能受到上司的重用。"}, {"position": "六二", "text": "旅即次，怀其资，得童仆，贞。", "xiang": "得童仆贞，终无尤也。", "baihua": "旅人来到市场，带着钱财，买来一男仆，卜问得吉兆。\n\n《象辞》说：买一男仆，卜问得吉兆，看来这笔买卖没有问题。", "shaoyong": "吉： 得此爻者，运气转好，营谋有成。做官的显耀。"}, {"position": "九三", "text": "旅焚其次，丧其童仆，贞厉。", "xiang": "旅焚其次，亦以伤矣。", "baihua": "旅人来到着火的市场上，新买的男仆乘乱跑掉。卜问得险兆。\n\n《象辞》说：旅人来到着火的市场，岂不遭受损失。因为旅人带着男仆同往，男仆乘乱跑掉是很自然的。", "shaoyong": "凶： 得此爻者，运势转坏，多灾多难。做官的有离职之忧。"}, {"position": "九四", "text": "旅于处，得其资斧，我心不快。", "xiang": "旅于处，未得位也。", "baihua": "旅人回到客居之处，因为赚了不少钱，心中不踏实。\n\n《象辞》说：旅人回到客居之处，这不是恰当的住处。赚了不少钱，恐怕抢劫，自然心中不踏实。", "shaoyong": "凶： 得此爻者，在外者会有所成就，但美中不足，有忧惨是非之事发生。从商者会获利。"}, {"position": "六五", "text": "射雉一矢亡，终以誉命。", "xiang": "终以誉命，上逮也。", "baihua": "射野鸡，一发命中，其人因而博得善时的美名。\n\n《象辞》说：终于博得善射的美名，众口传誉，上面的人也知道了。", "shaoyong": "吉： 得此爻者，会得到老者的帮助，事有所成。"}, {"position": "上九", "text": "鸟焚其巢，旅人先笑后号啕。丧牛于易，凶。", "xiang": "以旅在上，其义焚也。", "baihua": "鸟儿的巢窠被焚烧，周人的邑落被抢劫，四处流落的周人啊，美好的生活已成往事，悲惨的现实即在眼前，狄人牵着牛羊去，往后的日子怎么过。\n\n《象辞》说：以商旅身份而身登高爵，非分之极，其居室被焚毁是意料之中的事，牛羊在易地被抢劫，也没有人来体恤安慰，是理所应当。", "shaoyong": "凶： 得此爻者，先好后坏，或迁居修造以避灾难，或有目疾，或会遭火灾。做官的难保其位，有先得后失之忧。"}]
  },
  {
    id: 57,
    name: "巽为风",
    shortName: "巽卦",
    upper: "巽",
    lower: "巽",
    symbol: "☴\n☴",
    text: "巽。小亨。利有攸往，利见大人。",
    xiangZhuan: "随风，巽。",
    baihua: "稍见亨通。利于出行，利于会见王公贵族。\n\n《象辞》说：本卦为巽卦相迭而成，巽为风，因而长风相随，吹拂不断，是巽卦的卦象。君子观此卦象，取法于长吹不断的风，从而不断地申明教义，反复地颁行政令，灌输纲常大义。",
    duanyi: "巽卦巽上巽下，为巽宫本位卦。巽为顺，谦逊、顺从之意，对君子有利，利见大人。",
    shaoyong: "顺伏容人，谦虚行事；得贵多助，利在远处。\n\n得此卦者，运势起伏不定，宜随机应变，谦虚行事，则可得意外之收获。",
    chuantong: "这个卦是同卦（下巽上巽）相叠，巽为风，两风相重，长风不绝，无孔不入，巽亦为顺、谦逊的态度和行为，可无往不利。",
    yaoci: [{"position": "初六", "text": "进退，利武人之贞。", "xiang": "进退，志疑也。", "baihua": "进退听命，这是利于武人的占卜。\n\n《象辞》说：进退听命，是因为自己没有成见。武人具有坚定的意志是应该的，因为只有意志坚定，才能勇敢无畏，临危不乱。", "shaoyong": "平： 得此爻者，有得有失，不良者多招诽谤。做官的或有差役，进退不一，或有兼权，难中有易。"}, {"position": "九二", "text": "巽在床下，用史巫纷若，吉，无咎。", "xiang": "纷若之吉，得中也。", "baihua": "病人卧床不起，祝史巫士降神祭祀，禳灾驱鬼，忙碌不停。病情有好转，灾难消除了。\n\n《象辞》说：祝史巫士禳灾驱鬼忙碌不停，之所以使病情有好转，因为九二阳爻居下卦中位，爻象既得，灾难自退。", "shaoyong": "吉： 得此爻者，诚恳待人，谋望获利。做官的有升迁之机。"}, {"position": "九三", "text": "频巽，吝。", "xiang": "频巽之吝，志穷也。", "baihua": "勉强顺从，其心必不顺畅。\n\n《象辞》说：勉强顺从，而内心不顺畅，说明这是出于无可奈何。", "shaoyong": "凶： 得此爻者，运势低迷，有穷困之厄。做官的有被贬职之忧。"}, {"position": "六四", "text": "悔亡，田获三品。", "xiang": "田获三品，有功也。", "baihua": "没有悔恨，狩猎获得各种猎物。\n\n《象辞》说：狩猎获得各种猎物，说明狩猎大有收获。", "shaoyong": "吉： 得此爻者，正当好运，多福多利。读书人会取得佳绩。"}, {"position": "九五", "text": "贞吉，悔亡，无不利。无初有终。先庚三日，后庚三日，吉。", "xiang": "九五之吉，位中正也。", "baihua": "贞卜得吉兆，没有悔恨，无所不利。虽没有良好的开端，但有良好的结局。时日定在丁日或癸日，其事一定成功。\n\n《象辞》说：九五爻辞之所以讲吉利，因为九五阳爻居上卦中位，像人事合于正道，自然吉利。", "shaoyong": "吉： 得此爻者，谋望有成，无往不利。做官的先阻后顺。"}, {"position": "上九", "text": "巽在床下，丧其资斧，贞凶。", "xiang": "巽在床下，上穷也；丧其资斧，正乎凶也。", "baihua": "人隐伏在床底下，钱财则被洗劫一空。卜问得凶兆。\n\n《象辞》说：隐伏在床底下，正是上九阳爻穷途末路之象。钱财被洗劫，不正是凶险之事吗？", "shaoyong": "凶： 得此爻者，多损失，或生疾病。做官的有运不逢时，须谨慎。"}]
  },
  {
    id: 58,
    name: "兑为泽",
    shortName: "兑卦",
    upper: "兑",
    lower: "兑",
    symbol: "☱\n☱",
    text: "兑。亨，利，贞。",
    xiangZhuan: "丽泽，兑。",
    baihua: "初九：和睦欢喜，吉利。\n\n《象辞》说：和睦欢喜之所以吉利，因为人际邦交无所猜疑。",
    duanyi: "",
    shaoyong: "吉： 得此爻者，人情和合，百谋皆遂。",
    chuantong: "这个卦是同卦（下泽上泽）相叠。泽为水。两泽相连，两水交流，上下相和，团结一致，朋友相助，欢欣喜悦。兑为悦也。同秉刚健之德，外抱柔和之姿，坚行正道，导民向上。",
    yaoci: [{"position": "初九", "text": "和兑，吉。", "xiang": "和兑之吉，行未疑也。", "baihua": "和睦欢喜，吉利。\n\n《象辞》说：和睦欢喜之所以吉利，因为人际邦交无所猜疑。", "shaoyong": "吉： 得此爻者，人情和合，百谋皆遂。"}, {"position": "九二", "text": "孚兑，吉，悔亡。", "xiang": "孚兑之吉，信志也。", "baihua": "优待俘虏，吉利，没有悔恨。\n\n《象辞》说：以诚信待人，人亦热忱待之，之所以吉利，因为互相之间有了信任。", "shaoyong": "吉： 得此爻者，正当好运，事事和顺。做官的有升迁之兆。"}, {"position": "六三", "text": "来兑，凶。", "xiang": "", "baihua": "以使人归服为乐，蕴藏着凶险。\n\n《象辞》说：以使人归服为乐，蕴藏着凶险，因为力小而任大，德薄而欲多，所行必不当。", "shaoyong": "凶： 得此爻者，会有意外之祸，甚者则失道忘身。做官的有听信谗言而遭辱之忧。"}, {"position": "九四", "text": "商兑，未宁，介疾有喜。", "xiang": "九四之喜，有庆也。", "baihua": "商谈恢复邦交之事，尚未达成协议，但两国的矛盾分歧有了愈合的趋势。\n\n《象辞》说：九四爻辞所讲的喜，即是指将有喜庆之事。", "shaoyong": "平： 得此爻者，从商获利，或进人口，不良者或有疾病，谋望不成。做官的会身居要职，升迁有望。"}, {"position": "九五", "text": "孚于剥，有厉。", "xiang": "孚于剥，位正当也。", "baihua": "被剥国俘虏。剥国无理挑衅，必遭惩罚（对我方而言，坏事将变为好事）。\n\n《象辞》说：当被侵剥之时，仍以诚信待人，正如九五阳爻所象，其人秉行中正之道，必能逢凶化吉。", "shaoyong": "凶： 得此爻者，时运不佳，多意外之祸。做官的会受到小人的诽谤。"}, {"position": "上六", "text": "引兑。", "xiang": "上六引兑，未光也。", "baihua": "引导大家和睦相处。\n\n《象辞》说：上六爻辞讲引导大家和睦相处，用意虽佳，但上六阴爻处一卦之尽头，像其人未必能一呼百应。", "shaoyong": "平： 得此爻者，营谋不顺，谨防有忧。"}]
  },
  {
    id: 59,
    name: "风水涣",
    shortName: "涣卦",
    upper: "巽",
    lower: "坎",
    symbol: "☵\n☴",
    text: "涣。亨，王假有庙。利涉大川，利贞。",
    xiangZhuan: "风行水上，涣。",
    baihua: "亨通，因为君王亲临宗庙，禳灾祈福。利于涉水过江河。这是吉利的贞卜\n\n《象辞》说：本卦上卦为巽，巽为风；下卦为坎，坎为水。风行水上，是涣卦的卦象。先王观此卦象，从而享祭天帝，建立宗庙，推行尊天孝祖的“德教”。",
    duanyi: "涣卦巽上坎下，为离宫五世卦。涣即涣散，表示恶事离身，患难将消，利涉大川，出入无阻，乃是吉卦。",
    shaoyong: "离散解消，灾害涣散；乘机观变，养威蓄锐。\n\n得此卦者，初有不顺，但终可解困，凡事宜小心则百事亨通，忌任性放纵。",
    chuantong: "这个卦是异卦（下坎上巽）相叠。风在水上行，推波助澜，四方流溢。涣，水流流散之意。象征组织和人心涣散，必须用积极的手段和方法克服，战胜弊端，挽救涣散，转危为安。",
    yaoci: [{"position": "初六", "text": "用拯马壮，吉。", "xiang": "初六之吉，顺也。", "baihua": "洪水突来，因而乘马逃避，匆促跌伤，幸免淹亡之祸，吉利。\n\n《象辞》说：初六爻辞讲的吉利，是因为初六阴爻居九二阳爻之下，有阴柔顺从阳刚之意。像马顺从人意。", "shaoyong": "吉： 得此爻者，得尊上提举，营谋皆遂。做官的会受到重用，有望晋升。"}, {"position": "九二", "text": "涣奔其机，悔亡。", "xiang": "涣奔其机，得愿也。", "baihua": "洪水奔涌，冲毁房基。性命无虞。不幸中之万幸。\n\n《象辞》说：荡涤冲刷其污垢，正是心中所愿。", "shaoyong": "平： 得此爻者，谋望有成，或会成家。做官的有实权。"}, {"position": "六三", "text": "涣其躬，无悔。", "xiang": "涣其躬，志在外也。", "baihua": "洪水冲到身上，幸免于难，尚可庆幸。\n\n《象辞》说：冲刷他的身体，说明其人志在教育他人，治理国家。", "shaoyong": "平： 得此爻者，常人获利。做官的出外就职。"}, {"position": "六四", "text": "涣其群，元吉。涣有丘，匪夷所思。", "xiang": "涣其群，元吉，光大也。", "baihua": "洪水冲向人群，然而十分幸运，因为人群聚集在山丘上，洪水只能淹到山脚，否则其后果是平常难以想像的。\n\n《象辞》说：冲刷大众百姓，说明君王德教广施，教化大行。", "shaoyong": "吉： 得此爻者，先凶后吉，谋望和合，求利可获。做官的会身居要职。"}, {"position": "九五", "text": "涣汗其大号，涣王居，无咎。", "xiang": "王居无咎，正位也。", "baihua": "洪水横溢，淹没国都，淹及王宫，牵好人员早巳撤走，没有大的灾难。\n\n《象辞》说：王宫没有遭遇灾难，因为九五阳爻居上卦中位，位尊且正，自然无灾难。", "shaoyong": "吉： 得此爻者，正当好运，事事皆吉，求利者遂。做官的会升迁。"}, {"position": "上九", "text": "涣其血，去逖出，无咎。", "xiang": "涣其血，远害也。", "baihua": "洪水退去，忧患消除，但仍须警惕，加强防范，这样就没有灾难。\n\n《象辞》说：有血光之灾，走开，远远地走开，这样就可远离灾害。", "shaoyong": "平： 得此爻者，先难后易，运势好转。做官的外出就职者会有灾难。"}]
  },
  {
    id: 60,
    name: "水泽节",
    shortName: "节卦",
    upper: "坎",
    lower: "兑",
    symbol: "☱\n☵",
    text: "节。亨，苦节不可贞。",
    xiangZhuan: "泽上有水，节。",
    baihua: "亨通。如果以节制为苦，其凶吉则不可卜问。\n\n《象辞》说：本卦下卦为兑，兑为泽；上卦为坎，坎为水。泽中水满，因而须高筑堤防，这是节卦的卦象。君子观此卦象，从而建立政纲制度，确立伦理原则。",
    duanyi: "节卦坎上兑下，为坎宫初世卦。节说明需节制、节约，停止挥霍，这样才能居家康宁。",
    shaoyong: "操守节度，适可而止；审时度势，能知变通。\n\n得此卦者，宜安分守己，切忌贪心不足，诸事必须节制，不宜过份，更要戒酒色。",
    chuantong: "这个卦是异卦（下兑上坎）相叠。兑为泽，坎为水。泽有水而流有限，多必溢于泽外。因此要有节度，故称节。节卦与涣卦相反，互为综卦，交相使用。天地有节度才能常新，国家有节度才能安稳，个人有节度才能完美。",
    yaoci: [{"position": "初九", "text": "不出户庭，无咎。", "xiang": "不出户庭，知通塞也。", "baihua": "筮遇此爻，杜门不出，没有灾祸。\n\n《象辞》说：杜门不出，因为其人知道所行必不通。", "shaoyong": "平： 得此爻者，进取不利，宜守旧。"}, {"position": "九二", "text": "不出门庭，凶。", "xiang": "不出门庭，失时极也。", "baihua": "筮遇此爻，杜门不出，也有凶险。\n\n《象辞》说：杜门不出，也有凶险，因为坐失良机，错误已极。", "shaoyong": "凶： 得此爻者，时运不佳，事多乖离，宜动不宜静。做官的不得时运。"}, {"position": "六三", "text": "不节若，则嗟若。无咎。", "xiang": "不节之嗟，又谁咎也。", "baihua": "不节俭则困穷，处困穷则知悔过，知悔过则可以无灾难。\n\n《象辞》说：奢侈带来了悔恨，这是谁之过？", "shaoyong": "平： 得此爻者，多辛苦，少收获。"}, {"position": "六四", "text": "安节，亨。", "xiang": "安节之亨，承上道也。", "baihua": "安于节俭遵礼的生活，通泰。\n\n《象辞》说：安于节俭遵礼的生活之所以吉利，是因为顺从了君上的旨意。", "shaoyong": "吉： 得此爻者，秉公守法，安于正道，福利可获。做官的会得到上司的欣赏，升迁有望。"}, {"position": "九五", "text": "甘节，吉，往有尚。", "xiang": "甘节之吉，居位中也。", "baihua": "以节俭遵礼为乐，吉利。秉此而行，所往必得别人资助。\n\n《象辞》说：以节俭遵礼为乐之所以吉利，因为九五之爻，所居恰当，像人居德行义，自然获得人家资助。", "shaoyong": "吉： 得此爻者，正当好运，谋望有成。"}, {"position": "上六", "text": "苦节，贞凶。悔亡。", "xiang": "苦节贞凶，其道穷也。", "baihua": "以节俭遵礼为苦，卜问得凶兆，其人将为家道败落而悔恨。\n\n《象辞》说：以节俭遵礼为苦，卜问得凶兆，正如上六阴爻孤悬一卦之尽头，像人走入穷困不通的境地。", "shaoyong": "凶： 得此爻者，不得天时，名利皆无。做官的不知变通，前途渺茫。"}]
  },
  {
    id: 61,
    name: "风泽中孚",
    shortName: "中孚卦",
    upper: "巽",
    lower: "兑",
    symbol: "☱\n☴",
    text: "中孚。豚鱼，吉。利涉大川，利贞。",
    xiangZhuan: "泽上有风，中孚。",
    baihua: "豚鱼献祭，虽物薄但心诚，吉利。并利于涉水过河。这是吉利的贞卜。\n\n《象辞》说：本卦上卦为巽，巽为风；下卦为兑，兑为泽，泽上有风，风起波涌。这是中孚的卦象。君子观此卦象，有感于风化邦国，唯德教为先，因而审议讼狱，不轻置重典。",
    duanyi: "中孚卦巽上兑下，为艮宫游魂卦。中孚即忠信之意，主利涉大川，厄难消除。",
    shaoyong: "信而有实，诚恳诚信；知己协助，谋望克遂。\n\n得此卦者，正直诚信者吉利，会得到朋友的帮助，谋事可成；心存邪念者则凶。",
    chuantong: "这个卦是异卦（下兑上巽）相叠。孚本义孵，孵卵出壳的日期非常准确，有信的意义。卦形外实内虚，喻心中诚信，所以称中孚卦。这是立身处世的根本。",
    yaoci: [{"position": "初九", "text": "虞吉，有它不燕。", "xiang": "初九虞吉，志未变也。", "baihua": "行安神之礼，吉利。有这样的变故，自然不行讌礼。\n\n《象辞》说：初九爻辞讲行安神之礼，吉利，因为慕恋先人的心愿未变。\n\n北宋易学家邵雍解\n\n吉： 得此爻者，得贵人提举，谋事有成，但喜中有忧，宜行正道，修身养性，不可逸乐。做官的会受到举荐，能居要职。", "shaoyong": ""}, {"position": "九二", "text": "鸣鹤在阴，其子和之。我有好爵，吾与尔靡之。", "xiang": "其子和之，中心愿也。", "baihua": "老鹤在树荫下鸣叫，小鹤在旁边附和。我有美酒，与你共享用。\n\n《象辞》说：小鹤和应老鹤，这是心灵相通的表现。", "shaoyong": "吉： 得此爻者，无往不利，多进钱财，或生子。做官的会晋升。"}, {"position": "六三", "text": "得敌，或鼓或罢，或泣或歌。", "xiang": "或鼓或罢，位不当也。", "baihua": "击败了敌人，有的击鼓追击，有的凯旋报捷；消息传来，有的高兴得热泪盈眶，有的放声高歌。\n\n《象辞》说：有的人击鼓追击，有的凯旋报捷，但从爻象看来，六三阴爻而处于阳位，胜利之中，恐怕隐伏着不测之祸。", "shaoyong": "凶： 得此爻者，喜中有忧，事多反复。做官的同僚不睦，先进后退。"}, {"position": "六四", "text": "月既望，马匹亡，无咎。", "xiang": "马匹亡，绝类上也。", "baihua": "月中的时候，马匹丢失了，但无大的灾祸。\n\n《象辞》说：马匹丢失了，此后要加倍警惕，防止再发生类似事情。", "shaoyong": "平： 得此爻者，能得到提拔，但有失去配偶或财产之忧。做官的会晋升，身居要位。"}, {"position": "九五", "text": "有孚挛如，无咎。", "xiang": "有孚挛如，位正当也。", "baihua": "俘虏成群，串连捆绑。没有灾难。\n\n《象辞》说：存心诚信，始终如一，正如九五爻象所显示的，其人行事与其地位相合。", "shaoyong": "吉： 得此爻者，人情和合，谋事有成，无往不利。做官的君臣一心，会得到上司的赞赏。"}, {"position": "上九", "text": "翰音登于天，贞凶。", "xiang": "翰音登于天，何可长也。", "baihua": "鸡飞到天空。卜问得凶兆。\n\n《象辞》说：鸡飞到天空，它怎能长久飞翔呢？", "shaoyong": "凶： 得此爻者，多虚少实，前路凶险。经商者会有损失。做官的有近颜之喜。"}]
  },
  {
    id: 62,
    name: "雷山小过",
    shortName: "小过卦",
    upper: "震",
    lower: "艮",
    symbol: "☶\n☳",
    text: "小过。亨，利贞。可小事，不可大事。飞鸟遗之音。不宜上，宜下，大吉。",
    xiangZhuan: "山上有雷，小过。",
    baihua: "亨通，这是吉利的贞卜。但是只适宜于小事，不适宜大事。飞鸟空中过，叫声耳边留，警惕人们： 登高必遇险 ，下行则吉利。\n\n象辞说：本卦下卦为艮，艮为山；上卦为震，震为雷，山上有雷，是小过的卦象。君子观此卦象，惧畏天雷，不敢有过失。因而行事不敢过于恭谦，居丧不敢过度哀伤，用度不敢过于节俭，唯适中而已。",
    duanyi: "小过卦震上艮下，为兑宫游魂卦。占得此卦，举事有利，可以举小事，不可举大事。",
    shaoyong: "阴顺阳困，柔软用事；谨慎自持，不宜急进。\n\n得此卦者，诸事不利，宜行小事，不宜成大事，更防因自身的过失惹来是非争讼。",
    chuantong: "这个卦是异卦（下艮上震）相叠。艮为山，震为雷，过山雷鸣，不可不畏惧。阳为大，阴为小，卦外四阴超过中二阳，故称“小过”，小有越过。",
    yaoci: [{"position": "初六", "text": "飞鸟以凶。", "xiang": "飞鸟以凶，不可如何也。", "baihua": "", "shaoyong": ""}, {"position": "六二", "text": "过其祖，遇其妣。不及其君，遇其臣，无咎。", "xiang": "不及其君，臣不可过也。", "baihua": "", "shaoyong": ""}, {"position": "九三", "text": "弗过防之，从或戕之，凶。", "xiang": "从或戕之，凶如何也。", "baihua": "", "shaoyong": ""}, {"position": "九四", "text": "无咎，弗过遇之，往厉必戒。勿用，永贞。", "xiang": "弗过遇之，位不当也。", "baihua": "", "shaoyong": ""}, {"position": "六五", "text": "密云不雨，自我西郊。公弋取彼在穴。", "xiang": "密云不雨，已上也。", "baihua": "", "shaoyong": ""}, {"position": "上六", "text": "弗遇过之，飞鸟离之，凶。是谓灾眚。", "xiang": "弗遇过之，已亢也。", "baihua": "", "shaoyong": ""}]
  },
  {
    id: 63,
    name: "水火既济",
    shortName: "既济卦",
    upper: "坎",
    lower: "离",
    symbol: "☲\n☵",
    text: "既济。亨，小利贞，初吉终乱。",
    xiangZhuan: "水在火上，既济。",
    baihua: "亨通。这是小见吉利的贞卜。起初吉利，最后将发生变故。\n\n《象辞》说：本卦上卦为坎，坎为水；下卦为离，离为火。水上火下，水浇火熄，是既济之卦的卦象。君子观此卦象，从而有备于无患之时，防范于未然之际。",
    duanyi: "既济卦坎上离下，为坎宫三世卦。既济就是说已经成功，事情已经摆平。但还需谨慎，当心物极必反。",
    shaoyong: "济助有成，坚忍自重；由大而小，确保盛运。\n\n得此卦者，事业有成，成功之象，但谨防盛极必衰，宜退守为吉，再进则凶。",
    chuantong: "这个卦是异卦（下离上坎）相叠。坎为水，离为火，水火相交，水在火上，水势压倒火势，救火大功告成。既，已经；济，成也。既济就是事情已经成功，但终将发生变故。",
    yaoci: [{"position": "初九", "text": "曳其轮，濡其尾，无咎。", "xiang": "曳其轮，义无咎也。", "baihua": "", "shaoyong": ""}, {"position": "六二", "text": "妇丧其茀，勿逐，七日得。", "xiang": "七日得，以中道也。", "baihua": "", "shaoyong": ""}, {"position": "九三", "text": "高宗伐鬼方，三年克之。小人勿用。", "xiang": "三年克之，惫也。", "baihua": "", "shaoyong": ""}, {"position": "六四", "text": "繻有衣袽，终日戒。", "xiang": "终日戒，有所疑也。", "baihua": "", "shaoyong": ""}, {"position": "九五", "text": "东邻杀牛，不如西郊之禴祭，实受其福。", "xiang": "东邻杀牛，不如西邻之时也。", "baihua": "", "shaoyong": ""}, {"position": "上六", "text": "濡其首，厉。", "xiang": "濡其首厉，何可久也。", "baihua": "", "shaoyong": ""}]
  },
  {
    id: 64,
    name: "火水未济",
    shortName: "未济卦",
    upper: "离",
    lower: "坎",
    symbol: "☵\n☲",
    text: "未济。亨，小狐汔济，濡其尾，无攸利。",
    xiangZhuan: "火在水上，未济。",
    baihua: "亨通。小狐狸快要渡过河，却打湿了尾巴。看来此行无所利。\n\n《象辞》说：本卦上卦为离，离为火；下卦为坎，坎为水。火在水上，水不能克火，是未济卦的卦象。君子观此卦象，有感于水火错位不能相克，从而以谨慎的态度辨辩事物的性质，审视其方位。",
    duanyi: "未济卦离上坎下，为离宫三世卦。未济就是未完成，此卦爻位不正，形象上极端恶劣，但变化在酝酿之中，未来充满希望。",
    shaoyong: "不能资助，待时而动；由小而大，不可躁进。\n\n得此卦者，运势不通，诸事不能如愿，宜由小及大，稳步进取，要耐心去突破难关，则终可成功。",
    chuantong: "这个卦是异卦（下坎上离）相叠。离为火，坎为水。火上水下，火势压倒水势，救火大功未成，故称未济。《周易》以乾坤二卦为始，以既济、未济二卦为终，充分反映了变化发展的思想。",
    yaoci: [{"position": "初六", "text": "濡其尾，吝。", "xiang": "濡其尾，亦不知极也。", "baihua": "涉水渡河，沾湿了衣尾，前进有困难。\n\n《象辞》说：涉水渡河，沾湿了衣尾，见微知巨，再冒险前进，是不知儆戒。", "shaoyong": "凶： 得此爻者，经营不利，涉水行舟者，谨防溺水之患。做官的仕途有阻，不能前进。"}, {"position": "九二", "text": "曳其轮，贞吉。", "xiang": "九二贞吉，中以行正也。", "baihua": "提着腰带涉水过河。卜问得吉兆。\n\n《象辞》说：九二爻辞讲贞吉，因为九二阳爻处下卦中位，像人行事遵循正道。", "shaoyong": "吉： 得此爻者，安份守纪者，谋望遂意。做官的克服困难者，晋升有望。"}, {"position": "六三", "text": "未济，征凶，利涉大川。", "xiang": "未济征凶，位不当也。", "baihua": "渡不了河，出行有凶险。不利于涉水渡河。\n\n《象辞》说：渡不了河，出行有凶险，因为六三阴爻居阳位，像人处境不利。", "shaoyong": "凶： 得此爻者，宜见机行事，不宜妄动。做官的有因人成事之美。在商旅则涉川历险而利可获。"}, {"position": "九四", "text": "贞吉，悔亡，震用伐鬼方。三年有赏于大国。", "xiang": "贞吉悔亡，志行也。", "baihua": "吉利的贞卜，没有悔恨。大动干戈，助殷讨伐鬼方，费时三年，打败了它，获得殷国的奖赏。\n\n《象辞》说：吉利的卜问，没有悔恨，说明志得意行。", "shaoyong": "吉： 得此爻者，会得好人提举，获利丰厚。做官的会受到重用，名利双全。读书人会取得佳绩。"}, {"position": "六五", "text": "贞吉，无悔，君子之光。有孚，吉。", "xiang": "君子之光，其晖吉也。", "baihua": "吉利的贞卜，没有悔恨。打了胜仗，捕获了俘虏，这是君子的光荣，吉利。\n\n《象辞》说：君子光荣，君子光明正大，自然吉利。", "shaoyong": "吉： 得此爻者，谋望有成，财利丰厚。做官的能得到升迁。"}, {"position": "上九", "text": "有孚于饮酒，无咎。濡其首，有孚失是。", "xiang": "饮酒濡首，亦不知节也。", "baihua": "捕获了俘虏，饮酒庆贺。没有灾难，但酗酒闹事，头发都淋湿了。俘虏乘机作乱，将他们杀了。\n\n《象辞》说：酗酒闹事头发都淋湿，也太不知节制了。", "shaoyong": "平： 得此爻者，行险而顺，不良者有溺水之厄，纵酒之灾。做官的有望升迁。"}]
  }
];
